minAgeDays:60,peakAgeDays:180,maxAgeDays:540,
tags:['Vanilla','Smooth','Dessert','Secondary'],
description:'Real vanilla beans split + added in secondary. Creates a smooth dessert mead — vanilla custard meets honey wine. Pair with cheesecake or just sip neat.',
ingredients:[
{item:'Wildflower Honey',amount:'1.7 kg',notes:''},
{item:'Spring Water',amount:'4.5 L',notes:''},
{item:"Mangrove Jack's M05 Yeast",amount:'10 g',notes:''},
{item:'Mead Yeast Nutrient',amount:'12 g',notes:''},
{item:'Vanilla Beans (Madagascar/Bourbon)',amount:'2-3 beans',notes:'SECONDARY: split lengthwise to expose seeds'}
],
steps:[
{day:0,title:'Brew Day',desc:'Standard traditional base — honey + water + nutrient + yeast.'},
{day:1,title:'First Nutrient',desc:'6g.'},
{day:3,title:'Second Nutrient',desc:'6g.'},
{day:21,title:'Verify Primary Complete',desc:'Two stable readings 3 days apart.'},
{day:24,title:'Add Vanilla (SECONDARY)',desc:'SECONDARY: Split 2-3 vanilla beans lengthwise. Drop into fermenter. Vanilla extracts beautifully in mead.'},
{day:38,title:'Taste Test',desc:'Pull a sample. If vanilla is forward, remove beans. If subtle, leave another week.'},
{day:50,title:'Remove Beans & Bottle',desc:'Beans removed (rinse and freeze for re-use in cooking). Bottle.'},
{day:90,title:'First Tasting',desc:'Vanilla integrates over weeks. Subtle at first, develops over time.'}
],
