// ==================== INSIGHTS VIEW ====================
// Combines best-tasting batch insights (what your highest-rated batches share)
// with a personal-trend dashboard (year-over-year attenuation, ratings, cost,
// time-to-bottle). Both require enough data to be meaningful — show helpful
// empty-states when there aren't enough batches yet.

function renderInsightsView(){
  var bottled=APP.batches.filter(function(b){return APP.bottling[b.id];});
  var failed=APP.batches.filter(function(b){return b.failed;});
  if(bottled.length<3&&!failed.length){
    // Pattern-mining needs more data, but the fun lifetime stats are worth
    // showing from batch one.
    return'<div class="page-title">Insights</div><div class="page-subtitle">Patterns in your brewing</div>'
      +renderFunInsights()
      +'<div class="info-box" style="margin-top:8px"><div style="font-size:13px;color:var(--text2)">📊 Deeper pattern-mining (what your best batches share, trends over time) unlocks at <strong>3 bottled batches</strong> — you\'re at '+bottled.length+'. Keep brewing!</div></div>';
  }
  return'<div class="page-title">Insights</div><div class="page-subtitle">Patterns in your brewing journey · '+bottled.length+' bottled · '+failed.length+' failed</div>'
    +renderFunInsights()
    +renderBestTastingInsights()
    +renderFailedBatchInsights()
    +renderPersonalTrends();
}

// Fun + meaningful lifetime insights mined from the whole brewing history.
function renderFunInsights(){
  var batches=APP.batches||[];
  if(!batches.length)return'';
  var L=(typeof lifetimeStats==='function')?lifetimeStats():null;
  function mode(arr){var c={},best=null,bn=0;arr.forEach(function(v){if(!v)return;c[v]=(c[v]||0)+1;if(c[v]>bn){bn=c[v];best=v;}});return best?{val:best,n:bn}:null;}
  // ---- aggregates ----
  var totalVolume=batches.reduce(function(s,b){return s+(parseFloat(b.volume)||0);},0);
  var totalHoney=batches.reduce(function(s,b){return s+(parseFloat(b.honey)||0);},0);
  var favHoney=mode(batches.map(function(b){return b.honeyType;}));
  var favYeast=mode(batches.map(function(b){var y=getYeastById(b.yeast);return y?y.name.split('—')[0].trim():b.yeast;}));
  var styles={};batches.forEach(function(b){var r=APP.recipes.find(function(x){return x.id===b.recipeId;});var c=(r&&(r.category||r.style))||b.style;if(c)styles[c]=1;});
  var distinctStyles=Object.keys(styles).length;
  // ABV extremes + days-to-bottle from bottled batches
  var abvs=[],ttb=[];
  batches.forEach(function(b){
    var bot=APP.bottling[b.id];if(!bot)return;
    var abv=parseFloat(bot.abv)||(b.og&&bot.fg?parseFloat(calcABV(b.og,bot.fg)):0);
    if(abv>0)abvs.push({abv:abv,name:b.name});
    if(bot.date&&b.startDate){var d=Math.round((new Date(bot.date)-new Date(b.startDate))/86400000);if(d>0&&d<2000)ttb.push(d);}
  });
  abvs.sort(function(a,b){return b.abv-a.abv;});
  var avgTTB=ttb.length?Math.round(ttb.reduce(function(s,x){return s+x;},0)/ttb.length):null;
  // bottles ever + "glasses" (≈5 per 750, ≈3.3 per 500)
  var bottledEver=L?L.bottledEver:0;
  var glasses=Math.round(bottledEver*4.5);
  // bee fun fact: ~1 kg honey ≈ 195,000 km of bee flight; Earth ≈ 40,075 km
  var beeKm=Math.round(totalHoney*195000);
  var earths=totalHoney?(beeKm/40075):0;
  // success rate
  var failedN=batches.filter(function(b){return b.failed;}).length;
  var finishedOrBottled=batches.filter(function(b){return APP.bottling[b.id];}).length;
  var successRate=(finishedOrBottled+failedN)?Math.round(finishedOrBottled/(finishedOrBottled+failedN)*100):null;
  var ccy=APP.settings.currency||'€';
  var totalCost=batches.reduce(function(s,b){return s+((b.cost&&(b.cost.honey||0)+(b.cost.extras||0))||0);},0);

  function tile(icon,val,label,sub){
    return'<div style="background:var(--bg);border:1px solid var(--border);border-radius:var(--radius);padding:14px;text-align:center">'
      +'<div style="font-size:20px;line-height:1;margin-bottom:6px">'+icon+'</div>'
      +'<div style="font-family:var(--font-display);font-size:21px;color:var(--gold2);line-height:1.1">'+val+'</div>'
      +'<div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.2px;margin-top:5px;text-transform:uppercase">'+label+'</div>'
      +(sub?'<div style="font-size:10.5px;color:var(--text3);margin-top:4px;line-height:1.4">'+sub+'</div>':'')
      +'</div>';
  }
  var tiles=[
    tile('🍯',totalVolume.toFixed(0)+' L','Mead Brewed (lifetime)','≈ '+Math.round(totalVolume/0.75)+' × 750 ml made'),
    tile('🍷',bottledEver,'Bottles Bottled','≈ '+glasses+' glasses poured'),
    favHoney?tile('🌼',escHtml(favHoney.val),'Favourite Honey','used in '+favHoney.n+' batch'+(favHoney.n!==1?'es':'')):'',
    favYeast?tile('🧫',escHtml(favYeast.val),'Go-To Yeast','pitched '+favYeast.n+'×'):'',
    abvs.length?tile('🔥',abvs[0].abv.toFixed(1)+'%','Strongest Batch',escHtml(abvs[0].name)):'',
    avgTTB?tile('⏱',avgTTB+' days','Avg Brew → Bottle',null):'',
    tile('🎨',distinctStyles,'Styles Explored',distinctStyles>=6?'a true polymath!':'keep exploring'),
    successRate!=null?tile('🎯',successRate+'%','Success Rate',failedN?failedN+' lost to learn from':'flawless so far'):'',
    totalCost>0?tile('💰',ccy+totalCost.toFixed(0),'Invested in the Craft',bottledEver?'≈ '+ccy+(totalCost/bottledEver).toFixed(2)+'/bottle':null):''
  ].filter(Boolean).join('');

  var beeFact=totalHoney>0
    ? '<div style="margin-top:14px;padding:12px 14px;background:linear-gradient(135deg,rgba(201,168,76,0.10),rgba(201,168,76,0.02));border:1px solid var(--border);border-radius:var(--radius);font-size:13px;color:var(--text2);line-height:1.6">'
      +'🐝 <strong style="color:var(--gold2)">Bee math:</strong> your '+totalHoney.toFixed(1)+' kg of honey represents roughly <strong>'+beeKm.toLocaleString()+' km</strong> of bee flight — that\'s about <strong>'+earths.toFixed(1)+'×</strong> around the Earth, or '+(earths/9.6).toFixed(1)+'× the distance to the Moon. Tip your hat to the bees.</div>'
    : '';

  return'<div class="card" style="margin-bottom:16px"><div class="card-header"><div class="card-title">✨ FUN FACTS &amp; MILESTONES</div></div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:10px">'+tiles+'</div>'
    +beeFact
    +'</div>';
}

// Failed batch insights: postmortems list + pattern-mining counterpart to
// "what your best batches share". When you have failures, learning from them
// systematically is more valuable than reviewing them ad-hoc.
function renderFailedBatchInsights(){
  var failed=(APP.batches||[]).filter(function(b){return b.failed;});
  if(!failed.length)return''; // no failures = no card. Keeps the view cleaner.
  // Sort newest-first
  failed.sort(function(a,b){return(b.failed.date||'').localeCompare(a.failed.date||'');});
  // Tally categories
  var byCategory={};
  failed.forEach(function(b){
    var c=b.failed.category||'other';
    if(!byCategory[c])byCategory[c]={count:0,batches:[]};
    byCategory[c].count++;
    byCategory[c].batches.push(b);
  });
  var topCategory=Object.keys(byCategory).sort(function(a,b){return byCategory[b].count-byCategory[a].count;})[0];
  // Pattern-match: what common attributes show up across failures
  function tallyMode(arr,getter){
    var counts={};
    arr.forEach(function(x){var v=getter(x);if(v==null||v==='')return;counts[v]=(counts[v]||0)+1;});
    var entries=Object.entries(counts).sort(function(a,b){return b[1]-a[1];});
    return entries.length?entries[0]:null;
  }
  var commonHoney=tallyMode(failed,function(b){return b.honeyType;});
  var commonYeast=tallyMode(failed,function(b){return b.yeast;});
  var commonStyle=tallyMode(failed,function(b){var r=APP.recipes.find(function(x){return x.id===b.recipeId;});return r&&r.style;});

  // Postmortem cards — most recent 5, newer cards higher
  var postmortems=failed.slice(0,5).map(function(b){
    var f=b.failed;
    var cat=FAILURE_CATEGORIES.find(function(c){return c.id===f.category;})||{label:f.category,icon:'⚰'};
    var color=getBatchColor(b);
    return'<div onclick="showView(\'batch\',\''+b.id+'\')" style="cursor:pointer;background:var(--bg);border-left:3px solid var(--red2);border-radius:var(--radius);padding:12px 14px;margin-bottom:8px;transition:background 0.15s" onmouseover="this.style.background=\'var(--bg3)\'" onmouseout="this.style.background=\'var(--bg)\'">'
      +'<div style="display:flex;align-items:baseline;justify-content:space-between;margin-bottom:6px;flex-wrap:wrap;gap:6px">'
        +'<div style="display:flex;align-items:baseline;gap:8px"><div style="font-family:var(--font-display);font-size:13px;color:'+color+'">'+escHtml(b.name)+'</div>'+(b.serial?'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3)">#'+escHtml(b.serial)+'</div>':'')+'</div>'
        +'<div style="font-family:var(--font-mono);font-size:9.5px;color:var(--red2);letter-spacing:1.5px">'+cat.icon+' '+escHtml(cat.label.toUpperCase())+'</div>'
      +'</div>'
      +(f.whatWentWrong?'<div style="font-size:11.5px;color:var(--text2);line-height:1.5;font-style:italic">'+escHtml(f.whatWentWrong.length>180?f.whatWentWrong.slice(0,180)+'…':f.whatWentWrong)+'</div>':'')
      +(f.whatToTryNext?'<div style="font-size:11px;color:var(--gold2);line-height:1.5;margin-top:6px;border-top:1px dotted var(--border);padding-top:5px"><strong style="font-family:var(--font-mono);font-size:9px;letter-spacing:1.5px;text-transform:uppercase">→</strong> '+escHtml(f.whatToTryNext.length>140?f.whatToTryNext.slice(0,140)+'…':f.whatToTryNext)+'</div>':'')
      +'</div>';
  }).join('');

  var patternRows=[];
  if(failed.length>=2){
    if(commonHoney&&commonHoney[1]>=2)patternRows.push({k:'Most common honey',v:commonHoney[0],detail:'in '+commonHoney[1]+' of '+failed.length+' failures'});
    if(commonYeast&&commonYeast[1]>=2)patternRows.push({k:'Most common yeast',v:commonYeast[0],detail:'in '+commonYeast[1]+' of '+failed.length+' failures'});
    if(commonStyle&&commonStyle[1]>=2)patternRows.push({k:'Most common style',v:commonStyle[0],detail:'in '+commonStyle[1]+' of '+failed.length+' failures'});
    if(topCategory&&byCategory[topCategory].count>=2){
      var topCatLabel=(FAILURE_CATEGORIES.find(function(c){return c.id===topCategory;})||{label:topCategory}).label;
      patternRows.push({k:'Most common failure',v:topCatLabel,detail:byCategory[topCategory].count+' of '+failed.length+' failures'});
    }
  }
  var patternBlock=patternRows.length?'<div style="background:var(--bg);border-radius:var(--radius);padding:10px 14px;margin-bottom:14px;border-left:3px solid var(--gold)">'
    +'<div style="font-family:var(--font-mono);font-size:9.5px;color:var(--gold);letter-spacing:1.5px;margin-bottom:6px">⚠ PATTERNS WORTH NOTING</div>'
    +patternRows.map(function(r){return'<div style="display:flex;justify-content:space-between;font-size:12px;padding:4px 0"><div style="color:var(--text3);font-family:var(--font-mono);font-size:10px;letter-spacing:1px">'+escHtml(r.k.toUpperCase())+'</div><div style="text-align:right"><span style="color:var(--gold2);font-family:var(--font-display);font-size:13px">'+escHtml(r.v)+'</span> <span style="color:var(--text3);font-size:10.5px;font-style:italic">'+escHtml(r.detail)+'</span></div></div>';}).join('')
    +'</div>':'';

  var totalBatches=(APP.batches||[]).length;
  var failureRate=totalBatches?(failed.length/totalBatches*100).toFixed(0):0;

  return'<div class="card" style="margin-bottom:16px;border-left:3px solid var(--red2)"><div class="card-header"><div class="card-title">⚰ POSTMORTEMS</div><div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px">'+failed.length+' FAILED · '+failureRate+'% OF '+totalBatches+'</div></div>'
    +'<div style="font-size:12.5px;color:var(--text3);margin-bottom:12px;line-height:1.55">Lessons preserved. The postmortems your past-self wrote so future-you doesn\'t repeat the same mistake. Failure rate stays low when you actually learn from these.</div>'
    +patternBlock
    +postmortems
    +(failed.length>5?'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px;text-align:center;margin-top:8px">Showing 5 most recent · '+(failed.length-5)+' more in batch list</div>':'')
    +'</div>';
}

// Best-tasting insights: find the common threads across your highest-rated
// batches. Pulls all batches with at least one 4-5 star tasting, then
// computes mode/median for each interesting attribute.
function renderBestTastingInsights(){
  // Build per-batch summary including best tasting rating
  var batchSummaries=APP.batches.filter(function(b){return APP.bottling[b.id];}).map(function(b){
    var tastings=(APP.tastings[b.id]||[]).filter(function(t){return t.rating;});
    var bestRating=tastings.length?Math.max.apply(null,tastings.map(function(t){return t.rating;})):0;
    var bot=APP.bottling[b.id];
    var recipe=APP.recipes.find(function(r){return r.id===b.recipeId;});
    return{
      batch:b,
      rating:bestRating,
      honeyType:b.honeyType,
      yeast:b.yeast,
      og:b.og,
      style:(recipe&&recipe.style)||b.style,
      abv:bot.abv,
      daysToBottle:b.startDate&&bot.date?Math.floor((new Date(bot.date)-new Date(b.startDate))/86400000):null
    };
  });
  var topRated=batchSummaries.filter(function(s){return s.rating>=4;});
  if(topRated.length<2){
    return'<div class="card" style="margin-bottom:16px"><div class="card-header"><div class="card-title">🌟 BEST-TASTING INSIGHTS</div></div>'
      +'<div style="font-size:13px;color:var(--text3);font-style:italic;padding:14px 0">Need at least 2 batches with a 4-star or higher tasting to find patterns. You have '+topRated.length+'.</div>'
      +'</div>';
  }
  // Tally common attributes
  function tallyMode(arr,getter){
    var counts={};
    arr.forEach(function(x){
      var v=getter(x);
      if(v==null||v==='')return;
      counts[v]=(counts[v]||0)+1;
    });
    var entries=Object.entries(counts).sort(function(a,b){return b[1]-a[1];});
    return entries.length?entries[0]:null;
  }
  function median(arr,getter){
    var vals=arr.map(getter).filter(function(v){return v!=null&&!isNaN(v);}).sort(function(a,b){return a-b;});
    if(!vals.length)return null;
    var mid=Math.floor(vals.length/2);
    return vals.length%2?vals[mid]:(vals[mid-1]+vals[mid])/2;
  }
  var commonHoney=tallyMode(topRated,function(s){return s.honeyType;});
  var commonStyle=tallyMode(topRated,function(s){return s.style;});
  var commonYeast=tallyMode(topRated,function(s){return s.yeast;});
  var medianABV=median(topRated,function(s){return parseFloat(s.abv);});
  var medianDays=median(topRated,function(s){return s.daysToBottle;});
  var medianOG=median(topRated,function(s){return parseFloat(s.og);});

  function row(label,value,detail){
    if(!value)return'';
    return'<div style="display:flex;justify-content:space-between;align-items:baseline;padding:10px 0;border-bottom:1px solid var(--border)"><div style="font-family:var(--font-mono);font-size:10.5px;color:var(--text3);letter-spacing:1px">'+escHtml(label.toUpperCase())+'</div><div style="text-align:right"><div style="font-family:var(--font-display);font-size:14px;color:var(--gold2)">'+escHtml(String(value))+'</div>'+(detail?'<div style="font-size:10.5px;color:var(--text3);font-style:italic;margin-top:2px">'+escHtml(detail)+'</div>':'')+'</div></div>';
  }
  var rows=[
    commonHoney?row('Most common honey',commonHoney[0],'in '+commonHoney[1]+' of '+topRated.length+' top-rated batches'):'',
    commonStyle?row('Most common style',commonStyle[0],'in '+commonStyle[1]+' of '+topRated.length+' top-rated batches'):'',
    commonYeast?row('Most common yeast',commonYeast[0],'in '+commonYeast[1]+' of '+topRated.length+' top-rated batches'):'',
    medianABV!=null?row('Median ABV',medianABV.toFixed(1)+'%',null):'',
    medianOG!=null?row('Median OG',medianOG.toFixed(3),null):'',
    medianDays!=null?row('Median days to bottle',Math.round(medianDays)+' days',null):''
  ].filter(Boolean).join('');
  // List the actual batches
  topRated.sort(function(a,b){return b.rating-a.rating;});
  var batchList=topRated.slice(0,5).map(function(s){
    var stars='★'.repeat(s.rating)+'<span style="color:var(--bg4)">'+'★'.repeat(5-s.rating)+'</span>';
    return'<div onclick="showView(\'batch\',\''+s.batch.id+'\')" style="cursor:pointer;padding:8px 12px;background:var(--bg);border-left:3px solid '+getBatchColor(s.batch)+';border-radius:var(--radius);margin-bottom:4px"><div style="display:flex;justify-content:space-between;align-items:center"><div style="font-family:var(--font-display);font-size:13px;color:'+getBatchColor(s.batch)+'">'+escHtml(s.batch.name)+'</div><div>'+stars+'</div></div></div>';
  }).join('');
  return'<div class="card" style="margin-bottom:16px;border-left:3px solid var(--gold2)"><div class="card-header"><div class="card-title">🌟 WHAT YOUR BEST BATCHES SHARE</div><div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px">'+topRated.length+' BATCHES · 4★ AND ABOVE</div></div>'
    +rows
    +(batchList?'<div style="font-family:var(--font-mono);font-size:10px;color:var(--gold);letter-spacing:1.5px;margin:14px 0 6px">— TOP RATED —</div>'+batchList:'')
    +'</div>';
}

// Personal trend dashboard — year-over-year stats. Useful starting at year 2.
function renderPersonalTrends(){
  var bottled=APP.batches.filter(function(b){return APP.bottling[b.id];});
  // Group by start-year
  var byYear={};
  bottled.forEach(function(b){
    var year=new Date(b.startDate).getFullYear();
    if(isNaN(year))return;
    if(!byYear[year])byYear[year]={year:year,batches:[]};
    byYear[year].batches.push(b);
  });
  var years=Object.keys(byYear).map(Number).sort();
  if(years.length<2){
    return'<div class="card" style="margin-bottom:16px"><div class="card-header"><div class="card-title">📈 YEAR-OVER-YEAR TRENDS</div></div>'
      +'<div style="font-size:13px;color:var(--text3);font-style:italic;padding:14px 0">Need at least 2 brewing years to compute trends. You\'re in year '+years.length+'.</div>'
      +'</div>';
  }
  // Per-year aggregates
  years.forEach(function(y){
    var data=byYear[y];
    var ratings=[],attenuations=[],times=[],costPerBottle=[];
    data.batches.forEach(function(b){
      var bot=APP.bottling[b.id];
      var ts=(APP.tastings[b.id]||[]).filter(function(t){return t.rating;});
      if(ts.length){
        ratings.push(ts.reduce(function(s,t){return s+t.rating;},0)/ts.length);
      }
      if(b.og&&bot.fg){
        attenuations.push((b.og-bot.fg)/(b.og-1)*100);
      }
      if(b.startDate&&bot.date){
        times.push(Math.floor((new Date(bot.date)-new Date(b.startDate))/86400000));
      }
      if(b.cost){
        var total=(b.cost.honey||0)+(b.cost.extras||0);
        var bottles=bottlesOriginal(bot);
        if(total>0&&bottles>0)costPerBottle.push(total/bottles);
      }
    });
    function avg(arr){return arr.length?arr.reduce(function(s,v){return s+v;},0)/arr.length:null;}
    data.batchCount=data.batches.length;
    data.avgRating=avg(ratings);
    data.avgAttenuation=avg(attenuations);
    data.avgDaysToBottle=avg(times);
    data.avgCostPerBottle=avg(costPerBottle);
  });
  var ccy=APP.settings.currency||'€';

  function renderYearColumn(y,prevY){
    var d=byYear[y];
    var prev=prevY?byYear[prevY]:null;
    function deltaPill(curr,prev,fmt,higherIsBetter){
      if(curr==null||prev==null)return'';
      var diff=curr-prev;
      if(Math.abs(diff)<0.001)return'';
      var isGood=higherIsBetter?(diff>0):(diff<0);
      var color=isGood?'var(--green2)':'var(--red2)';
      return'<span style="font-family:var(--font-mono);font-size:9.5px;color:'+color+';margin-left:6px;letter-spacing:0.5px">'+(diff>=0?'▲':'▼')+' '+fmt(Math.abs(diff))+'</span>';
    }
    return'<div style="background:var(--bg);border-radius:var(--radius);padding:14px;flex:1;min-width:0">'
      +'<div style="font-family:var(--font-display);font-size:24px;color:var(--gold2);margin-bottom:14px">'+y+'</div>'
      +'<div style="margin-bottom:10px"><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-bottom:2px">BATCHES BREWED</div><div style="font-size:14px;color:var(--text);font-family:var(--font-display)">'+d.batchCount+(prev?deltaPill(d.batchCount,prev.batchCount,function(v){return Math.round(v);},true):'')+'</div></div>'
      +(d.avgRating!=null?'<div style="margin-bottom:10px"><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-bottom:2px">AVG TASTING RATING</div><div style="font-size:14px;color:var(--text);font-family:var(--font-display)">'+d.avgRating.toFixed(2)+'★'+(prev&&prev.avgRating!=null?deltaPill(d.avgRating,prev.avgRating,function(v){return v.toFixed(2);},true):'')+'</div></div>':'')
      +(d.avgAttenuation!=null?'<div style="margin-bottom:10px"><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-bottom:2px">AVG ATTENUATION</div><div style="font-size:14px;color:var(--text);font-family:var(--font-display)">'+d.avgAttenuation.toFixed(0)+'%'+(prev&&prev.avgAttenuation!=null?deltaPill(d.avgAttenuation,prev.avgAttenuation,function(v){return v.toFixed(0)+'%';},true):'')+'</div></div>':'')
      +(d.avgDaysToBottle!=null?'<div style="margin-bottom:10px"><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-bottom:2px">AVG DAYS TO BOTTLE</div><div style="font-size:14px;color:var(--text);font-family:var(--font-display)">'+Math.round(d.avgDaysToBottle)+'d'+(prev&&prev.avgDaysToBottle!=null?deltaPill(d.avgDaysToBottle,prev.avgDaysToBottle,function(v){return Math.round(v)+'d';},false):'')+'</div></div>':'')
      +(d.avgCostPerBottle!=null?'<div style="margin-bottom:10px"><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-bottom:2px">AVG COST / BOTTLE</div><div style="font-size:14px;color:var(--text);font-family:var(--font-display)">'+ccy+d.avgCostPerBottle.toFixed(2)+(prev&&prev.avgCostPerBottle!=null?deltaPill(d.avgCostPerBottle,prev.avgCostPerBottle,function(v){return ccy+v.toFixed(2);},false):'')+'</div></div>':'')
      +'</div>';
  }
  // Show last 4 years
  var displayYears=years.slice(-4);
  var cols=displayYears.map(function(y,idx){
    var prev=idx>0?displayYears[idx-1]:null;
    return renderYearColumn(y,prev);
  }).join('');
  return'<div class="card" style="margin-bottom:16px"><div class="card-header"><div class="card-title">📈 YEAR-OVER-YEAR TRENDS</div></div>'
    +'<div style="font-size:12.5px;color:var(--text3);margin-bottom:14px;line-height:1.55">Arrows show change from the previous year. Green = improving (higher ratings, faster attenuation, lower cost), red = regressing.</div>'
    +'<div style="display:flex;gap:10px;flex-wrap:wrap">'+cols+'</div>'
    +'</div>';
}

// ==================== OFF-FLAVOR DIAGNOSTIC WIZARD ====================
// Interactive backwards-from-symptom troubleshooter. Pick the flavors you
// taste, get the likely causes ranked by overlap, with concrete fix steps.
// Data shape: each off-flavor maps to one or more causes, and each cause
// has steps to remediate or prevent. The UI tallies cause-matches across
// selected flavors and surfaces the top hits.

var OFF_FLAVOR_DB={
  'Rotten egg / sulphur':{
    icon:'🥚',
    causes:[{
      cause:'Stressed yeast / nitrogen deficiency',
      severity:'high',
      fix:['Stir vigorously to degas the H₂S','Add a half-dose of nutrient immediately','Warm to 22-24°C if currently cool','Time often heals — most sulphur dissipates by bottling']
    }]
  },
  'Band-aid / medicinal':{
    icon:'🩹',
    causes:[{
      cause:'Wild yeast or bacterial contamination (4-VG / phenolic)',
      severity:'high',
      fix:['Likely Brettanomyces or wild bacteria','Cannot be removed — accept or discard','Re-evaluate sanitation: sanitizer contact time and coverage','Replace porous gear (siphon tubing, plastic wand) — biofilm sticks']
    }]
  },
  'Vinegar / sharp acidic':{
    icon:'🍶',
    causes:[{
      cause:'Acetobacter contamination (oxygen exposure)',
      severity:'high',
      fix:['Limit oxygen contact: top up vessel, use airlock','Discard if strongly acetic — unrecoverable','Sanitize all vessels and gear with your no-rinse sanitizer','For prevention: fill bulk-aging vessels to >95%']
    }]
  },
  'Cardboard / wet paper / sherry':{
    icon:'📦',
    causes:[{
      cause:'Oxidation',
      severity:'medium',
      fix:['Add 0.5g/L potassium metabisulfite to bind oxygen','Rack with minimal splashing under the surface','For aging: keep headspace <3% in bulk vessels','Some "sherry" notes are stylistic in sack meads — context matters']
    }]
  },
  'Hot / solvent / nail polish':{
    icon:'🔥',
    causes:[{
      cause:'Fusel alcohols from high-temp fermentation',
      severity:'medium',
      fix:['Age 3-6 more months — fusels mellow significantly with time','Future batches: ferment 16-22°C, never above 26°C','Pitch enough yeast and stagger nutrients to reduce stress']
    }]
  },
  'Soapy / floral perfumed':{
    icon:'🧼',
    causes:[{
      cause:'Yeast autolysis (dead yeast cells released oils)',
      severity:'medium',
      fix:['Rack off the lees promptly after primary','Don\'t leave on gross lees longer than 3-4 weeks at warm temps','Future: cold-crash before racking to firm up sediment']
    },{
      cause:'Lavender or floral additions over-extracted',
      severity:'low',
      fix:['Reduce lavender to ≤8g per 5L next time, or use shorter contact time','Soap quality fades with 6-12 months of aging','Some character is style-appropriate for floral meads']
    }]
  },
  'Buttery / butterscotch':{
    icon:'🧈',
    causes:[{
      cause:'Diacetyl from incomplete fermentation',
      severity:'medium',
      fix:['Warm to 22-24°C and hold 7-14 days — yeast will reabsorb diacetyl','Don\'t rush bottling — let yeast clean up','Future: ensure adequate yeast pitch and nutrient']
    }]
  },
  'Yeasty / bready':{
    icon:'🍞',
    causes:[{
      cause:'Suspended yeast in young mead',
      severity:'low',
      fix:['Age longer — usually clears with 2-3 more months','Cold-crash 2 weeks at 2-4°C drops most yeast','Bentonite or gelatin fining for stubborn cases']
    }]
  },
  'Sourness / acetone':{
    icon:'🌬',
    causes:[{
      cause:'Lactobacillus or wild bacterial fermentation',
      severity:'high',
      fix:['Some sourness is style-appropriate (e.g. Pyment)','True acetone smell = unrecoverable, discard','Improve sanitation for future batches','Check tap water quality / source — chloramine inhibits but doesn\'t kill all bacteria']
    }]
  },
  'Astringent / mouth-drying':{
    icon:'🌿',
    causes:[{
      cause:'Over-extraction of tannins from fruit, herbs, or oak',
      severity:'low',
      fix:['Age 6+ months — astringency mellows','Future: shorter contact times, gentler fruit handling (no pulverizing)','For oak: reduce cube/chip contact by half']
    }]
  },
  'Sweet / cloying when expected dry':{
    icon:'🍯',
    causes:[{
      cause:'Stuck fermentation',
      severity:'medium',
      fix:['Check current SG against target','Add fresh nutrient and warm to 22-24°C','If still stuck, repitch with EC-1118 (alcohol-tolerant rescue strain)','Sometimes residual sweetness is fine — taste before "fixing"']
    }]
  },
  'Cooked / caramelized when not intended':{
    icon:'🍮',
    causes:[{
      cause:'Honey overheated during preparation',
      severity:'low',
      fix:['Future: never heat honey above 40°C','Maillard browning can be desirable in bochets — undesirable otherwise','Age to integrate flavor; some character will remain']
    }]
  }
};

function openOffFlavorWizard(){
  window._offFlavorSelections={};
  renderOffFlavorWizard();
}

function toggleOffFlavorSelection(flavor){
  if(!window._offFlavorSelections)window._offFlavorSelections={};
  if(window._offFlavorSelections[flavor])delete window._offFlavorSelections[flavor];
  else window._offFlavorSelections[flavor]=true;
  renderOffFlavorWizard();
}

function renderOffFlavorWizard(){
  closeModal();
  var sel=window._offFlavorSelections||{};
  var selectedFlavors=Object.keys(sel);
  // Build chips
  var chips=Object.keys(OFF_FLAVOR_DB).map(function(name){
    var isSel=!!sel[name];
    var entry=OFF_FLAVOR_DB[name];
    return'<span class="filter-chip '+(isSel?'active':'')+'" onclick="toggleOffFlavorSelection(\''+name.replace(/'/g,"\\'")+'\')" style="cursor:pointer;'+(isSel?'background:rgba(232,196,106,0.2);border-color:var(--gold);color:var(--gold2)':'')+'">'+entry.icon+' '+escHtml(name)+'</span>';
  }).join('');

  // Tally causes across selected flavors
  var causeMap={};
  selectedFlavors.forEach(function(f){
    var entry=OFF_FLAVOR_DB[f];
    if(!entry)return;
    entry.causes.forEach(function(c){
      if(!causeMap[c.cause])causeMap[c.cause]={cause:c.cause,severity:c.severity,fix:c.fix,flavors:[],hits:0};
      causeMap[c.cause].flavors.push(f);
      causeMap[c.cause].hits++;
    });
  });
  var causes=Object.values(causeMap).sort(function(a,b){return b.hits-a.hits;});
  var diagnosis;
  if(!selectedFlavors.length){
    diagnosis='<div style="padding:30px;text-align:center;color:var(--text3);font-style:italic">Select one or more off-flavors above to get likely causes and remediation steps.</div>';
  }else{
    diagnosis=causes.map(function(c){
      var sevColor=c.severity==='high'?'var(--red)':c.severity==='medium'?'var(--gold)':'var(--text3)';
      var sevLabel=c.severity==='high'?'LIKELY':c.severity==='medium'?'POSSIBLE':'SECONDARY';
      var multiHit=c.hits>1?'<span style="font-family:var(--font-mono);font-size:10px;color:var(--gold2);margin-left:8px">'+c.hits+' flavor matches</span>':'';
      return'<div style="background:var(--bg);border-left:3px solid '+sevColor+';border-radius:var(--radius);padding:14px;margin-bottom:10px">'
        +'<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:8px"><div style="font-family:var(--font-display);font-size:14px;color:var(--text)">'+escHtml(c.cause)+multiHit+'</div><div style="font-family:var(--font-mono);font-size:10px;color:'+sevColor+';letter-spacing:1.5px">'+sevLabel+'</div></div>'
        +'<ol style="padding-left:22px;margin:0;font-size:12.5px;color:var(--text2);line-height:1.6">'
        +c.fix.map(function(s){return'<li>'+escHtml(s)+'</li>';}).join('')
        +'</ol>'
        +'</div>';
    }).join('');
  }

  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:780px;max-height:92vh;display:flex;flex-direction:column">'
    +'<div class="modal-title">🧭 OFF-FLAVOR DIAGNOSTIC WIZARD</div>'
    +'<div style="font-size:12.5px;color:var(--text3);margin-bottom:14px;line-height:1.55">Pick the flavors and aromas you\'re detecting in your batch. Multiple selections combine — common causes float to the top.</div>'
    +'<div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px;padding-bottom:12px;border-bottom:1px solid var(--border)">'+chips+'</div>'
    +'<div style="flex:1;overflow-y:auto">'+diagnosis+'</div>'
    +'<div class="modal-actions" style="border-top:1px solid var(--border);padding-top:14px;margin-top:14px"><button class="btn btn-secondary" onclick="closeModal()">Close</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}

// Open a troubleshooting topic's step-by-step guidance in a detail modal.
// Topics live across two arrays (brewing + app/sync); search both by id.
function openTroubleshootTopic(id){
  var all=((typeof TROUBLESHOOT_TOPICS!=='undefined'&&TROUBLESHOOT_TOPICS)||[])
    .concat((typeof APP_TROUBLESHOOT_TOPICS!=='undefined'&&APP_TROUBLESHOOT_TOPICS)||[]);
  var t=all.find(function(x){return x.id===id;});
  if(!t)return;
  closeModal();
  var stepsHtml=t.steps.map(function(s){return'<li style="margin-bottom:10px;line-height:1.55">'+s+'</li>';}).join('');
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:600px">'
    +'<div class="modal-title">'+t.icon+' '+escHtml(t.title)+'</div>'
    +(t.category?'<div style="font-family:var(--font-mono);font-size:10px;letter-spacing:1.5px;color:var(--text3);text-transform:uppercase;margin:-12px 0 14px">'+escHtml(t.category)+'</div>':'')
    +'<ol style="padding-left:22px;margin:0;font-size:13.5px;color:var(--text2)">'+stepsHtml+'</ol>'
    +'<div class="modal-actions"><button class="btn btn-secondary" onclick="closeModal()">Close</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}
function renderTroubleshoot(){
  // Group by category — each category becomes a large card, with its topics as
  // button-cards inside that open the step-by-step detail modal.
  var categories={};
  TROUBLESHOOT_TOPICS.forEach(function(t){
    var cat=t.category||'Other';
    if(!categories[cat])categories[cat]=[];
    categories[cat].push(t);
  });
  var CAT_ICONS={Fermentation:'🫧',Temperature:'🌡',"Off-Flavors":'👃',Clarity:'💧',Process:'🔧',Bottling:'🍾',Aging:'⏳',Sanitation:'🧼',Result:'🏁',Other:'🔧'};
  function topicBtn(t){
    return'<button class="ts-item" onclick="openTroubleshootTopic(\''+t.id+'\')">'
      +'<span class="ts-ico">'+t.icon+'</span>'
      +'<span style="flex:1;min-width:0"><span style="display:block;font-size:13px;line-height:1.35;color:var(--text)">'+escHtml(t.title)+'</span>'
      +'<span class="ts-meta">'+t.steps.length+' STEP'+(t.steps.length===1?'':'S')+' →</span></span>'
      +'</button>';
  }
  function catCard(cat,items,icon){
    return'<div class="card" style="margin-bottom:16px">'
      +'<div class="card-header" style="display:flex;justify-content:space-between;align-items:center"><div class="card-title">'+(icon||CAT_ICONS[cat]||'🔧')+' '+escHtml(cat)+'</div>'
      +'<span style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px">'+items.length+' topic'+(items.length===1?'':'s')+'</span></div>'
      +'<div class="ts-grid">'+items.map(topicBtn).join('')+'</div></div>';
  }
  var categoryOrder=['Fermentation','Temperature','Off-Flavors','Clarity','Process','Bottling','Aging','Sanitation','Result'];
  var seen={};
  var brewingHtml=categoryOrder.map(function(cat){if(!categories[cat])return'';seen[cat]=1;return catCard(cat,categories[cat]);}).join('');
  // any categories not in the explicit order land at the end
  brewingHtml+=Object.keys(categories).filter(function(c){return!seen[c];}).map(function(c){return catCard(c,categories[c]);}).join('');
  var appCard=catCard('App & Sync Issues',APP_TROUBLESHOOT_TOPICS,'🖥');
  return'<div class="page-title">Troubleshooting</div><div class="page-subtitle">Brewing problems and process guidance</div>'
    +'<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px"><button class="btn btn-primary" onclick="openOffFlavorWizard()">🧭 Off-flavor diagnostic wizard</button></div>'
    +'<div style="font-size:13px;color:var(--text2);margin-bottom:16px;font-style:italic">Pick a category, then tap a topic for step-by-step guidance — or use the diagnostic wizard above to work backward from observed flavors.</div>'
    +brewingHtml
    +appCard;
}

// ==================== TASTING EVOLUTION CHART ====================
// Overlays multiple tasting wheels for the same batch on a single radar,
// color-coded by date so you can see how the flavor profile evolved.
function renderTastingEvolution(tastings){
  if(!tastings||tastings.length<2)return'';
  var withWheels=tastings.filter(function(t){
    return t.wheel&&Object.values(t.wheel).some(function(v){return v>0;});
  });
  if(withWheels.length<2)return'';
  // Sort oldest → newest
  withWheels.sort(function(a,b){return(a.date||'').localeCompare(b.date||'');});
  // Color palette — gray (oldest) → gold (newest)
  function colorFor(idx,total){
    var t=total===1?0:idx/(total-1);
    // gray rgb(120,120,120) → gold rgb(232,196,106)
    var r=Math.round(120+(232-120)*t);
    var g=Math.round(120+(196-120)*t);
    var b=Math.round(120+(106-120)*t);
    return'rgb('+r+','+g+','+b+')';
  }
  var size=320,cx=size/2,cy=size/2,r=size/2-40,n=TASTING_AXES.length;
  // Grid rings
  var rings=[1,2,3,4,5].map(function(level){
    var pts=TASTING_AXES.map(function(ax,i){
      var angle=(Math.PI*2*i/n)-Math.PI/2;
      var d=r*(level/5);
      return(cx+Math.cos(angle)*d)+','+(cy+Math.sin(angle)*d);
    }).join(' ');
    return'<polygon points="'+pts+'" fill="none" stroke="#2a2a35" stroke-width="0.5"/>';
  }).join('');
  // Axis lines
  var axes=TASTING_AXES.map(function(ax,i){
    var angle=(Math.PI*2*i/n)-Math.PI/2;
    var ex=cx+Math.cos(angle)*r;
    var ey=cy+Math.sin(angle)*r;
    return'<line x1="'+cx+'" y1="'+cy+'" x2="'+ex+'" y2="'+ey+'" stroke="#2a2a35" stroke-width="0.5"/>';
  }).join('');
  // Axis labels
  var labels=TASTING_AXES.map(function(ax,i){
    var angle=(Math.PI*2*i/n)-Math.PI/2;
    var lx=cx+Math.cos(angle)*(r+22);
    var ly=cy+Math.sin(angle)*(r+22)+4;
    return'<text x="'+lx+'" y="'+ly+'" text-anchor="middle" fill="#a89880" font-family="var(--font-mono)" font-size="9" style="text-transform:uppercase;letter-spacing:1px">'+ax.label+'</text>';
  }).join('');
  // One polygon per tasting
  var polygons=withWheels.map(function(t,idx){
    var color=colorFor(idx,withWheels.length);
    var pts=TASTING_AXES.map(function(ax,i){
      var v=(t.wheel&&t.wheel[ax.key])||0;
      var angle=(Math.PI*2*i/n)-Math.PI/2;
      var d=r*(v/5);
      return(cx+Math.cos(angle)*d)+','+(cy+Math.sin(angle)*d);
    }).join(' ');
    var isLatest=idx===withWheels.length-1;
    return'<polygon points="'+pts+'" fill="'+color+(isLatest?'40':'15')+'" stroke="'+color+'" stroke-width="'+(isLatest?2:1)+'" stroke-dasharray="'+(isLatest?'':'3,2')+'"/>';
  }).join('');
  // Legend
  var legend=withWheels.map(function(t,idx){
    var color=colorFor(idx,withWheels.length);
    var isLatest=idx===withWheels.length-1;
    return'<div style="display:flex;align-items:center;gap:8px;padding:4px 0;font-size:11px;color:'+(isLatest?'var(--gold2)':'var(--text3)')+';font-family:var(--font-mono)">'
      +'<span style="display:inline-block;width:18px;height:3px;background:'+color+';border-radius:2px"></span>'
      +'<span>'+fmtDate(t.date)+(isLatest?' · LATEST':'')+'</span>'
      +'<span style="margin-left:auto;color:var(--text3)">'+'★'.repeat(t.rating||0)+'</span>'
      +'</div>';
  }).join('');
  return'<div class="card" style="margin-top:16px"><div class="card-header"><div class="card-title">🌀 TASTING EVOLUTION · '+withWheels.length+' notes</div></div>'
    +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;align-items:center;flex-wrap:wrap">'
    +'<div><svg viewBox="-40 -10 400 340" overflow="visible" style="width:100%;display:block;overflow:visible" preserveAspectRatio="xMidYMid meet">'+rings+axes+polygons+labels+'</svg></div>'
    +'<div>'+legend+'<div style="font-size:11px;color:var(--text3);font-style:italic;margin-top:10px;padding-top:8px;border-top:1px solid var(--border)">Faded outlines = earlier tastings. The solid gold polygon is the most recent. Notice which axes grew (more developed) and which mellowed (less pronounced) — that\'s your aging signature.</div></div>'
    +'</div></div>';
}

// ==================== TASTING SIDE-BY-SIDE COMPARISON ====================
// Pick 2-3 tastings of the same batch and see them rendered next to each other
// with all fields visible at once (rating, color, aroma, flavor, finish,
// wheel deltas, notes). Useful for tracking how a batch evolves with age.
//
// State lives on window._tastingCompare = { batchId, selectedIds: [] }.

function openTastingCompareModal(batchId){
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b){toast('⚠ Batch not found');return;}
  var tastings=APP.tastings[batchId]||[];
  if(tastings.length<2){toast('⚠ Need at least 2 tastings to compare');return;}
  // Default selection: most recent + oldest (good starter comparison).
  var sorted=tastings.slice().sort(function(a,b){return(a.date||'').localeCompare(b.date||'');});
  window._tastingCompare={
    batchId:batchId,
    selectedIds:[sorted[0].id,sorted[sorted.length-1].id]
  };
  renderTastingCompareModal();
}

function renderTastingCompareModal(){
  closeModal();
  var s=window._tastingCompare;
  if(!s)return;
  var b=APP.batches.find(function(x){return x.id===s.batchId;});
  if(!b)return;
  var tastings=(APP.tastings[s.batchId]||[]).slice().sort(function(a,b){return(a.date||'').localeCompare(b.date||'');});

  // Selector row — chip per tasting. Selected ones highlighted.
  var maxSelect=3;
  var chips=tastings.map(function(t){
    var sel=s.selectedIds.indexOf(t.id)!==-1;
    var label=fmtDate(t.date)+(t.rating?' · '+'★'.repeat(t.rating):'');
    return'<span class="filter-chip '+(sel?'active':'')+'" style="cursor:pointer;'+(sel?'background:rgba(232,196,106,0.2);border-color:var(--gold);color:var(--gold2)':'')+'" onclick="toggleTastingCompare(\''+t.id+'\')">'+escHtml(label)+'</span>';
  }).join('');

  var selected=tastings.filter(function(t){return s.selectedIds.indexOf(t.id)!==-1;});
  var body='';
  if(selected.length<2){
    body='<div style="padding:24px;text-align:center;color:var(--text3);font-style:italic">Pick at least 2 tastings above to compare them side by side. You can compare up to '+maxSelect+'.</div>';
  }else{
    // Column-per-tasting layout. Wheels overlaid in a combined radar.
    var cols=selected.map(function(t,idx){
      var color=['#c9a350','#8a8aa0','#a0c08a','#c89060'][idx%4];
      var fields=[
        ['Rating',t.rating?'★'.repeat(t.rating)+'☆'.repeat(5-t.rating):'—'],
        ['Color',t.color||'—'],
        ['Aroma',t.aroma||'—'],
        ['Flavor',t.flavor||'—'],
        ['Finish',t.finish||'—'],
        ['Notes',t.note||t.notes||'—']
      ];
      return'<div style="background:var(--bg);border-radius:var(--radius);border-top:3px solid '+color+';padding:14px;flex:1;min-width:0">'
        +'<div style="font-family:var(--font-display);font-size:13px;color:'+color+';margin-bottom:4px">'+fmtDate(t.date)+'</div>'
        +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px;margin-bottom:14px">DAY '+(typeof bottleDaysAged==='function'?(daysSince(t.date)+' since '+fmtDate(b.startDate)):'')+'</div>'
        +fields.map(function(f){
          return'<div style="margin-bottom:10px"><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-bottom:2px">'+f[0].toUpperCase()+'</div><div style="font-size:13px;color:var(--text);line-height:1.5">'+escHtml(f[1])+'</div></div>';
        }).join('')
        +'</div>';
    }).join('');

    // Overlaid radar across the selected tastings — reuses TASTING_AXES.
    var wheelOverlay='';
    if(typeof TASTING_AXES!=='undefined'){
      var withWheels=selected.filter(function(t){return t.wheel&&Object.values(t.wheel).some(function(v){return v>0;});});
      if(withWheels.length>=2){
        var size=320,cx=size/2,cy=size/2,r=size/2-40,n=TASTING_AXES.length;
        var rings=[1,2,3,4,5].map(function(level){
          var pts=TASTING_AXES.map(function(ax,i){
            var ang=(Math.PI*2*i/n)-Math.PI/2;
            var d=r*(level/5);
            return(cx+Math.cos(ang)*d)+','+(cy+Math.sin(ang)*d);
          }).join(' ');
          return'<polygon points="'+pts+'" fill="none" stroke="#2a2a35" stroke-width="0.5"/>';
        }).join('');
        var axes=TASTING_AXES.map(function(ax,i){
          var ang=(Math.PI*2*i/n)-Math.PI/2;
          var ex=cx+Math.cos(ang)*r;
          var ey=cy+Math.sin(ang)*r;
          return'<line x1="'+cx+'" y1="'+cy+'" x2="'+ex+'" y2="'+ey+'" stroke="#2a2a35" stroke-width="0.5"/>';
        }).join('');
        var labels=TASTING_AXES.map(function(ax,i){
          var ang=(Math.PI*2*i/n)-Math.PI/2;
          var lx=cx+Math.cos(ang)*(r+22);
          var ly=cy+Math.sin(ang)*(r+22)+4;
          return'<text x="'+lx+'" y="'+ly+'" text-anchor="middle" fill="#a89880" font-family="var(--font-mono)" font-size="9" style="letter-spacing:1px">'+ax.label+'</text>';
        }).join('');
        var polys=withWheels.map(function(t,idx){
          var color=['#c9a350','#8a8aa0','#a0c08a','#c89060'][idx%4];
          var pts=TASTING_AXES.map(function(ax,i){
            var v=(t.wheel&&t.wheel[ax.key])||0;
            var ang=(Math.PI*2*i/n)-Math.PI/2;
            var d=r*(v/5);
            return(cx+Math.cos(ang)*d)+','+(cy+Math.sin(ang)*d);
          }).join(' ');
          return'<polygon points="'+pts+'" fill="'+color+'30" stroke="'+color+'" stroke-width="1.5"/>';
        }).join('');
        var legend=withWheels.map(function(t,idx){
          var color=['#c9a350','#8a8aa0','#a0c08a','#c89060'][idx%4];
          return'<div style="display:flex;align-items:center;gap:8px;font-size:11px;font-family:var(--font-mono);color:var(--text2)"><span style="display:inline-block;width:16px;height:3px;background:'+color+';border-radius:2px"></span>'+fmtDate(t.date)+'</div>';
        }).join('');
        wheelOverlay='<div style="margin-top:20px;padding:14px;background:var(--bg);border-radius:var(--radius)">'
          +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin-bottom:12px">TASTING WHEEL OVERLAY</div>'
          +'<div style="display:grid;grid-template-columns:1fr auto;gap:14px;align-items:center">'
          +'<svg viewBox="-40 -10 400 340" style="width:100%;display:block;overflow:visible">'+rings+axes+polys+labels+'</svg>'
          +'<div style="display:flex;flex-direction:column;gap:8px">'+legend+'</div>'
          +'</div></div>';
      }
    }

    body='<div style="display:flex;gap:10px;flex-wrap:wrap;align-items:stretch">'+cols+'</div>'+wheelOverlay;
  }

  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:980px;max-height:92vh;display:flex;flex-direction:column">'
    +'<div class="modal-title">📊 COMPARE TASTINGS · '+escHtml(b.name)+'</div>'
    +'<div style="font-size:12.5px;color:var(--text3);margin-bottom:10px;line-height:1.55">Pick 2-3 tastings to view side by side. The radar overlay below combines tasting-wheel scores for batches that have them.</div>'
    +'<div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px;padding-bottom:10px;border-bottom:1px solid var(--border)">'+chips+'</div>'
    +'<div style="flex:1;overflow-y:auto">'+body+'</div>'
    +'<div class="modal-actions" style="border-top:1px solid var(--border);padding-top:14px"><button class="btn btn-secondary" onclick="closeModal()">Close</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}

function toggleTastingCompare(tastingId){
  var s=window._tastingCompare;
  if(!s)return;
  var idx=s.selectedIds.indexOf(tastingId);
  if(idx>=0){
    s.selectedIds.splice(idx,1);
  }else{
    if(s.selectedIds.length>=3){
      // Cycle: drop the oldest to make room for the new one.
      s.selectedIds.shift();
    }
    s.selectedIds.push(tastingId);
  }
  renderTastingCompareModal();
}

// ==================== PERSONAL RECORDS / MEADWRIGHT ACHIEVEMENTS ====================
function computePersonalRecords(){
  var records={
    highestABV:null,
    strongestAttenuation:null,
    longestAged:null,
    biggestYear:null,
    mostBottlesInBatch:null,
    totalBatchesLifetime:APP.batches.length,
    totalBottlesLifetime:0,
    bottlesDrunkLifetime:0,
    bottlesGiftedLifetime:0,
    oldestActiveBatch:null,
    distinctRecipes:0,
    highestRatedBatch:null
  };
  var recipesSeen={};
  // Track year batch counts
  var byYear={};
  APP.batches.forEach(function(b){
    recipesSeen[b.recipeId]=true;
    var y=new Date(b.startDate).getFullYear();
    byYear[y]=(byYear[y]||0)+1;
    var bot=APP.bottling[b.id];
    if(bot){
      var orig=bottlesOriginal(bot);
      records.totalBottlesLifetime+=orig;
      records.bottlesGiftedLifetime+=bottlesInLocation(bot,'gifted');
      records.bottlesDrunkLifetime+=orig-totalBottles(bot);
      // Highest ABV
      if(bot.abv&&(!records.highestABV||bot.abv>records.highestABV.value)){
        records.highestABV={value:bot.abv,batch:b};
      }
      // Strongest attenuation
      if(b.og&&bot.fg){
        var att=((b.og-bot.fg)/(b.og-1))*100;
        if(!records.strongestAttenuation||att>records.strongestAttenuation.value){
          records.strongestAttenuation={value:att,batch:b};
        }
      }
      // Most bottles in a batch
      if(!records.mostBottlesInBatch||orig>records.mostBottlesInBatch.value){
        records.mostBottlesInBatch={value:orig,batch:b};
      }
      // Longest aged — bottling date vs today (and still has bottles on-hand, i.e., aging)
      if(bottlesOnHand(bot)>0){
        var aged=Math.floor((Date.now()-new Date(bot.date).getTime())/86400000);
        if(!records.longestAged||aged>records.longestAged.value){
          records.longestAged={value:aged,batch:b};
        }
      }
    }else{
      // Oldest active batch (started but not bottled)
      var ageDays=daysSince(b.startDate);
      if(!records.oldestActiveBatch||ageDays>records.oldestActiveBatch.value){
        records.oldestActiveBatch={value:ageDays,batch:b};
      }
    }
    // Highest-rated tasting on this batch
    var tastings=APP.tastings[b.id]||[];
    tastings.forEach(function(t){
      if(t.rating&&(!records.highestRatedBatch||t.rating>records.highestRatedBatch.value||(t.rating===records.highestRatedBatch.value&&new Date(t.date)>new Date(records.highestRatedBatch.tasting.date)))){
        records.highestRatedBatch={value:t.rating,batch:b,tasting:t};
      }
    });
  });
  // Biggest year
  var maxY=0,maxYr=null;
  Object.keys(byYear).forEach(function(y){
    if(byYear[y]>maxY){maxY=byYear[y];maxYr=y;}
  });
  if(maxYr)records.biggestYear={value:maxY,year:maxYr};
  records.distinctRecipes=Object.keys(recipesSeen).length;
  return records;
}

function renderPersonalRecords(){
  var r=computePersonalRecords();
  function tile(icon,label,value,detail){
    return'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius);padding:14px;text-align:center">'
      +'<div style="font-size:24px;line-height:1">'+icon+'</div>'
      +'<div style="font-family:var(--font-display);font-size:24px;color:var(--gold2);margin:4px 0">'+(value||'—')+'</div>'
      +'<div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;text-transform:uppercase">'+label+'</div>'
      +(detail?'<div style="font-size:11px;color:var(--text2);margin-top:4px;font-style:italic;line-height:1.3">'+detail+'</div>':'')
      +'</div>';
  }
  return'<div class="card" style="margin-top:16px;border-color:var(--gold)"><div class="card-header"><div class="card-title">🏆 MEADWRIGHT RECORDS · ALL-TIME</div></div>'
    +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px">'
    +tile('🔥','Highest ABV',r.highestABV?r.highestABV.value.toFixed(1)+'%':'—',r.highestABV?escHtml(r.highestABV.batch.name):'')
    +tile('💪','Best Attenuation',r.strongestAttenuation?r.strongestAttenuation.value.toFixed(1)+'%':'—',r.strongestAttenuation?escHtml(r.strongestAttenuation.batch.name):'')
    +tile('⌛','Longest Aged',r.longestAged?fmtDaysShort(r.longestAged.value):'—',r.longestAged?escHtml(r.longestAged.batch.name)+' · still resting':'')
    +tile('📅','Biggest Year',r.biggestYear?r.biggestYear.value+' batches':'—',r.biggestYear?r.biggestYear.year:'')
    +tile('🍾','Largest Batch',r.mostBottlesInBatch?r.mostBottlesInBatch.value+' btl':'—',r.mostBottlesInBatch?escHtml(r.mostBottlesInBatch.batch.name):'')
    +tile('⭐','Top-Rated',r.highestRatedBatch?'★'.repeat(r.highestRatedBatch.value):'—',r.highestRatedBatch?escHtml(r.highestRatedBatch.batch.name):'')
    +tile('🧪','Recipes Tried',r.distinctRecipes,'distinct recipes')
    +tile('🎁','Bottles Gifted',r.bottlesGiftedLifetime,'shared with others')
    +'</div>'
    +'<div style="margin-top:14px;padding-top:12px;border-top:1px solid var(--border);font-family:var(--font-mono);font-size:11px;color:var(--text3);text-align:center">LIFETIME · '+r.totalBatchesLifetime+' batches · '+r.totalBottlesLifetime+' bottles produced · '+r.bottlesDrunkLifetime+' consumed</div>'
    +'</div>';
}

// ==================== BLENDING CALCULATOR ====================
function renderBlendingTool(){
  var bottled=APP.batches.filter(function(b){return APP.bottling[b.id]&&bottlesOnHand(APP.bottling[b.id])>0;});
  if(bottled.length<1){
    return'<div class="card"><div class="card-header"><div class="card-title">🥂 BLENDING CALCULATOR</div></div>'
      +'<div style="color:var(--text3);font-style:italic;padding:10px 0;font-size:13px">You need at least 1 bottled batch with bottles on-hand to blend (with another batch, or with water to lower strength). Currently you have '+bottled.length+'.</div></div>';
  }
  var opts=bottled.map(function(b){
    var bot=APP.bottling[b.id];
    return'<option value="'+b.id+'">'+escHtml(b.name)+' · '+(bot.abv||'?')+'% ABV · '+(bot.sweetness||'—')+' · '+bottlesOnHand(bot)+' avail</option>';
  }).join('');
  // Water as a B-side option — classic dilution of an over-strong mead.
  var optsB=opts+'<option value="__water">Plain water · 0% ABV (dilution)</option>';
  var idA=window._blendA||bottled[0].id;
  var idB=window._blendB||(bottled[1]?bottled[1].id:'__water');
  var ratioA=window._blendRatio||50;
  // Pre-compute the initial output HTML inline. Previously this used a trailing
  // <script>updateBlendOutput()<\/script> tag, but main.innerHTML=... refuses to
  // execute inline <script> nodes — so the output stayed blank until the user
  // first interacted with a control. By computing the markup here we render
  // useful output on first paint.
  var initialOutput=computeBlendOutputHTML(idA,idB,ratioA);
  return'<div class="card"><div class="card-header"><div class="card-title">🥂 BLENDING CALCULATOR</div></div>'
    +'<div style="font-size:13px;color:var(--text2);margin-bottom:12px">Blend two bottled meads in any ratio to predict the resulting ABV, sweetness, and per-litre cost. Useful for dialing in a balanced finish before committing.</div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Batch A</label><select class="form-select" id="blend-a" onchange="window._blendA=this.value;renderMain()">'+opts.replace('value="'+idA+'"','value="'+idA+'" selected')+'</select></div>'
    +'<div class="form-group"><label class="form-label">Batch B</label><select class="form-select" id="blend-b" onchange="window._blendB=this.value;renderMain()">'+optsB.replace('value="'+idB+'"','value="'+idB+'" selected')+'</select></div></div>'
    +'<div class="form-group"><label class="form-label">Total blend volume (L) — for the litre breakdown</label><input class="form-input" id="blend-vol" type="number" min="0.1" step="0.1" value="'+(window._blendVol||5)+'" oninput="window._blendVol=parseFloat(this.value)||5;updateBlendOutput()"></div>'
    +'<div class="form-group"><label class="form-label">Blend Ratio · A : B = <span id="blend-ratio-display">'+ratioA+' : '+(100-ratioA)+'</span></label>'
    +'<input type="range" min="10" max="90" step="5" value="'+ratioA+'" id="blend-ratio" oninput="window._blendRatio=parseInt(this.value);document.getElementById(\'blend-ratio-display\').textContent=this.value+\' : \'+(100-this.value);updateBlendOutput()" style="width:100%;cursor:pointer"></div>'
    +'<div id="blend-output" style="margin-top:14px">'+initialOutput+'</div>'
    +'</div>';
}

// Pure-data version of the blend rendering. Returns HTML string for the
// blend-output container based on the two selected batch IDs and ratio.
// Shared between initial render (renderBlendingTool) and live update
// (updateBlendOutput).
function computeBlendOutputHTML(idA,idB,ratioA){
  if(!idA||!idB)return'';
  var bA=APP.batches.find(function(x){return x.id===idA;});
  if(!bA)return'';
  var botA=APP.bottling[bA.id];
  if(!botA)return'';
  // Batch B may be the synthetic "water" entry — a 0% ABV, FG 1.000, no-cost,
  // no-flavour diluent. This is the classic fix for an over-strong or
  // over-sweet mead. Treat it as a pseudo-batch so the rest of the math is
  // identical.
  var isWater=(idB==='__water');
  var bB=isWater?null:APP.batches.find(function(x){return x.id===idB;});
  var botB=isWater?null:(bB&&APP.bottling[bB.id]);
  if(!isWater&&(!bB||!botB))return'';
  var fa=ratioA/100,fb=1-fa;
  var abvA=botA.abv||(bA.og&&botA.fg?parseFloat(calcABV(bA.og,botA.fg)):null);
  var abvB=isWater?0:(botB.abv||(bB.og&&botB.fg?parseFloat(calcABV(bB.og,botB.fg)):null));
  var blendedABV=(abvA!=null&&abvB!=null)?(abvA*fa+abvB*fb):null;
  var fgA=botA.fg||1.010;
  var fgB=isWater?1.000:(botB.fg||1.010);
  var blendedFG=fgA*fa+fgB*fb;
  var sweetIdx={'Bone Dry':0,'Dry':1,'Off-Dry':2,'Semi-Sweet':3,'Sweet':4,'Dessert':5,'':2};
  // Water has no sugar — pull sweetness DOWN toward bone-dry, scaled by how
  // much water is in the blend, rather than parking it at the neutral midpoint.
  var sA=(sweetIdx[botA.sweetness||'']!=null?sweetIdx[botA.sweetness||'']:2);
  var sB=isWater?0:(sweetIdx[botB.sweetness||'']!=null?sweetIdx[botB.sweetness||'']:2);
  var sIdx=sA*fa+sB*fb;
  var sLabels=['Bone Dry','Dry','Off-Dry','Semi-Sweet','Sweet','Dessert'];
  var blendedSweet=sLabels[Math.round(Math.max(0,Math.min(5,sIdx)))];
  var ccy=APP.settings.currency||'€';
  var costA=(bA.cost&&bottlesOriginal(botA)>0)?((bA.cost.honey||0)+(bA.cost.extras||0))/bottlesOriginal(botA):0;
  var costB=isWater?0:((bB.cost&&bottlesOriginal(botB)>0)?((bB.cost.honey||0)+(bB.cost.extras||0))/bottlesOriginal(botB):0);
  var blendedCost=costA*fa+costB*fb;
  var colorA=getBatchColor(bA),colorB=isWater?'#5a7a8a':getBatchColor(bB);
  var nameB=isWater?'Water':bB.name;
  // Litre breakdown for the chosen total volume — what you actually pour.
  var totVol=window._blendVol||5;
  var litA=totVol*fa, litB=totVol*fb;
  var unit=(typeof currentUnitSystem==='function'&&currentUnitSystem()!=='metric');
  function volStr(L){
    if(!unit)return L.toFixed(2)+' L';
    var q=L*1.05669; return L.toFixed(2)+' L ('+q.toFixed(2)+' qt)';
  }
  return'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:10px;margin-bottom:12px">'
    +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius);padding:14px;text-align:center"><div style="font-family:var(--font-display);font-size:24px;color:var(--gold2)">'+(blendedABV!=null?blendedABV.toFixed(1)+'%':'—')+'</div><div class="micro-label">BLENDED ABV</div></div>'
    +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius);padding:14px;text-align:center"><div style="font-family:var(--font-display);font-size:24px;color:var(--blue2)">'+blendedFG.toFixed(3)+'</div><div class="micro-label">BLENDED FG</div></div>'
    +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius);padding:14px;text-align:center"><div style="font-family:var(--font-display);font-size:16px;color:var(--text2);font-style:italic">'+blendedSweet+'</div><div class="micro-label">PROFILE</div></div>'
    +(blendedCost>0?'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius);padding:14px;text-align:center"><div style="font-family:var(--font-display);font-size:24px;color:var(--green2)">'+ccy+blendedCost.toFixed(2)+'</div><div class="micro-label">PER-BOTTLE COST</div></div>':'')
    +'</div>'
    +'<div style="display:flex;gap:0;height:40px;border-radius:var(--radius);overflow:hidden;border:1px solid var(--border);margin-bottom:8px">'
    +'<div style="width:'+ratioA+'%;background:'+colorA+';display:flex;align-items:center;justify-content:center;color:#fff;font-family:var(--font-display);font-size:12px;letter-spacing:1px">'+escHtml(bA.name.slice(0,18))+(bA.name.length>18?'…':'')+' · '+ratioA+'%</div>'
    +'<div style="width:'+(100-ratioA)+'%;background:'+colorB+';display:flex;align-items:center;justify-content:center;color:#fff;font-family:var(--font-display);font-size:12px;letter-spacing:1px">'+escHtml(nameB.slice(0,18))+(nameB.length>18?'…':'')+' · '+(100-ratioA)+'%</div>'
    +'</div>'
    +'<div style="display:flex;gap:8px;margin-bottom:8px;font-family:var(--font-mono);font-size:11.5px;color:var(--text2)">'
    +'<div style="flex:1;text-align:center;padding:7px;background:var(--bg4);border-radius:var(--radius)"><span style="color:'+colorA+'">●</span> '+escHtml(bA.name.slice(0,16))+': <strong>'+volStr(litA)+'</strong></div>'
    +'<div style="flex:1;text-align:center;padding:7px;background:var(--bg4);border-radius:var(--radius)"><span style="color:'+colorB+'">●</span> '+escHtml(nameB.slice(0,16))+': <strong>'+volStr(litB)+'</strong></div>'
    +'</div>'
    +'<div style="font-size:11px;color:var(--text3);font-style:italic;text-align:center">Approximate values. Sweetness blends linearly on a 6-point scale; real blending may shift slightly with carbonation, oxidation, or rest time. '+(isWater?'Diluting with water also thins body and aroma — taste as you go.':'Bench-trial a small measured blend before committing the whole batch.')+'</div>';
}

function updateBlendOutput(){
  var idA=window._blendA||(document.getElementById('blend-a')&&document.getElementById('blend-a').value);
  var idB=window._blendB||(document.getElementById('blend-b')&&document.getElementById('blend-b').value);
  var ratioA=window._blendRatio||50;
  var out=document.getElementById('blend-output');
  if(!out)return;
  out.innerHTML=computeBlendOutputHTML(idA,idB,ratioA);
}

// ==================== CROSS-BATCH YEAST ANALYTICS ====================
function renderYeastAnalytics(){
  // Group bottled batches by yeast (or 'M05' default if not set)
  var bottled=APP.batches.filter(function(b){return APP.bottling[b.id];});
  if(!bottled.length)return'';
  var byYeast={};
  bottled.forEach(function(b){
    var yeast=b.yeast||'M05';
    if(!byYeast[yeast])byYeast[yeast]={batches:[],attenuations:[],abvs:[],ferments:[],ogToFG:[]};
    byYeast[yeast].batches.push(b);
    var bot=APP.bottling[b.id];
    if(b.og&&bot.fg){
      byYeast[yeast].attenuations.push(((b.og-bot.fg)/(b.og-1))*100);
      byYeast[yeast].ogToFG.push({og:b.og,fg:bot.fg});
    }
    if(bot.abv)byYeast[yeast].abvs.push(bot.abv);
    if(bot.date){
      var ferment=Math.floor((new Date(bot.date)-new Date(b.startDate))/86400000);
      if(ferment>0&&ferment<400)byYeast[yeast].ferments.push(ferment);
    }
  });
  function stats(arr){
    if(!arr.length)return null;
    var sum=arr.reduce(function(a,v){return a+v;},0);
    return{avg:sum/arr.length,min:Math.min.apply(null,arr),max:Math.max.apply(null,arr),n:arr.length};
  }
  var cards=Object.keys(byYeast).map(function(yeast){
    var d=byYeast[yeast];
    var attS=stats(d.attenuations);
    var abvS=stats(d.abvs);
    var fermS=stats(d.ferments);
    // Color for yeast
    var c=yeast==='M05'?'#c9a84c':yeast==='K1V-1116'?'#8a3838':yeast==='71B'?'#5a8db8':yeast==='EC-1118'?'#6a8a4a':'#a0a0a0';
    return'<div style="background:var(--bg3);border:1px solid var(--border);border-left:3px solid '+c+';border-radius:var(--radius);padding:14px;margin-bottom:10px">'
      +'<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:10px"><div style="font-family:var(--font-display);font-size:15px;color:'+c+';letter-spacing:1.5px">'+escHtml(yeast)+'</div><div style="font-family:var(--font-mono);font-size:11px;color:var(--text3)">'+d.batches.length+' batch'+(d.batches.length!==1?'es':'')+'</div></div>'
      +'<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(110px,1fr));gap:8px">'
      +(attS?'<div style="text-align:center;padding:8px 4px;background:var(--bg4);border-radius:6px"><div style="font-family:var(--font-display);font-size:18px;color:var(--gold2)">'+attS.avg.toFixed(1)+'%</div><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1px;margin-top:2px">AVG ATTEN.</div><div style="font-size:10px;color:var(--text3);margin-top:2px">'+attS.min.toFixed(0)+'–'+attS.max.toFixed(0)+'%</div></div>':'')
      +(abvS?'<div style="text-align:center;padding:8px 4px;background:var(--bg4);border-radius:6px"><div style="font-family:var(--font-display);font-size:18px;color:var(--gold2)">'+abvS.avg.toFixed(1)+'%</div><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1px;margin-top:2px">AVG ABV</div><div style="font-size:10px;color:var(--text3);margin-top:2px">'+abvS.min.toFixed(1)+'–'+abvS.max.toFixed(1)+'%</div></div>':'')
      +(fermS?'<div style="text-align:center;padding:8px 4px;background:var(--bg4);border-radius:6px"><div style="font-family:var(--font-display);font-size:18px;color:var(--gold2)">'+fmtDurationCompact(Math.round(fermS.avg))+'</div><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1px;margin-top:2px">AVG FERMENT</div><div style="font-size:10px;color:var(--text3);margin-top:2px">'+fmtDurationCompact(fermS.min)+'–'+fmtDurationCompact(fermS.max)+'</div></div>':'')
      +'</div>'
      +(yeast==='M05'&&attS?'<div style="font-size:11px;color:var(--text3);margin-top:10px;padding-top:8px;border-top:1px solid var(--border);font-style:italic">Mangrove Jack spec: 95-100% attenuation, up to 18% ABV tolerance. Your '+attS.avg.toFixed(1)+'% '+(attS.avg<90?'is below spec — check temp/nutrients':attS.avg>95?'matches the published profile':'is close to spec')+'.</div>':'')
      +'</div>';
  }).join('');
  return'<div><div class="card-header" style="margin-bottom:10px"><div class="card-title">🧪 YEAST PERFORMANCE · LONGITUDINAL</div></div>'+cards+'</div>';
}

// ==================== GIFT RECIPIENT LOG ====================
// When the gifted location count is increased, prompt for who received the bottles.
// Stored per-bottling as bot.gifts = [{id, date, recipient, count, occasion, notes}].

function openGiftRecipientModal(batchId,deltaCount,size){
  closeModal();
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b)return;
  size=size||DEFAULT_BOTTLE_SIZE;
  // Suggest recipient names from prior gifts
  var priorRecipients={};
  Object.keys(APP.bottling).forEach(function(bid){
    var bot=APP.bottling[bid];
    if(bot.gifts)bot.gifts.forEach(function(g){priorRecipients[g.recipient]=true;});
  });
  var dataListOpts=Object.keys(priorRecipients).map(function(n){return'<option value="'+escHtml(n)+'">';}).join('');
  document.body.insertAdjacentHTML('beforeend',
    '<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:460px">'
    +'<div class="modal-title">🎁 RECORD GIFT'+(deltaCount>1?' ('+deltaCount+' × '+size+'ml)':' ('+size+'ml)')+'</div>'
    +'<div style="font-size:13px;color:var(--text2);margin-bottom:14px">Recording '+deltaCount+' × '+size+'ml gift'+(deltaCount!==1?'s':'')+' of <strong style="color:var(--gold2)">'+escHtml(b.name)+'</strong>. Track who got the bottle'+(deltaCount!==1?'s':'')+' so you can follow up later.</div>'
    +'<input type="hidden" id="gift-size" value="'+size+'">'
    +'<div class="form-group"><label class="form-label">Recipient</label><input class="form-input" id="gift-recipient" placeholder="Mom / Sarah / Jan & Marie" list="gift-recipients-list" autofocus>'
    +'<datalist id="gift-recipients-list">'+dataListOpts+'</datalist></div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Date</label><input class="form-input" type="date" id="gift-date" value="'+today()+'"></div>'
    +'<div class="form-group"><label class="form-label">Bottles</label><input class="form-input" type="number" id="gift-count" min="1" value="'+deltaCount+'"></div></div>'
    +'<div class="form-group"><label class="form-label">Occasion (optional)</label><input class="form-input" id="gift-occasion" placeholder="Birthday / Christmas / Just because"></div>'
    +'<div class="form-group"><label class="form-label">Notes (optional)</label><textarea class="form-textarea" id="gift-notes" placeholder="They loved the cherry one last time, prefer drier…"></textarea></div>'
    +'<div class="modal-actions">'
    +'<button class="btn btn-secondary" onclick="skipGiftRecording(\''+batchId+'\','+deltaCount+','+size+')">Skip — Just Count</button>'
    +'<button class="btn btn-primary" onclick="saveGiftRecord(\''+batchId+'\','+deltaCount+','+size+')">Save Gift</button>'
    +'</div></div></div>');
  setTimeout(function(){var r=document.getElementById('gift-recipient');if(r)r.focus();},50);
}

function saveGiftRecord(batchId,deltaCount,size){
  var bot=APP.bottling[batchId];
  if(!bot)return;
  size=parseInt(size)||DEFAULT_BOTTLE_SIZE;
  var recipient=document.getElementById('gift-recipient').value.trim();
  if(!recipient){toast('⚠ Enter a recipient or click Skip');return;}
  var count=parseInt(document.getElementById('gift-count').value)||deltaCount;
  if(!bot.locations)bot.locations={cellar:{},fridge:{},gifted:{},other:{}};
  if((bot.locations.cellar[size]||0)<count){
    toast('⚠ Only '+(bot.locations.cellar[size]||0)+' × '+size+'ml in cellar — cannot gift '+count);
    return;
  }
  if(!bot.gifts)bot.gifts=[];
  bot.gifts.push({
    id:genId(),
    date:document.getElementById('gift-date').value||today(),
    recipient:recipient,
    count:count,
    size:size,
    occasion:document.getElementById('gift-occasion').value.trim(),
    notes:document.getElementById('gift-notes').value.trim()
  });
  // Transfer: cellar[size] -> gifted[size]
  bot.locations.cellar[size]=(bot.locations.cellar[size]||0)-count;
  bot.locations.gifted[size]=(bot.locations.gifted[size]||0)+count;
  if(bot.locations.cellar[size]<=0)delete bot.locations.cellar[size];
  closeModal();
  scheduleSave();
  toast('🎁 '+count+' × '+size+'ml bottle'+(count!==1?'s':'')+' gifted to '+recipient);
  renderMain();
}

function skipGiftRecording(batchId,deltaCount,size){
  var bot=APP.bottling[batchId];
  if(!bot)return;
  size=parseInt(size)||DEFAULT_BOTTLE_SIZE;
  if(!bot.locations)bot.locations={cellar:{},fridge:{},gifted:{},other:{}};
  if((bot.locations.cellar[size]||0)<deltaCount){
    toast('⚠ Not enough in cellar');
    closeModal();
    renderMain();
    return;
  }
  bot.locations.cellar[size]=(bot.locations.cellar[size]||0)-deltaCount;
  bot.locations.gifted[size]=(bot.locations.gifted[size]||0)+deltaCount;
  if(bot.locations.cellar[size]<=0)delete bot.locations.cellar[size];
  closeModal();
  scheduleSave();
  toast('🎁 '+deltaCount+' × '+size+'ml bottle'+(deltaCount!==1?'s':'')+' marked as gifted (no recipient recorded)');
  renderMain();
}

function deleteGiftRecord(batchId,giftId){
  if(!confirm('Delete this gift record? Bottles will return to the cellar count.'))return;
  var bot=APP.bottling[batchId];
  if(!bot||!bot.gifts)return;
  var gift=bot.gifts.find(function(g){return g.id===giftId;});
  if(!gift)return;
  bot.gifts=bot.gifts.filter(function(g){return g.id!==giftId;});
  var size=gift.size||DEFAULT_BOTTLE_SIZE;
  if(bot.locations){
    if(!bot.locations.gifted)bot.locations.gifted={};
    if(!bot.locations.cellar)bot.locations.cellar={};
    bot.locations.gifted[size]=Math.max(0,(bot.locations.gifted[size]||0)-gift.count);
    bot.locations.cellar[size]=(bot.locations.cellar[size]||0)+gift.count;
    if(bot.locations.gifted[size]<=0)delete bot.locations.gifted[size];
  }
  scheduleSave();toast('Gift record deleted, '+gift.count+' × '+size+'ml returned to cellar');renderMain();
}

function renderGiftHistory(bot,batchId){
  if(!bot.gifts||!bot.gifts.length)return'';
  // Aggregate by recipient
  var byRecipient={};
  bot.gifts.forEach(function(g){
    if(!byRecipient[g.recipient])byRecipient[g.recipient]={count:0,gifts:[]};
    byRecipient[g.recipient].count+=g.count;
    byRecipient[g.recipient].gifts.push(g);
  });
  var summary=Object.keys(byRecipient).map(function(name){
    var d=byRecipient[name];
    return escHtml(name)+(d.count>1?' ('+d.count+')':'');
  }).join(', ');
  return'<div style="margin-top:8px;font-size:11px;color:var(--text3);padding:6px 8px;background:var(--bg4);border-radius:6px;border-left:2px solid var(--gold)">'
    +'<span style="font-family:var(--font-mono);letter-spacing:1px;color:var(--gold2)">🎁 GIVEN TO:</span> '+summary
    +' <button class="btn btn-secondary btn-sm" style="margin-left:6px;padding:2px 8px;font-size:10px" onclick="showGiftDetails(\''+batchId+'\')">Details</button>'
    +'</div>';
}

function showGiftDetails(batchId){
  closeModal();
  var bot=APP.bottling[batchId];
  if(!bot||!bot.gifts||!bot.gifts.length)return;
  var b=APP.batches.find(function(x){return x.id===batchId;});
  var rows=bot.gifts.slice().sort(function(a,c){return(c.date||'').localeCompare(a.date||'');}).map(function(g){
    return'<div style="display:flex;gap:12px;padding:10px 0;border-bottom:1px solid var(--border);align-items:flex-start">'
      +'<div style="flex:1"><div style="font-family:var(--font-display);font-size:14px;color:var(--gold2)">'+escHtml(g.recipient)+'</div>'
      +'<div style="font-size:11px;color:var(--text3);margin-top:2px">'+fmtDate(g.date)+(g.occasion?' · '+escHtml(g.occasion):'')+'</div>'
      +(g.notes?'<div style="font-size:12px;color:var(--text2);margin-top:4px;font-style:italic">'+escHtml(g.notes)+'</div>':'')+'</div>'
      +'<div style="text-align:right"><div style="font-family:var(--font-display);font-size:16px;color:var(--gold2)">'+g.count+'</div><div style="font-size:9px;color:var(--text3);font-family:var(--font-mono)">BOTTLE'+(g.count!==1?'S':'')+'</div></div>'
      +'<button class="btn-icon" onclick="deleteGiftRecord(\''+batchId+'\',\''+g.id+'\')" title="Delete record">×</button>'
      +'</div>';
  }).join('');
  document.body.insertAdjacentHTML('beforeend',
    '<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:520px">'
    +'<div class="modal-title">🎁 GIFTS · '+escHtml(b?b.name:'')+'</div>'
    +'<div style="font-size:12px;color:var(--text3);margin-bottom:8px;font-family:var(--font-mono);letter-spacing:1px">'+bot.gifts.length+' gift'+(bot.gifts.length!==1?'s':'')+' · '+bot.gifts.reduce(function(s,g){return s+g.count;},0)+' bottles total</div>'
    +rows
    +'<div class="modal-actions"><button class="btn btn-primary" onclick="closeModal()">Close</button></div>'
    +'</div></div>');
}

// ==================== BOTTLING DAY GUIDED WORKFLOW ====================
// Multi-step modal walking the user through bottling: pre-flight → final gravity →
// sanitize timer → fill → label preview → save. Replaces the "form in a vacuum"
// experience with a checklist-driven flow.

var BOTTLING_STEPS=[
  {id:'preflight',title:'Pre-Flight',icon:'✓'},
  {id:'fg',title:'Final Gravity',icon:'⚗'},
  {id:'sanitize',title:'Sanitize',icon:'🧴'},
  {id:'fill',title:'Fill Bottles',icon:'🍾'},
  {id:'label',title:'Labels',icon:'🏷'},
  {id:'finish',title:'Save',icon:'✦'}
];

var bottlingWorkflowState={
  batchId:null,
  stepIdx:0,
  preflight:{},
  fg:null,
  abv:null,
  sanitizerStartedAt:null,
  sanitizerCompleted:false,
  counts:{500:0,750:0},  // per-size bottle counts
  closure:'crown',       // 'crown' | 'cork' — drives deduction + cost
  customSize:0,
  customQty:0,
  sweetness:'',
  notes:'',
  date:''
};

function startBottlingWorkflow(batchId){
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b){toast('⚠ Batch not found');return;}
  var existing=APP.bottling[batchId]||{};
  // Previously this used `APP.logs[batchId][batchId.length-1]` — indexing by
  // the batch *ID's* string length, which silently returned undefined for
  // anything other than ~24-element log arrays. Fix: index by the log array's
  // own length minus one.
  var batchLogs=APP.logs[batchId]||[];
  var lastLog=batchLogs.length?batchLogs[batchLogs.length-1]:null;
  // Try to read existing per-size counts
  var existingCounts=existing.countsAtBottling?_coerceLocations(existing.countsAtBottling):{};
  var c500=existingCounts[500]||0;
  var c750=existingCounts[750]||(!existing.countsAtBottling&&existing.bottleCount?existing.bottleCount:0);
  var customSize=0,customQty=0;
  Object.keys(existingCounts).forEach(function(s){if(s!=='500'&&s!=='750'){customSize=parseInt(s);customQty=existingCounts[s];}});
  // ABV gap fix: if there's no existing.fg yet but we DO have a recent log, use
  // that log's gravity for the initial ABV estimate. Previously the workflow
  // started with abv=null on first-time bottling even though we had a valid
  // gravity reading to work from.
  var initialFg=existing.fg||(lastLog?lastLog.gravity:null);
  var initialClosure=existing.closure||'crown';
  // Restore any in-flight sanitize timer for this batch from localStorage —
  // survives page reloads / accidental modal closes so the user doesn't lose
  // the countdown mid-soak.
  var savedTimer=null;
  try{
    var raw=localStorage.getItem('meadows_sanitizeTimer');
    if(raw){
      var parsed=JSON.parse(raw);
      // Only restore if it belongs to THIS batch AND hasn't fully elapsed >5min ago
      // (anything older than 5min past the 2min duration is stale).
      if(parsed&&parsed.batchId===batchId&&parsed.startedAt){
        var ageSec=(Date.now()-parsed.startedAt)/1000;
        if(ageSec<420){savedTimer=parsed;}else{localStorage.removeItem('meadows_sanitizeTimer');}
      }
    }
  }catch(e){}
  bottlingWorkflowState={
    batchId:batchId,
    stepIdx:0,
    preflight:{bottles:false,caps:false,sanitizer:false,siphon:false,wand:false,hydrometer:false},
    fg:initialFg,
    closure:initialClosure,
    abv:existing.abv||(b.og&&initialFg?parseFloat(calcABV(b.og,initialFg)):null),
    sanitizerStartedAt:savedTimer?savedTimer.startedAt:null,
    sanitizerCompleted:savedTimer?!!savedTimer.completed:false,
    counts:{500:c500,750:c750||6},  // default 6×750ml if fresh
    customSize:customSize,
    customQty:customQty,
    sweetness:existing.sweetness||'',
    notes:existing.notes||'',
    date:existing.date||today()
  };
  renderBottlingWorkflow();
}

// Helpers for the bottling sanitize timer's localStorage persistence. Public
// so the click-handler inline can call them.
function startSanitizeTimer(){
  var s=bottlingWorkflowState;
  s.sanitizerStartedAt=Date.now();
  s.sanitizerCompleted=false;
  try{localStorage.setItem('meadows_sanitizeTimer',JSON.stringify({batchId:s.batchId,startedAt:s.sanitizerStartedAt,completed:false}));}catch(e){}
  renderBottlingWorkflow();
}
function completeSanitizeTimer(){
  bottlingWorkflowState.sanitizerCompleted=true;
  try{localStorage.removeItem('meadows_sanitizeTimer');}catch(e){}
  renderBottlingWorkflow();
}
function resetSanitizeTimer(){
  bottlingWorkflowState.sanitizerStartedAt=null;
  bottlingWorkflowState.sanitizerCompleted=false;
  try{localStorage.removeItem('meadows_sanitizeTimer');}catch(e){}
  renderBottlingWorkflow();
}

function renderBottlingWorkflow(){
  closeModal();
  var s=bottlingWorkflowState;
  var b=APP.batches.find(function(x){return x.id===s.batchId;});
  if(!b)return;
  var step=BOTTLING_STEPS[s.stepIdx];
  // Stepper header
  var stepper=BOTTLING_STEPS.map(function(st,i){
    var done=i<s.stepIdx,active=i===s.stepIdx;
    return'<div style="display:flex;align-items:center;gap:6px;flex:1;opacity:'+(active?1:done?0.7:0.4)+'"><div style="width:24px;height:24px;border-radius:12px;background:'+(done?'var(--green2)':active?'var(--gold)':'var(--bg4)')+';color:'+(done||active?'#0a0a0b':'var(--text3)')+';display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:600;flex-shrink:0">'+(done?'✓':st.icon)+'</div><div style="font-family:var(--font-mono);font-size:10px;letter-spacing:1px;color:'+(active?'var(--gold2)':'var(--text3)')+'">'+st.title.toUpperCase()+'</div>'+(i<BOTTLING_STEPS.length-1?'<div style="flex:1;height:1px;background:var(--border)"></div>':'')+'</div>';
  }).join('');
  var content=renderBottlingStepContent(step.id,s,b);
  var canPrev=s.stepIdx>0;
  var canNext=canAdvanceBottlingStep(step.id,s);
  var isLast=s.stepIdx===BOTTLING_STEPS.length-1;
  document.body.insertAdjacentHTML('beforeend',
    '<div class="modal-overlay" onclick="if(event.target===this&&confirm(\'Cancel bottling workflow? Progress will be lost.\'))closeModal()"><div class="modal" style="max-width:640px;max-height:90vh;display:flex;flex-direction:column">'
    +'<div class="modal-title">🍾 GUIDED BOTTLING · '+escHtml(b.name)+'</div>'
    +'<div style="display:flex;gap:0;align-items:center;margin-bottom:18px">'+stepper+'</div>'
    +'<div style="flex:1;overflow-y:auto">'+content+'</div>'
    +'<div class="modal-actions" style="border-top:1px solid var(--border);padding-top:14px">'
    +(canPrev?'<button class="btn btn-secondary" onclick="bottlingPrevStep()">← Back</button>':'<span></span>')
    +'<button class="btn btn-secondary" onclick="if(confirm(\'Cancel bottling workflow?\'))closeModal()">Cancel</button>'
    +(isLast?'<button class="btn btn-primary" onclick="finishBottlingWorkflow()">✦ Complete Bottling</button>':'<button class="btn btn-primary" id="bw-next-btn" onclick="bottlingNextStep()" '+(canNext?'':'disabled style="opacity:0.4;cursor:not-allowed"')+'>Next →</button>')
    +'</div></div></div>');
}

function renderBottlingStepContent(stepId,s,b){
  if(stepId==='preflight'){
    var items=[
      {key:'bottles',label:'Bottles cleaned and dry',hint:'Match the count to ' +s.bottleCount+' or more'},
      {key:'caps',label:'Caps / corks ready',hint:'Crown caps, corks, or swing-tops — your choice'},
      {key:'sanitizer',label:'Sanitizer mixed ('+getSanitizer().name+')',hint:'~'+getSanitizer().mlPerL+' ml per litre water'},
      {key:'siphon',label:'Auto-siphon / racking cane',hint:'Clean and ready to deploy'},
      {key:'wand',label:'Bottling wand or filler',hint:'For controlled bottle filling'},
      {key:'hydrometer',label:'Hydrometer (for final gravity)',hint:'Take a final reading before bottling'}
    ];
    var rows=items.map(function(it){
      return'<label style="display:flex;align-items:flex-start;gap:10px;padding:8px 0;cursor:pointer;border-bottom:1px solid var(--border)">'
        +'<input type="checkbox" '+(s.preflight[it.key]?'checked':'')+' onchange="bottlingWorkflowState.preflight[\''+it.key+'\']=this.checked;renderBottlingWorkflow()" style="margin-top:3px;cursor:pointer;width:18px;height:18px">'
        +'<div><div style="font-size:14px;color:var(--text)">'+escHtml(it.label)+'</div><div style="font-size:11px;color:var(--text3);font-style:italic">'+escHtml(it.hint)+'</div></div>'
        +'</label>';
    }).join('');
    var allChecked=items.every(function(it){return s.preflight[it.key];});
    return'<div style="font-size:13px;color:var(--text2);margin-bottom:14px">Confirm everything is ready before you start. Bottling day rewards preparation — once the siphon is running, you don\'t want to be hunting for sanitizer.</div>'+rows
      +'<div style="margin-top:14px;padding:10px;background:'+(allChecked?'#0d1f12':'var(--bg4)')+';border-left:3px solid '+(allChecked?'var(--green)':'var(--gold)')+';border-radius:var(--radius);font-size:12px;color:'+(allChecked?'var(--green2)':'var(--text2)')+'">'
      +(allChecked?'✓ All ready. Click Next to continue.':'Complete the checklist to proceed.')
      +'</div>';
  }
  if(stepId==='fg'){
    var ogText=b.og?b.og.toFixed(3):'—';
    var lastLog=(APP.logs[b.id]&&APP.logs[b.id].length)?APP.logs[b.id][APP.logs[b.id].length-1]:null;
    var calcedAbv=(b.og&&s.fg)?calcABV(b.og,s.fg):'—';
    return'<div style="font-size:13px;color:var(--text2);margin-bottom:14px">Take your final hydrometer reading. The batch should be at terminal gravity — no drop in 48-72 hours.</div>'
      +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius);padding:14px;margin-bottom:14px">'
      +'<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;text-align:center">'
      +'<div><div style="font-family:var(--font-display);font-size:20px;color:var(--blue2)">'+ogText+'</div><div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin-top:2px">ORIGINAL</div></div>'
      +'<div><div id="bw-fg-val" style="font-family:var(--font-display);font-size:20px;color:var(--gold2)">'+(s.fg?s.fg.toFixed(3):'—')+'</div><div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin-top:2px">FINAL</div></div>'
      +'<div><div id="bw-abv-val" style="font-family:var(--font-display);font-size:20px;color:var(--green2)">'+calcedAbv+'%</div><div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin-top:2px">ABV</div></div>'
      +'</div></div>'
      +(lastLog?'<div style="font-size:12px;color:var(--text3);margin-bottom:10px;font-style:italic">Last logged gravity: '+lastLog.gravity+' on '+fmtDate(lastLog.date)+(daysSince(lastLog.date)<3?' — fresh, good to use':' — consider taking a new reading')+'</div>':'')
      +'<div class="form-row"><div class="form-group"><label class="form-label">Final Gravity</label><input class="form-input" type="number" step="0.001" id="bw-fg-input" value="'+(s.fg||'')+'" oninput="updateBwFG(this.value)"></div>'
      +'<div class="form-group"><label class="form-label">Manual ABV Override (optional)</label><input class="form-input" type="number" step="0.1" id="bw-abv-input" value="'+(s.abv||'')+'" oninput="updateBwAbvOverride(this.value)"></div></div>';
  }
  if(stepId==='sanitize'){
    var elapsed=s.sanitizerStartedAt?Math.floor((Date.now()-s.sanitizerStartedAt)/1000):0;
    var duration=120; // 2 minutes
    var remaining=Math.max(0,duration-elapsed);
    var mm=Math.floor(remaining/60),ss=remaining%60;
    var progress=Math.min(100,(elapsed/duration)*100);
    var running=s.sanitizerStartedAt&&!s.sanitizerCompleted&&remaining>0;
    if(running){
      // Schedule a re-render
      setTimeout(function(){if(bottlingWorkflowState.sanitizerStartedAt===s.sanitizerStartedAt&&!bottlingWorkflowState.sanitizerCompleted)renderBottlingWorkflow();},1000);
    }
    if(remaining===0&&s.sanitizerStartedAt&&!s.sanitizerCompleted){
      bottlingWorkflowState.sanitizerCompleted=true;
      try{localStorage.removeItem('meadows_sanitizeTimer');}catch(e){}
    }
    return'<div style="font-size:13px;color:var(--text2);margin-bottom:14px">Sanitize all bottles, caps, siphon, and wand. StarSan needs ~30 seconds of contact time, but 2 minutes covers all surfaces with margin.</div>'
      +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius2);padding:24px;text-align:center;margin-bottom:14px">'
      +'<div style="font-family:var(--font-display);font-size:56px;color:'+(s.sanitizerCompleted?'var(--green2)':running?'var(--gold2)':'var(--text3)')+';line-height:1">'+(s.sanitizerCompleted?'DONE':((mm<10?'0':'')+mm+':'+(ss<10?'0':'')+ss))+'</div>'
      +'<div style="font-family:var(--font-mono);font-size:11px;color:var(--text3);letter-spacing:2px;margin-top:8px">'+(s.sanitizerCompleted?'✓ SANITIZATION COMPLETE':running?'SANITIZING — KEEP IN CONTACT':'2-MINUTE TIMER')+'</div>'
      +(running||s.sanitizerCompleted?'<div style="margin-top:14px;height:6px;background:var(--bg4);border-radius:3px;overflow:hidden"><div style="height:100%;width:'+progress+'%;background:linear-gradient(90deg,var(--gold),var(--green2));transition:width 1s linear"></div></div>':'')
      +'</div>'
      +(!s.sanitizerStartedAt?'<button class="btn btn-primary" style="width:100%" onclick="startSanitizeTimer()">▶ Start 2-Minute Timer</button>':'')
      +(running?'<button class="btn btn-secondary" style="width:100%" onclick="completeSanitizeTimer()">Skip — Already Done</button>':'')
      +(s.sanitizerCompleted?'<div style="padding:10px;background:#0d1f12;border-left:3px solid var(--green);border-radius:var(--radius);font-size:12px;color:var(--green2);margin-bottom:8px">✓ Sanitization complete. Drain bottles and proceed to filling.</div><button class="btn btn-secondary btn-sm" onclick="resetSanitizeTimer()">↻ Reset Timer</button>':'');
  }
  if(stepId==='fill'){
    var totalBot=s.counts[500]+s.counts[750]+(s.customSize>0?s.customQty:0);
    var totalMl=s.counts[500]*500+s.counts[750]*750+(s.customSize>0?s.customQty*s.customSize:0);
    return'<div style="font-size:13px;color:var(--text2);margin-bottom:14px">Siphon into your sanitized bottles. Fill to the bottom of the bottle neck (~25mm headspace). Cap or cork immediately. Wipe drips before they become sticky regrets.</div>'
      +'<div class="form-group"><label class="form-label">Bottling Date</label><input class="form-input" type="date" id="bw-date" value="'+s.date+'" onchange="bottlingWorkflowState.date=this.value"></div>'
      +'<div style="margin:8px 0 4px;font-family:var(--font-mono);font-size:11px;color:var(--text3);letter-spacing:1.5px;text-transform:uppercase">BOTTLE COUNTS BY SIZE</div>'
      +'<div class="form-row"><div class="form-group"><label class="form-label">🍶 500 ml bottles</label><input class="form-input" type="number" min="0" id="bw-count-500" value="'+(s.counts[500]||'')+'" oninput="updateBwFillCount()"></div>'
      +'<div class="form-group"><label class="form-label">🍷 750 ml bottles</label><input class="form-input" type="number" min="0" id="bw-count-750" value="'+(s.counts[750]||'')+'" oninput="updateBwFillCount()"></div></div>'
      +'<details style="margin-bottom:10px"'+(s.customSize>0||s.customQty>0?' open':'')+'><summary style="cursor:pointer;font-size:12px;color:var(--text3);padding:4px 0">+ Custom bottle size</summary>'
      +'<div class="form-row" style="margin-top:6px"><div class="form-group"><label class="form-label">Custom size (ml)</label><input class="form-input" type="number" min="100" id="bw-custom-size" value="'+(s.customSize||'')+'" oninput="updateBwFillCount()"></div>'
      +'<div class="form-group"><label class="form-label">Quantity</label><input class="form-input" type="number" min="0" id="bw-custom-qty" value="'+(s.customQty||'')+'" oninput="updateBwFillCount()"></div></div>'
      +'</details>'
      +'<div id="bw-total-info" style="padding:10px 12px;background:var(--bg4);border-left:3px solid var(--gold);border-radius:var(--radius);margin-bottom:10px;font-family:var(--font-mono);font-size:13px;color:var(--gold2);'+(totalBot>0?'':'display:none')+'">TOTAL: '+totalBot+' bottle'+(totalBot!==1?'s':'')+' · '+(totalMl/1000).toFixed(2)+' L</div>'
      +'<div class="form-group"><label class="form-label">Final Sweetness Profile</label><select class="form-select" id="bw-sweetness" onchange="bottlingWorkflowState.sweetness=this.value">'
      +['','Bone Dry','Dry','Off-Dry','Semi-Sweet','Sweet','Dessert'].map(function(o){return'<option value="'+o+'"'+(s.sweetness===o?' selected':'')+'>'+(o||'(set after tasting)')+'</option>';}).join('')
      +'</select></div>'
      +'<div class="form-group"><label class="form-label">Closure</label><select class="form-select" id="bw-closure" onchange="bottlingWorkflowState.closure=this.value">'
      +'<option value="crown"'+((s.closure||'crown')!=='cork'?' selected':'')+'>⭕ Crown caps</option>'
      +'<option value="cork"'+(s.closure==='cork'?' selected':'')+'>🪵 Corks</option>'
      +'</select><div style="font-size:11px;color:var(--text3);margin-top:4px">Bottles and closures are deducted from Supplies (when tracked) and priced into the batch cost breakdown.</div></div>'
      +'<div class="form-group"><label class="form-label">Bottling Notes (optional)</label><textarea class="form-textarea" id="bw-notes" oninput="bottlingWorkflowState.notes=this.value" placeholder="Bottle type used, cap/cork, anything unusual…">'+escHtml(s.notes)+'</textarea></div>'
      +'<div id="bw-cellar-info" style="padding:10px;background:var(--bg4);border-left:3px solid var(--gold);border-radius:var(--radius);font-size:12px;color:var(--text2);margin-top:8px;'+(totalBot>0?'':'display:none')+'">All '+totalBot+' bottle'+(totalBot!==1?'s':'')+' will land in the cellar by default. You can split into fridge/gifted/other from the Cellar view later.</div>';
  }
  if(stepId==='label'){
    var recipe=APP.recipes.find(function(r){return r.id===b.recipeId;});
    var abvForLabel=s.abv||(b.og&&s.fg?parseFloat(calcABV(b.og,s.fg)):null);
    return'<div style="font-size:13px;color:var(--text2);margin-bottom:14px">Your label is ready. Save as PNG, print directly, or skip if you\'ll label later. The ABV is baked into the hexagon — no separate sticker needed.</div>'
      +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius2);padding:14px;margin-bottom:14px;text-align:center">'
      +renderLabelWithABV(recipe?recipe.id:'r1',abvForLabel||0,{batch:b})
      +'</div>'
      +'<div style="display:flex;gap:8px;justify-content:center;flex-wrap:wrap">'
      +'<button class="btn btn-secondary" onclick="(function(){var tempBot={abv:'+(abvForLabel||0)+'};APP.bottling[\''+b.id+'\']=Object.assign({},APP.bottling[\''+b.id+'\']||{},tempBot);downloadLabel(\''+b.id+'\');}())">⬇ Save PNG</button>'
      +'<button class="btn btn-secondary" onclick="(function(){var tempBot={abv:'+(abvForLabel||0)+'};APP.bottling[\''+b.id+'\']=Object.assign({},APP.bottling[\''+b.id+'\']||{},tempBot);printLabel(\''+b.id+'\');}())">🖨 Print</button>'
      +'<button class="btn btn-secondary" onclick="bottlingNextStep()">Skip for Now</button>'
      +'</div>';
  }
  if(stepId==='finish'){
    var recipe=APP.recipes.find(function(r){return r.id===b.recipeId;});
    var totalBot=s.counts[500]+s.counts[750]+(s.customSize>0?s.customQty:0);
    var totalMl=s.counts[500]*500+s.counts[750]*750+(s.customSize>0?s.customQty*s.customSize:0);
    var sizeParts=[];
    if(s.counts[500]>0)sizeParts.push(s.counts[500]+' × 500ml');
    if(s.counts[750]>0)sizeParts.push(s.counts[750]+' × 750ml');
    if(s.customSize>0&&s.customQty>0)sizeParts.push(s.customQty+' × '+s.customSize+'ml');
    return'<div style="font-size:13px;color:var(--text2);margin-bottom:14px">Review your bottling record. Clicking <strong>Complete Bottling</strong> saves everything, puts all '+totalBot+' bottle'+(totalBot!==1?'s':'')+' in the cellar, and marks the batch as bottled.</div>'
      +'<div style="background:var(--bg3);border:1px solid var(--border);border-radius:var(--radius2);padding:18px">'
      +'<div style="font-family:var(--font-display);font-size:18px;color:var(--gold2);margin-bottom:10px;letter-spacing:2px">'+escHtml(b.name)+'</div>'
      +'<table style="width:100%;font-size:13px">'
      +'<tr><td style="color:var(--text3);padding:4px 0">Style</td><td style="color:var(--text2)">'+escHtml(recipe?recipe.style:'Custom')+'</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">Bottling Date</td><td style="color:var(--text2)">'+fmtDate(s.date)+'</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">Original Gravity</td><td style="color:var(--text2);font-family:var(--font-mono)">'+(b.og||'—')+'</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">Final Gravity</td><td style="color:var(--text2);font-family:var(--font-mono)">'+(s.fg||'—')+'</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">ABV</td><td style="color:var(--green2);font-family:var(--font-mono)">'+(s.abv||(b.og&&s.fg?calcABV(b.og,s.fg):'—'))+'%</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">Bottles Filled</td><td style="color:var(--gold2);font-family:var(--font-display);font-size:16px">'+totalBot+'</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">Sizes</td><td style="color:var(--text2);font-size:12px">'+sizeParts.join(' + ')+'</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">Closure</td><td style="color:var(--text2)">'+((s.closure||'crown')==='cork'?'🪵 Corks':'⭕ Crown caps')+'</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">Total Volume</td><td style="color:var(--text2);font-family:var(--font-mono)">'+(totalMl/1000).toFixed(2)+' L</td></tr>'
      +'<tr><td style="color:var(--text3);padding:4px 0">Sweetness</td><td style="color:var(--text2)">'+(s.sweetness||'(unset)')+'</td></tr>'
      +'</table>'
      +(s.notes?'<div style="margin-top:10px;padding-top:10px;border-top:1px solid var(--border);font-size:12px;color:var(--text2);font-style:italic">'+escHtml(s.notes)+'</div>':'')
      +'</div>';
  }
  return'';
}

function canAdvanceBottlingStep(stepId,s){
  if(stepId==='preflight')return Object.keys(s.preflight).every(function(k){return s.preflight[k];});
  if(stepId==='fg')return s.fg!=null&&s.fg>=0.98&&s.fg<=1.2;
  if(stepId==='sanitize')return s.sanitizerCompleted;
  if(stepId==='fill'){
    var totalBot=s.counts[500]+s.counts[750]+(s.customSize>0?s.customQty:0);
    return totalBot>0;
  }
  if(stepId==='label')return true;
  return true;
}

// Targeted UI updates that DON'T re-render the modal (preserves input focus while typing).
function updateBwNextButton(){
  var btn=document.getElementById('bw-next-btn');
  if(!btn)return;
  var step=BOTTLING_STEPS[bottlingWorkflowState.stepIdx];
  var ok=canAdvanceBottlingStep(step.id,bottlingWorkflowState);
  if(ok){btn.removeAttribute('disabled');btn.style.opacity='1';btn.style.cursor='pointer';}
  else{btn.setAttribute('disabled','disabled');btn.style.opacity='0.4';btn.style.cursor='not-allowed';}
}

function updateBwFG(val){
  var s=bottlingWorkflowState;
  var b=APP.batches.find(function(x){return x.id===s.batchId;});
  s.fg=parseFloat(val);if(isNaN(s.fg))s.fg=null;
  s.abv=(b&&b.og&&s.fg)?parseFloat(calcABV(b.og,s.fg)):null;
  var fgEl=document.getElementById('bw-fg-val');
  var abvEl=document.getElementById('bw-abv-val');
  if(fgEl)fgEl.textContent=s.fg?s.fg.toFixed(3):'—';
  if(abvEl)abvEl.textContent=(s.abv!=null?s.abv.toFixed(1):'—')+'%';
  updateBwNextButton();
}

function updateBwAbvOverride(val){
  var s=bottlingWorkflowState;
  var v=parseFloat(val);
  if(!isNaN(v))s.abv=v;
  else{
    var b=APP.batches.find(function(x){return x.id===s.batchId;});
    s.abv=(b&&b.og&&s.fg)?parseFloat(calcABV(b.og,s.fg)):null;
  }
  var abvEl=document.getElementById('bw-abv-val');
  if(abvEl)abvEl.textContent=(s.abv!=null?s.abv.toFixed(1):'—')+'%';
}

function updateBwFillCount(){
  var s=bottlingWorkflowState;
  var i500=document.getElementById('bw-count-500');
  var i750=document.getElementById('bw-count-750');
  var ics=document.getElementById('bw-custom-size');
  var icq=document.getElementById('bw-custom-qty');
  s.counts[500]=i500?(parseInt(i500.value)||0):0;
  s.counts[750]=i750?(parseInt(i750.value)||0):0;
  s.customSize=ics?(parseInt(ics.value)||0):0;
  s.customQty=icq?(parseInt(icq.value)||0):0;
  var totalBot=s.counts[500]+s.counts[750]+(s.customSize>0?s.customQty:0);
  var totalMl=s.counts[500]*500+s.counts[750]*750+(s.customSize>0?s.customQty*s.customSize:0);
  var totalEl=document.getElementById('bw-total-info');
  var cellarEl=document.getElementById('bw-cellar-info');
  if(totalEl){
    if(totalBot>0){totalEl.style.display='';totalEl.textContent='TOTAL: '+totalBot+' bottle'+(totalBot!==1?'s':'')+' · '+(totalMl/1000).toFixed(2)+' L';}
    else{totalEl.style.display='none';}
  }
  if(cellarEl){
    if(totalBot>0){cellarEl.style.display='';cellarEl.textContent='All '+totalBot+' bottle'+(totalBot!==1?'s':'')+' will land in the cellar by default. You can split into fridge/gifted/other from the Cellar view later.';}
    else{cellarEl.style.display='none';}
  }
  updateBwNextButton();
}

function bottlingNextStep(){
  if(bottlingWorkflowState.stepIdx<BOTTLING_STEPS.length-1){
    bottlingWorkflowState.stepIdx++;
    renderBottlingWorkflow();
  }
}

function bottlingPrevStep(){
  if(bottlingWorkflowState.stepIdx>0){
    bottlingWorkflowState.stepIdx--;
    renderBottlingWorkflow();
  }
}

// Deduct bottles (per size) and closures from tracked supplies, returning a
// cost breakdown for the batch economics card. Untracked items are listed
// with zero cost — packaging stock-keeping is optional.
function consumePackagingSupplies(countsBySize,totalBottles,closure){
  var items=[];var cost=0;
  function take(typeKey,qty,label){
    if(qty<=0)return;
    var sup=(APP.supplies||[]).find(function(x){return x.type===typeKey;});
    var price=sup?(parseFloat(sup.pricePerUnit)||0):0;
    if(sup){
      var have=parseFloat(sup.qty)||0;
      sup.qty=Math.max(0,have-qty);
      if(have<qty)toast('⚠ Supplies: only '+have+' '+label+' tracked — stock set to 0');
    }
    items.push({label:label,qty:qty,cost:Math.round(price*qty*100)/100,tracked:!!sup});
    cost+=price*qty;
  }
  Object.keys(countsBySize||{}).forEach(function(size){
    var n=parseInt(countsBySize[size])||0;
    var sz=parseInt(size);
    if(sz===750)take('bottle750',n,'750 ml bottles');
    else if(sz===500)take('bottle500',n,'500 ml bottles');
    else if(n>0)items.push({label:sz+' ml bottles',qty:n,cost:0,tracked:false});
  });
  take(closure==='cork'?'cork':'crowncap',totalBottles,closure==='cork'?'corks':'crown caps');
  return{items:items,cost:Math.round(cost*100)/100};
}

function finishBottlingWorkflow(){
  var s=bottlingWorkflowState;
  var b=APP.batches.find(function(x){return x.id===s.batchId;});
  // Build size counts map
  var countsAtBottling={};
  if(s.counts[500]>0)countsAtBottling[500]=s.counts[500];
  if(s.counts[750]>0)countsAtBottling[750]=s.counts[750];
  if(s.customSize>0&&s.customQty>0)countsAtBottling[s.customSize]=s.customQty;
  var total=Object.keys(countsAtBottling).reduce(function(s2,k){return s2+countsAtBottling[k];},0);
  // Packaging: deduct bottles + closures from supplies and price them.
  var packaging=consumePackagingSupplies(countsAtBottling,total,s.closure||'crown');
  // Locations: everything in cellar at first
  var locations={cellar:{},fridge:{},gifted:{},other:{}};
  Object.keys(countsAtBottling).forEach(function(size){
    locations.cellar[parseInt(size)]=countsAtBottling[size];
  });
  // Commit
  var existing=APP.bottling[s.batchId]||{};
  APP.bottling[s.batchId]={
    date:s.date||today(),
    bottleCount:total,
    bottlesAtBottling:total,
    countsAtBottling:countsAtBottling,
    bottleSizes:Object.keys(countsAtBottling).map(function(k){return parseInt(k);}).sort(function(a,c){return a-c;}),
    locations:locations,
    fg:s.fg,
    abv:s.abv||(b&&b.og&&s.fg?parseFloat(calcABV(b.og,s.fg)):null),
    sweetness:s.sweetness,
    notes:s.notes,
    closure:s.closure||'crown',
    packaging:packaging,
    gifts:existing.gifts||[]
  };
  closeModal();
  scheduleSave();
  toast('✦ Bottling complete · '+total+' bottle'+(total!==1?'s':'')+' in the cellar'+(packaging.cost>0?' · '+(APP.settings.currency||'€')+packaging.cost.toFixed(2)+' packaging':''));
  showView('cellar');
}

// ==================== LABEL DESIGNER (Phase 2) ====================
// Modal UI for customizing the per-recipe overlay layout. Two columns:
// a live label preview on the left, element controls on the right. Changes
// flow through window._designerState (working copy) into the preview in
// real time; nothing hits APP.settings until the user clicks Save.

// Friendly font choices surfaced in the picker. Match the keys to the
// overlayFontStack() map so the rendered output uses the right CSS stack.
var DESIGNER_FONTS=['Cinzel','Georgia','Crimson Pro','JetBrains Mono','serif','sans','mono'];

// Element tabs — order matters for UI flow (top-down on a label).
var DESIGNER_ELEMENTS=[
  {key:'style',    label:'Recipe Style',    text:true,  desc:'Top caps line (e.g. "BOCHET")'},
  {key:'name',     label:'Recipe Name',     text:true,  desc:'Italic title (e.g. "Caramelized Honey Mead")'},
  {key:'batchName',label:'Batch Name',      text:true,  desc:'Your batch name in the cream band'},
  {key:'abv',      label:'ABV',             text:true,  desc:'Alcohol percentage'},
  {key:'qr',       label:'QR Code',         text:false, desc:'Scannable share-link QR'},
  {key:'bestDrink',label:'Best-Drink Box',  text:false, desc:'Drinking-window date card'}
];

// Public entry: open the designer for the given recipe.
function openLabelDesigner(recipeId){
  var recipe=(APP.recipes||[]).find(function(r){return r.id===recipeId;});
  if(!recipe){toast('⚠ Recipe not found');return;}
  // Snapshot the current overlay config into a working state — Save commits,
  // Cancel discards.
  window._designerState={
    recipeId:recipeId,
    workingOverlays:JSON.parse(JSON.stringify(getRecipeOverlays(recipeId))),
    selectedElement:'batchName'
  };
  document.body.insertAdjacentHTML('beforeend',renderLabelDesignerModal());
}

// Render the entire designer modal. Called once on open + whenever a control
// change requires re-rendering the right column (element switch, etc.).
function renderLabelDesignerModal(){
  var s=window._designerState;
  var recipe=(APP.recipes||[]).find(function(r){return r.id===s.recipeId;});
  var color=recipe.brandColor||'#c9a350';
  var preview=renderDesignerPreview();
  var tabs=DESIGNER_ELEMENTS.map(function(el){
    var active=s.selectedElement===el.key;
    var cfg=s.workingOverlays[el.key];
    var dotColor=cfg.show?color:'var(--text3)';
    return'<button onclick="selectDesignerElement(\''+el.key+'\')" class="designer-tab'+(active?' active':'')+'" '
      +'style="display:flex;align-items:center;gap:8px;padding:8px 12px;border:1px solid '+(active?color:'var(--border)')+';'
      +'background:'+(active?'rgba(201,163,80,0.08)':'transparent')+';color:var(--text);'
      +'border-radius:4px;cursor:pointer;font-family:var(--font-mono);font-size:11px;'
      +'letter-spacing:0.5px;text-align:left;width:100%;margin-bottom:4px">'
      +'<span style="display:inline-block;width:6px;height:6px;border-radius:50%;background:'+dotColor+'"></span>'
      +'<span style="flex:1">'+escHtml(el.label)+'</span>'
      +(cfg.show?'':'<span style="font-size:9px;color:var(--text3);font-style:italic">hidden</span>')
      +'</button>';
  }).join('');
  var controls=renderDesignerControls();
  // Flex column with a pinned header + footer and a scrolling middle — if the
  // whole modal scrolls instead, the Save/Cancel footer ends up clipped below
  // the 92vh cutoff on short viewports (e.g. inside an HA iframe) where the
  // overlay scrollbar is invisible, making Save effectively unclickable.
  return'<div class="modal-overlay" id="designer-overlay" onclick="if(event.target===this)closeLabelDesigner()">'
    +'<div class="modal" style="max-width:980px;width:96vw;background:var(--bg2);border:1px solid '+color+';max-height:92vh;display:flex;flex-direction:column">'
    +'<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:6px;padding-bottom:10px;border-bottom:1px solid var(--border)">'
    +'<div class="modal-title" style="color:'+color+';margin:0">🎨 LABEL DESIGNER</div>'
    +'<div style="font-family:var(--font-display);font-size:14px;color:var(--text2);font-style:italic">'+escHtml(recipe.name)+'</div>'
    +'</div>'
    +'<div style="flex:1;overflow-y:auto;min-height:0;padding-right:4px">'
    +'<div style="display:grid;grid-template-columns:340px 1fr;gap:24px;align-items:start;margin-top:14px">'
    // Left: preview + background image picker
    +'<div>'
    +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin-bottom:8px">LIVE PREVIEW</div>'
    +'<div id="designer-preview" style="border-radius:6px;overflow:hidden">'+preview+'</div>'
    +'<div style="font-size:11px;color:var(--text3);font-style:italic;margin-top:8px;text-align:center">Sample batch "Demo Mead" at 11.5% ABV</div>'
    +renderDesignerBackgroundCard()
    +'</div>'
    // Right: tabs + controls
    +'<div>'
    +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin-bottom:8px">OVERLAY ELEMENTS</div>'
    +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:14px">'+tabs+'</div>'
    +'<div id="designer-controls">'+controls+'</div>'
    +'</div>'
    +'</div>'
    +'</div>'
    // Footer — pinned below the scroll area so Save/Cancel are always visible
    +'<div style="display:flex;gap:8px;margin-top:14px;padding-top:14px;border-top:1px solid var(--border);flex-shrink:0">'
    +'<button class="btn btn-danger btn-sm" onclick="resetDesignerOverlays()" title="Discard all customizations for this recipe">↺ Reset to defaults</button>'
    +'<button class="btn btn-secondary btn-sm" onclick="applyDesignerToAll()" title="Use this layout for every recipe">≡ Apply to all recipes</button>'
    +'<div style="flex:1"></div>'
    +'<button class="btn btn-secondary" onclick="closeLabelDesigner()">Cancel</button>'
    +'<button class="btn btn-primary" onclick="saveDesignerOverlays()">Save</button>'
    +'</div>'
    +'</div></div>';
}

// Render the live label preview with current working overlays.
function renderDesignerPreview(){
  var s=window._designerState;
  var recipe=(APP.recipes||[]).find(function(r){return r.id===s.recipeId;});
  // Build a sample batch object so users can see the batchName/ABV slots in action
  var sampleBatch={id:'__designer-sample',name:'Demo Mead',recipeId:s.recipeId,startDate:'2025-06-01'};
  // Provide a fake bottling so best-drink box renders
  var origBot=APP.bottling[sampleBatch.id];
  APP.bottling[sampleBatch.id]={date:'2025-06-01',fg:1.010,abv:11.5};
  var html=renderLabelWithABV(s.recipeId,'11.5',{batch:sampleBatch,qr:true,overlays:s.workingOverlays});
  // Tidy up
  if(origBot===undefined)delete APP.bottling[sampleBatch.id];
  else APP.bottling[sampleBatch.id]=origBot;
  return html;
}

// Render the control panel for the currently selected element.
function renderDesignerControls(){
  var s=window._designerState;
  var elKey=s.selectedElement;
  var el=DESIGNER_ELEMENTS.find(function(e){return e.key===elKey;});
  var cfg=s.workingOverlays[elKey];
  var recipe=(APP.recipes||[]).find(function(r){return r.id===s.recipeId;});
  var color=recipe.brandColor||'#c9a350';
  // Show/hide toggle
  var showToggle='<label style="display:flex;align-items:center;gap:8px;cursor:pointer;padding:8px 12px;background:var(--bg);border-radius:4px;margin-bottom:14px">'
    +'<input type="checkbox" '+(cfg.show?'checked':'')+' onchange="updateDesigner(\''+elKey+'\',\'show\',this.checked)" style="width:16px;height:16px;cursor:pointer;accent-color:'+color+'">'
    +'<span style="flex:1;font-size:13px;color:var(--text);font-weight:600">'+escHtml(el.label)+(cfg.show?'':' <span style="color:var(--text3);font-style:italic;font-weight:400">(hidden)</span>')+'</span>'
    +'<span style="font-size:11px;color:var(--text3);font-style:italic">'+escHtml(el.desc)+'</span>'
    +'</label>';
  // Position section: 9-grid + sliders
  var gridButtons='';
  ['T','M','B'].forEach(function(row){
    ['L','C','R'].forEach(function(col){
      var key=row+col;
      var gp=OVERLAY_GRID[key];
      var matches=Math.abs(cfg.x-gp.x)<2&&Math.abs(cfg.y-gp.y)<2;
      gridButtons+='<button onclick="snapDesigner(\''+elKey+'\',\''+key+'\')" '
        +'style="aspect-ratio:1;background:'+(matches?color:'var(--bg)')+';color:'+(matches?'#000':'var(--text2)')+';'
        +'border:1px solid '+(matches?color:'var(--border)')+';border-radius:3px;cursor:pointer;'
        +'font-family:var(--font-mono);font-size:10px;letter-spacing:0.5px" '
        +'title="'+key+' — '+gp.x+'%, '+gp.y+'%">'+key+'</button>';
    });
  });
  var positionSection='<div style="margin-bottom:14px;padding:12px;background:var(--bg);border-radius:4px;border:1px solid var(--border)">'
    +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px;margin-bottom:8px">POSITION</div>'
    +'<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:4px;max-width:180px;margin-bottom:12px">'+gridButtons+'</div>'
    +'<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px">'
    +'<div style="font-family:var(--font-mono);font-size:11px;color:var(--text3);width:18px">X</div>'
    +'<input type="range" min="0" max="100" step="0.5" value="'+cfg.x+'" oninput="liveSliderPct(this,\''+elKey+'\',\'x\')" onchange="refreshDesigner()" style="flex:1;accent-color:'+color+'">'
    +'<div id="rd-x-'+elKey+'" style="font-family:var(--font-mono);font-size:11px;color:var(--text);width:44px;text-align:right">'+cfg.x.toFixed(1)+'%</div>'
    +'</div>'
    +'<div style="display:flex;align-items:center;gap:10px">'
    +'<div style="font-family:var(--font-mono);font-size:11px;color:var(--text3);width:18px">Y</div>'
    +'<input type="range" min="0" max="100" step="0.5" value="'+cfg.y+'" oninput="liveSliderPct(this,\''+elKey+'\',\'y\')" onchange="refreshDesigner()" style="flex:1;accent-color:'+color+'">'
    +'<div id="rd-y-'+elKey+'" style="font-family:var(--font-mono);font-size:11px;color:var(--text);width:44px;text-align:right">'+cfg.y.toFixed(1)+'%</div>'
    +'</div>'
    +'</div>';
  // Typography section (text elements only)
  var typoSection='';
  if(el.text){
    var fontOpts=DESIGNER_FONTS.map(function(f){
      return'<option value="'+f+'"'+(cfg.font===f?' selected':'')+'>'+f+'</option>';
    }).join('');
    typoSection='<div style="margin-bottom:14px;padding:12px;background:var(--bg);border-radius:4px;border:1px solid var(--border)">'
      +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px;margin-bottom:10px">TYPOGRAPHY</div>'
      // Font + size on one row
      +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">'
      +'<div>'
      +'<label style="font-family:var(--font-mono);font-size:9.5px;color:var(--text3);letter-spacing:0.5px;display:block;margin-bottom:4px">FONT</label>'
      +'<select onchange="updateDesigner(\''+elKey+'\',\'font\',this.value)" class="form-input" style="font-size:12px;padding:5px 8px">'+fontOpts+'</select>'
      +'</div>'
      +'<div>'
      +'<label style="font-family:var(--font-mono);font-size:9.5px;color:var(--text3);letter-spacing:0.5px;display:block;margin-bottom:4px">SIZE · <span id="rd-size-'+elKey+'">'+cfg.size+'px</span></label>'
      +'<input type="range" min="8" max="80" step="1" value="'+cfg.size+'" oninput="liveSliderInt(this,\''+elKey+'\',\'size\')" onchange="refreshDesigner()" style="width:100%;accent-color:'+color+'">'
      +'</div>'
      +'</div>'
      // Color + weight + italic on one row
      +'<div style="display:grid;grid-template-columns:90px 1fr 1fr;gap:10px;margin-bottom:10px;align-items:end">'
      +'<div>'
      +'<label style="font-family:var(--font-mono);font-size:9.5px;color:var(--text3);letter-spacing:0.5px;display:block;margin-bottom:4px">COLOR</label>'
      +'<input type="color" value="'+cfg.color+'" oninput="liveColor(this,\''+elKey+'\',\'color\')" onchange="refreshDesigner()" style="width:100%;height:30px;border:1px solid var(--border);border-radius:3px;cursor:pointer;background:transparent">'
      +'</div>'
      +'<div>'
      +'<label style="font-family:var(--font-mono);font-size:9.5px;color:var(--text3);letter-spacing:0.5px;display:block;margin-bottom:4px">WEIGHT</label>'
      +'<button onclick="updateDesigner(\''+elKey+'\',\'weight\','+(cfg.weight>=600?400:700)+')" '
      +'style="width:100%;padding:6px 8px;background:'+(cfg.weight>=600?color:'var(--bg2)')+';color:'+(cfg.weight>=600?'#000':'var(--text)')+';'
      +'border:1px solid '+(cfg.weight>=600?color:'var(--border)')+';border-radius:3px;cursor:pointer;'
      +'font-family:var(--font);font-size:13px;font-weight:700">'+(cfg.weight>=600?'Bold':'Regular')+'</button>'
      +'</div>'
      +'<div>'
      +'<label style="font-family:var(--font-mono);font-size:9.5px;color:var(--text3);letter-spacing:0.5px;display:block;margin-bottom:4px">STYLE</label>'
      +'<button onclick="updateDesigner(\''+elKey+'\',\'italic\','+(!cfg.italic)+')" '
      +'style="width:100%;padding:6px 8px;background:'+(cfg.italic?color:'var(--bg2)')+';color:'+(cfg.italic?'#000':'var(--text)')+';'
      +'border:1px solid '+(cfg.italic?color:'var(--border)')+';border-radius:3px;cursor:pointer;'
      +'font-family:var(--font);font-size:13px;font-style:italic">Italic</button>'
      +'</div>'
      +'</div>'
      // Letter spacing
      +'<div style="display:flex;align-items:center;gap:10px">'
      +'<div style="font-family:var(--font-mono);font-size:9.5px;color:var(--text3);letter-spacing:0.5px;min-width:90px">LETTER SPACING</div>'
      +'<input type="range" min="0" max="20" step="0.5" value="'+(cfg.spacing||0)+'" oninput="liveSliderFloat(this,\''+elKey+'\',\'spacing\')" onchange="refreshDesigner()" style="flex:1;accent-color:'+color+'">'
      +'<div id="rd-spacing-'+elKey+'" style="font-family:var(--font-mono);font-size:11px;color:var(--text);min-width:32px;text-align:right">'+(cfg.spacing||0).toFixed(1)+'</div>'
      +'</div>'
      +'</div>';
  }else{
    // QR / Best-Drink — card theme picker. Position controls above already
    // move the card; theme controls how the backing card looks.
    var themeOpts=[
      {key:'light',label:'Light',swatch:'#faf3e0'},
      {key:'dark',label:'Dark',swatch:'#1a1208'},
      {key:'transparent',label:'None',swatch:'transparent'}
    ];
    var themeBtns=themeOpts.map(function(t){
      var active=(cfg.theme||'light')===t.key;
      var swatchStyle=t.key==='transparent'
        ?'background:repeating-conic-gradient(#444 0% 25%,#777 0% 50%) 50% / 8px 8px;'
        :'background:'+t.swatch+';';
      return'<button onclick="updateDesigner(\''+elKey+'\',\'theme\',\''+t.key+'\')" '
        +'style="display:flex;flex-direction:column;align-items:center;gap:4px;padding:8px 6px;'
        +'background:'+(active?'rgba(201,163,80,0.1)':'var(--bg2)')+';'
        +'border:1px solid '+(active?color:'var(--border)')+';border-radius:3px;cursor:pointer;color:var(--text);'
        +'font-family:var(--font);font-size:11px">'
        +'<div style="width:30px;height:18px;border-radius:3px;border:1px solid var(--border);'+swatchStyle+'"></div>'
        +'<span>'+escHtml(t.label)+'</span>'
        +'</button>';
    }).join('');
    typoSection='<div style="margin-bottom:14px;padding:12px;background:var(--bg);border-radius:4px;border:1px solid var(--border)">'
      +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px;margin-bottom:10px">CARD THEME</div>'
      +'<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px">'+themeBtns+'</div>'
      +'<div style="font-size:11px;color:var(--text3);font-style:italic;margin-top:8px">'
      +(cfg.theme==='transparent'?'Transparent — only the contents render, no card behind.'
        :cfg.theme==='dark'?'Dark card — good for light/colorful label artwork.'
        :'Light card — the default, works on most labels.')
      +'</div>'
      +'</div>';
  }
  return showToggle+positionSection+typoSection;
}

// Snap an element to one of the 9-grid positions
function snapDesigner(elKey,gridKey){
  var s=window._designerState;
  var gp=OVERLAY_GRID[gridKey];
  s.workingOverlays[elKey].x=gp.x;
  s.workingOverlays[elKey].y=gp.y;
  refreshDesigner();
}

// Update a single field on the working state and refresh
function updateDesigner(elKey,field,value){
  var s=window._designerState;
  s.workingOverlays[elKey][field]=value;
  refreshDesigner();
}

// ── Continuous-input fast path ──────────────────────────────────────────
// Sliders and the color picker fire input events many times per second while
// the user drags. The full refreshDesigner() rebuilds the modal's outerHTML
// which destroys the in-flight slider element — so dragging feels janky and
// the thumb resets. liveDesigner() updates the working state + preview ONLY,
// leaving the controls panel untouched. Discrete inputs (font dropdown,
// weight/italic toggles, grid snaps, theme picks, show/hide checkbox) still
// use updateDesigner() since their visual state changes the controls layout.
function liveDesigner(elKey,field,value){
  var s=window._designerState;
  if(!s)return;
  s.workingOverlays[elKey][field]=value;
  var preview=document.getElementById('designer-preview');
  if(preview)preview.innerHTML=renderDesignerPreview();
}

// Slider helpers — also update the inline readout in place
function liveSliderPct(input,elKey,field){
  var v=parseFloat(input.value);
  liveDesigner(elKey,field,v);
  var rd=document.getElementById('rd-'+field+'-'+elKey);
  if(rd)rd.textContent=v.toFixed(1)+'%';
}
function liveSliderInt(input,elKey,field){
  var v=parseInt(input.value,10);
  liveDesigner(elKey,field,v);
  var rd=document.getElementById('rd-'+field+'-'+elKey);
  if(rd)rd.textContent=v+'px';
}
function liveSliderFloat(input,elKey,field){
  var v=parseFloat(input.value);
  liveDesigner(elKey,field,v);
  var rd=document.getElementById('rd-'+field+'-'+elKey);
  if(rd)rd.textContent=v.toFixed(1);
}
function liveColor(input,elKey,field){
  liveDesigner(elKey,field,input.value);
}

// Switch the active element tab
function selectDesignerElement(elKey){
  window._designerState.selectedElement=elKey;
  refreshDesigner();
}

// Re-render the controls + preview in place. Cheaper than full modal rebuild
// since we don't touch the outer chrome / element tabs.
function refreshDesigner(){
  // Re-render the controls AND tabs (tabs reflect show/hide state)
  var overlay=document.getElementById('designer-overlay');
  if(!overlay)return;
  // Rebuild the whole modal — simpler than surgical updates and fast enough
  overlay.outerHTML=renderLabelDesignerModal();
}

// Persist working state to APP.settings.recipeOverlays and close.
// Only stores entries that DIFFER from the default to keep state lean.
function saveDesignerOverlays(){
  var s=window._designerState;
  if(!s){toast('⚠ Designer state lost — reopen the designer');return;}
  if(!APP.settings.recipeOverlays)APP.settings.recipeOverlays={};
  // Diff working state against defaults — only keep changed fields per element
  var diff={};
  ['style','name','batchName','abv','qr','bestDrink'].forEach(function(elKey){
    var working=s.workingOverlays[elKey]||{};
    var def=defaultOverlayFor(elKey,s.recipeId);
    var changed={};
    var hasChange=false;
    Object.keys(working).forEach(function(k){
      if(working[k]!==def[k]){changed[k]=working[k];hasChange=true;}
    });
    if(hasChange)diff[elKey]=changed;
  });
  if(Object.keys(diff).length){
    APP.settings.recipeOverlays[s.recipeId]=diff;
  }else{
    // No changes from default — remove any existing override
    delete APP.settings.recipeOverlays[s.recipeId];
  }
  scheduleSave();
  closeLabelDesigner();
  toast('✦ Label saved');
  renderMain();
}

function resetDesignerOverlays(){
  if(!confirm('Discard all customizations for this recipe and revert to defaults?'))return;
  var s=window._designerState;
  if(APP.settings.recipeOverlays&&APP.settings.recipeOverlays[s.recipeId]){
    delete APP.settings.recipeOverlays[s.recipeId];
  }
  // Persist immediately — the user confirmed a destructive action and would
  // be surprised if a tab reload brought the old overrides back.
  scheduleSave();
  // Reload working state from defaults
  s.workingOverlays=JSON.parse(JSON.stringify(getRecipeOverlays(s.recipeId)));
  refreshDesigner();
  toast('↺ Reset to defaults');
}

function applyDesignerToAll(){
  if(!confirm('Apply this layout to every recipe? Existing per-recipe customizations will be replaced.'))return;
  var s=window._designerState;
  if(!APP.settings.recipeOverlays)APP.settings.recipeOverlays={};
  // Build a diff against PER-RECIPE defaults (since photographic vs generic
  // recipes have different defaults — we want to preserve "show=false on
  // batch name for photo labels" by storing the diff appropriately).
  // The simpler choice: store the working state as-is across all recipes.
  // This means a designer change applies uniformly, which is what "Apply to
  // all" should do.
  (APP.recipes||[]).forEach(function(r){
    APP.settings.recipeOverlays[r.id]={};
    ['style','name','batchName','abv','qr','bestDrink'].forEach(function(elKey){
      var def=defaultOverlayFor(elKey,r.id);
      var working=s.workingOverlays[elKey];
      var changed={};
      var hasChange=false;
      Object.keys(working).forEach(function(k){
        if(working[k]!==def[k]){changed[k]=working[k];hasChange=true;}
      });
      if(hasChange)APP.settings.recipeOverlays[r.id][elKey]=changed;
    });
    // Trim empty
    if(!Object.keys(APP.settings.recipeOverlays[r.id]).length){
      delete APP.settings.recipeOverlays[r.id];
    }
  });
  scheduleSave();
  toast('✦ Applied to '+(APP.recipes||[]).length+' recipes');
}

function closeLabelDesigner(){
  var overlay=document.getElementById('designer-overlay');
  if(overlay)overlay.remove();
  window._designerState=null;
}

// ==================== MEDIA SOURCE RESOLVER (Phase 3) ====================
// Custom label images and the brand logo can be either:
//   1. A data URL (uploaded from device) — used directly as <img src>
//   2. A media-source:// identifier (picked from /config/media/) — must be
//      resolved against HA's media_source API to get a signed playable URL
//
// Resolved URLs are time-limited (~10min). We keep an in-memory cache and
// prefetch all known IDs at app boot. Cache misses cause getResolvedMediaUrl
// to return null (callers fall back to procedural/baked label) while an
// async resolution kicks off for next render.

if(typeof window._mediaResolveCache==='undefined')window._mediaResolveCache={};

// Determine the format of a stored label reference.
//   'data'    — data:image/...;base64,...  (use directly)
//   'media'   — media-source://...         (needs resolve)
//   'url'     — http(s) URL or /local/...  (use directly)
//   'none'    — null/empty/unknown
function classifyLabelRef(ref){
  if(!ref||typeof ref!=='string')return'none';
  if(ref.indexOf('data:')===0)return'data';
  if(ref.indexOf('media-source://')===0)return'media';
  if(/^https?:\/\//.test(ref)||ref.charAt(0)==='/')return'url';
  return'none';
}

// Synchronously resolve a label reference to a URL usable in <img src>.
// For data: URLs and direct URLs, returns the value unchanged. For
// media-source: refs, returns the cached resolved URL if fresh, else null
// (and schedules an async re-resolve so the cache fills for next render).
function getResolvedMediaUrl(ref){
  var kind=classifyLabelRef(ref);
  if(kind==='data'||kind==='url')return ref;
  if(kind==='media'){
    var cached=window._mediaResolveCache[ref];
    var now=Date.now();
    if(cached&&cached.expiresAt>now+30000)return cached.url;
    // Cache miss or near expiry — kick off async re-resolve in background
    if(!cached||!cached.refreshing){
      window._mediaResolveCache[ref]={url:cached?cached.url:null,expiresAt:cached?cached.expiresAt:0,refreshing:true};
      resolveMediaSourceId(ref).then(function(url){
        // Signed URLs typically last ~10 minutes; refresh at 8min to be safe
        window._mediaResolveCache[ref]={url:url,expiresAt:Date.now()+8*60*1000,refreshing:false};
        // Trigger re-renders so the new URL shows up immediately. We refresh
        // BOTH the main view (in case a label is visible there) AND the
        // designer modal if it's open (since renderMain doesn't touch the
        // designer's preview). Without the designer refresh, picking an HA
        // Media file would show the fallback label until the user reopened
        // the designer.
        if(!APP._shareMode&&typeof renderMain==='function')renderMain();
        if(window._designerState&&typeof refreshDesigner==='function')refreshDesigner();
        // Also refresh the topbar crest if this resolve was for the brand
        // logo — renderMain doesn't touch the topbar.
        if(APP.settings&&APP.settings.brandLogo===ref){
          var crest=document.getElementById('topbar-crest');
          if(crest&&typeof getBrandLogoSrc==='function'){
            crest.innerHTML='<img src="'+getBrandLogoSrc()+'" alt="MeadOS">';
          }
        }
      }).catch(function(err){
        console.warn('Media resolve failed for',ref,err);
        window._mediaResolveCache[ref]={url:null,expiresAt:0,refreshing:false,failed:true};
      });
    }
    return cached?cached.url:null;
  }
  return null;
}

// ==================== HA WEBSOCKET ====================
// HA's media_source/browse_media and media_source/resolve_media are exposed
// via the WebSocket API only — they are NOT REST endpoints. Earlier
// versions of this code POSTed to /api/media_source/browse_media which always
// failed with 404/405. The picker now talks WebSocket for these calls.
//
// One connection is maintained per session, authenticated once. Each call
// uses an incrementing id and resolves when the matching 'result' arrives.

if(typeof window._haWS==='undefined')window._haWS=null;
if(typeof window._haWSReady==='undefined')window._haWSReady=null;
if(typeof window._haWSPending==='undefined')window._haWSPending={};
if(typeof window._haWSId==='undefined')window._haWSId=0;

// The media-browser WebSocket needs the raw token (it can't go through the
// HTTP proxy). Fetch it on demand from the server — it isn't kept in app state.
function fetchHAToken(){
  return fetch('/api/ha-token')
    .then(function(r){return r.ok?r.json():null;})
    .then(function(j){return(j&&j.token)||null;})
    .catch(function(){return null;});
}

function ensureHAWebSocket(){
  if(window._haWSReady)return window._haWSReady;
  window._haWSReady=fetchHAToken().then(function(token){return new Promise(function(resolve,reject){
    if(!token){reject(new Error('No HA token'));return;}
    var base=(typeof haBaseUrl==='function'?haBaseUrl():'')||'';
    if(!base){reject(new Error('No HA URL configured'));return;}
    // http→ws, https→wss
    base=base.replace(/^http/,'ws');
    if(base.slice(-1)==='/')base=base.slice(0,-1);
    var url=base+'/api/websocket';
    console.log('[MeadOS] HA WebSocket connecting to',url);
    var ws;
    try{ws=new WebSocket(url);}catch(e){reject(e);return;}
    var settled=false;
    ws.onmessage=function(ev){
      var msg;
      try{msg=JSON.parse(ev.data);}catch(e){return;}
      if(msg.type==='auth_required'){
        ws.send(JSON.stringify({type:'auth',access_token:token}));
      }else if(msg.type==='auth_ok'){
        console.log('[MeadOS] HA WebSocket authenticated');
        window._haWS=ws;
        settled=true;
        resolve(ws);
      }else if(msg.type==='auth_invalid'){
        console.warn('[MeadOS] HA WebSocket auth invalid:',msg.message);
        settled=true;
        window._haWSReady=null;
        reject(new Error('HA token rejected: '+(msg.message||'auth_invalid')));
        try{ws.close();}catch(e){}
      }else if(msg.type==='result'){
        var pending=window._haWSPending[msg.id];
        if(pending){
          delete window._haWSPending[msg.id];
          if(msg.success)pending.resolve(msg.result);
          else pending.reject(new Error((msg.error&&msg.error.message)||'WS error'));
        }
      }
    };
    ws.onerror=function(ev){
      console.warn('[MeadOS] HA WebSocket error',ev);
      if(!settled){settled=true;window._haWSReady=null;reject(new Error('WebSocket connection error'));}
    };
    ws.onclose=function(){
      console.log('[MeadOS] HA WebSocket closed');
      window._haWS=null;
      window._haWSReady=null;
      // Reject any still-pending calls
      Object.keys(window._haWSPending).forEach(function(id){
        window._haWSPending[id].reject(new Error('WebSocket closed'));
        delete window._haWSPending[id];
      });
    };
    // 8-second connect timeout
    setTimeout(function(){
      if(!settled){settled=true;window._haWSReady=null;try{ws.close();}catch(e){}reject(new Error('WebSocket connect timeout'));}
    },8000);
  });});
  return window._haWSReady;
}

async function haWSCall(cmd){
  var ws=await ensureHAWebSocket();
  var id=++window._haWSId;
  return new Promise(function(resolve,reject){
    window._haWSPending[id]={resolve:resolve,reject:reject};
    try{ws.send(JSON.stringify(Object.assign({id:id},cmd)));}
    catch(e){delete window._haWSPending[id];reject(e);return;}
    // 15s timeout per call
    setTimeout(function(){
      if(window._haWSPending[id]){
        delete window._haWSPending[id];
        reject(new Error('WebSocket call timeout: '+(cmd.type||'?')));
      }
    },15000);
  });
}

// Resolve a media-source ID to a playable URL via WebSocket.
async function resolveMediaSourceId(mediaContentId){
  var result=await haWSCall({type:'media_source/resolve_media',media_content_id:mediaContentId});
  var base=(typeof haBaseUrl==='function'?haBaseUrl():'')||'';
  if(base.slice(-1)==='/')base=base.slice(0,-1);
  // HA returns either an absolute URL or a relative path like /api/media_source_proxy/...
  if(result.url&&result.url.charAt(0)==='/')return base+result.url;
  return result.url;
}

// Browse a folder via WebSocket. Returns {children:[...]} structure.
async function browseMediaSource(mediaContentId){
  return haWSCall({type:'media_source/browse_media',media_content_id:mediaContentId||null});
}

// Pre-resolve all known media-source IDs at app boot so cache is warm.
// Failures are non-fatal — callers fall back to procedural labels.
// Skipped entirely when HA is not configured/enabled, since media-source
// resolution requires the HA WebSocket which would otherwise time out for
// each stored ID (8s × N IDs of wasted connect attempts).
function prefetchAllMediaUrls(){
  if(typeof haConfigured!=='function'||!haConfigured())return;
  var ids=[];
  var cl=APP.settings.customLabels||{};
  Object.keys(cl).forEach(function(k){
    if(classifyLabelRef(cl[k])==='media')ids.push(cl[k]);
  });
  if(classifyLabelRef(APP.settings.brandLogo)==='media'){
    ids.push(APP.settings.brandLogo);
  }
  // De-dup
  ids=ids.filter(function(v,i,a){return a.indexOf(v)===i;});
  ids.forEach(function(id){getResolvedMediaUrl(id);});
}

// ==================== IMAGE UPLOAD UTILITY ====================
// Reads a File from <input type="file"> and returns a resized data URL.
// Resize keeps images under reasonable storage size — labels can be 900×900
// max (matches label spec); logos cap at 256×256. Output is JPEG @ quality
// 0.85 to balance fidelity with localStorage budget. PNG kept for images
// with transparency (logos often have it).
// Push a data-URL image to the server, which stores it as a plain file in
// the labels/ folder next to index.html and returns a tiny '/labels/<hash>'
// URL. Keeping URLs instead of megabytes of base64 in the state blob is what
// keeps page loads fast. Falls back to the data URL when the server can't
// store it (offline, etc.) — heavier but functional.
async function storeImageAsset(dataUrl,kind){
  try{
    var res=await apiFetch('/api/asset',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({data:dataUrl,kind:kind||'labels'})});
    if(res&&res.ok){
      var j=await res.json();
      if(j&&j.url)return j.url;
    }
  }catch(e){}
  return dataUrl;
}

// Build a square, dark-background app icon from the brand logo and store it as
// settings.appIcon. The OS masks the home-screen icon to a circle/squircle, so
// compositing the (often round/transparent) logo onto a padded dark square keeps
// it from being clipped. No image library needed — the browser canvas does it.
// Falls back to leaving appIcon unset (server then uses the raw logo) if the
// logo can't be drawn (e.g. a cross-origin source that taints the canvas).
async function regenerateAppIcon(){
  var prev=APP.settings&&APP.settings.appIcon;
  try{
    var brand=APP.settings&&APP.settings.brandLogo;
    if(!brand){APP.settings.appIcon=null;}
    else{
      var src=(typeof getBrandLogoSrc==='function')?getBrandLogoSrc():brand;
      var img=await new Promise(function(res,rej){var im=new Image();im.onload=function(){res(im);};im.onerror=function(){rej(new Error('load failed'));};im.src=src;});
      var iw=img.naturalWidth||img.width,ih=img.naturalHeight||img.height;
      if(!iw||!ih)throw new Error('no dimensions');
      var S=512,box=Math.round(S*0.78); // content in the central ~78% (maskable safe zone)
      var scale=Math.min(box/iw,box/ih),w=iw*scale,h=ih*scale;
      var cv=document.createElement('canvas');cv.width=S;cv.height=S;
      var ctx=cv.getContext('2d');
      ctx.fillStyle='#0a0a0b';ctx.fillRect(0,0,S,S);
      ctx.imageSmoothingEnabled=true;ctx.imageSmoothingQuality='high';
      ctx.drawImage(img,(S-w)/2,(S-h)/2,w,h);
      APP.settings.appIcon=await storeImageAsset(cv.toDataURL('image/png'),'brand');
    }
  }catch(e){APP.settings.appIcon=null;}
  if(prev&&prev!==APP.settings.appIcon&&typeof deleteAssetIfUnused==='function')deleteAssetIfUnused(prev);
}

// Is a stored /labels/ asset URL still referenced ANYWHERE in app state?
// Assets are content-addressed, so one file can back several references
// (two batches photographed with the same image, a label reused as a logo…).
// We only delete the file once the last reference is gone. Call this AFTER
// removing the reference from APP, so the scan reflects the post-delete state.
function assetUrlReferenced(url){
  if(!url)return true; // unknown → treat as in use (never delete)
  // Photos
  var photos=APP.photos||{};
  for(var bid in photos){
    if((photos[bid]||[]).some(function(p){return p.url===url;}))return true;
  }
  // Custom labels + brand logo
  var labels=(APP.settings&&APP.settings.customLabels)||{};
  for(var k in labels){if(labels[k]===url)return true;}
  if(APP.settings&&APP.settings.brandLogo===url)return true;
  if(APP.settings&&APP.settings.appIcon===url)return true;
  return false;
}

// Delete the underlying asset file IF it's a server-stored /labels/ asset and
// nothing else references it. Safe to call with any ref (data:/media:/empty —
// it no-ops). Best-effort: a failed delete just leaves the file (no orphan
// guarantee, but no user-facing error either).
async function deleteAssetIfUnused(url){
  if(classifyLabelRef(url)!=='url')return;       // only our own stored URLs
  if(url.indexOf('/labels/')!==0&&url.indexOf('/assets/')!==0)return; // not an uploaded asset
  if(assetUrlReferenced(url))return;              // still in use elsewhere
  try{
    await apiFetch('/api/asset/delete',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({url:url})});
  }catch(e){/* best-effort */}
}

// One-time migration: older versions embedded uploaded images as base64
// inside settings (and therefore inside every save/load of the state blob),
// which ballooned page loads to multiple seconds. Move them to the labels/
// folder and keep only the URLs.
async function migrateInlineImagesToAssets(){
  if(APP._shareMode)return;
  var jobs=[];
  var labels=APP.settings.customLabels||{};
  Object.keys(labels).forEach(function(k){
    if(typeof classifyLabelRef==='function'&&classifyLabelRef(labels[k])==='data')jobs.push({kind:'label',key:k,data:labels[k]});
  });
  if(typeof classifyLabelRef==='function'&&classifyLabelRef(APP.settings.brandLogo)==='data')jobs.push({kind:'logo',data:APP.settings.brandLogo});
  if(!jobs.length)return;
  var moved=0;
  for(var i=0;i<jobs.length;i++){
    var ref=await storeImageAsset(jobs[i].data,jobs[i].kind==='label'?'labels':'brand');
    if(ref!==jobs[i].data){
      if(jobs[i].kind==='label')APP.settings.customLabels[jobs[i].key]=ref;
      else APP.settings.brandLogo=ref;
      moved++;
    }
  }
  if(moved){
    scheduleSave();
    toast('🚀 Moved '+moved+' image'+(moved===1?'':'s')+' to the labels/ folder — page loads will be much faster');
  }
}

function readImageAsDataUrl(file,opts,callback){
  opts=opts||{};
  var maxDim=opts.maxDim||900;
  var preferPng=opts.preferPng===true;
  var reader=new FileReader();
  reader.onload=function(e){
    var img=new Image();
    img.onload=function(){
      var w=img.width,h=img.height;
      if(w>maxDim||h>maxDim){
        var scale=Math.min(maxDim/w,maxDim/h);
        w=Math.round(w*scale);
        h=Math.round(h*scale);
      }
      var canvas=document.createElement('canvas');
      canvas.width=w;canvas.height=h;
      var ctx=canvas.getContext('2d');
      ctx.drawImage(img,0,0,w,h);
      // Use PNG if requested OR if file already had transparency (heuristic
      // via the source mime type)
      var usePng=preferPng||/\.(png|svg)$/i.test(file.name||'')||(file.type||'').indexOf('png')>=0;
      var dataUrl=canvas.toDataURL(usePng?'image/png':'image/jpeg',0.85);
      callback(null,dataUrl,{w:w,h:h,bytes:dataUrl.length});
    };
    img.onerror=function(){callback(new Error('Image failed to load'));};
    img.src=e.target.result;
  };
  reader.onerror=function(){callback(new Error('File read failed'));};
  reader.readAsDataURL(file);
}

// ==================== IMAGE PICKER MODAL ====================
// Lets the user choose an image via:
//   • File upload from device (always available)
//   • HA Media Source browser (available when HA is configured)
//   • Direct URL paste (escape hatch)
//
// On selection, calls the provided callback with the stored reference (data
// URL string for uploads, media-source ID for HA picks, URL string for paste).

function openImagePicker(opts){
  opts=opts||{};
  var title=opts.title||'Pick an image';
  var callback=opts.onPick||function(){};
  var maxDim=opts.maxDim||900;
  var preferPng=opts.preferPng===true;
  var folder=opts.mediaFolder||'media-source://media_source/local';
  var canHA=(typeof haConfigured==='function')&&haConfigured();
  window._pickerState={
    title:title,
    callback:callback,
    kind:opts.kind||'labels',  // assets/<kind>/ subdir for uploads
    maxDim:maxDim,
    preferPng:preferPng,
    folder:folder,
    canHA:canHA,
    mode:canHA?'media':'upload',
    mediaItems:null,
    mediaLoading:false,
    mediaError:null,
    currentFolder:folder
  };
  document.body.insertAdjacentHTML('beforeend',renderImagePickerModal());
  if(canHA)loadMediaFolder(folder);
}

function renderImagePickerModal(){
  var s=window._pickerState;
  var tabBtn=function(key,label,enabled){
    var active=s.mode===key;
    return'<button onclick="setPickerMode(\''+key+'\')" '+(enabled?'':'disabled')+' '
      +'style="padding:8px 14px;border:1px solid '+(active?'var(--gold)':'var(--border)')+';'
      +'background:'+(active?'rgba(201,163,80,0.1)':'transparent')+';'
      +'color:'+(enabled?'var(--text)':'var(--text3)')+';'
      +'border-radius:4px;cursor:'+(enabled?'pointer':'not-allowed')+';'
      +'font-family:var(--font-mono);font-size:11px;letter-spacing:0.5px;margin-right:4px">'
      +escHtml(label)+'</button>';
  };
  var body='';
  if(s.mode==='upload')body=renderPickerUpload();
  else if(s.mode==='media')body=renderPickerMedia();
  else body=renderPickerUrl();
  return'<div class="modal-overlay" id="picker-overlay" onclick="if(event.target===this)closeImagePicker()">'
    +'<div class="modal" style="max-width:760px;width:94vw;max-height:88vh;overflow:auto;background:var(--bg2)">'
    +'<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:14px">'
    +'<div class="modal-title" style="margin:0">🖼 '+escHtml(s.title)+'</div>'
    +'<button class="btn btn-secondary btn-sm" onclick="closeImagePicker()">✕</button>'
    +'</div>'
    +'<div style="display:flex;margin-bottom:14px;border-bottom:1px solid var(--border);padding-bottom:10px">'
    +tabBtn('upload','📤 Upload',true)
    +tabBtn('media','🗂 HA Media',s.canHA)
    +tabBtn('url','🔗 URL',true)
    +(!s.canHA?'<span style="margin-left:8px;font-size:11px;color:var(--text3);font-style:italic;align-self:center">HA media browsing requires the optional Home Assistant connection (Settings)</span>':'')
    +'</div>'
    +'<div id="picker-body">'+body+'</div>'
    +'</div></div>';
}

function setPickerMode(mode){
  window._pickerState.mode=mode;
  // Re-render in place
  var overlay=document.getElementById('picker-overlay');
  if(overlay)overlay.outerHTML=renderImagePickerModal();
  if(mode==='media'&&!window._pickerState.mediaItems&&!window._pickerState.mediaLoading){
    loadMediaFolder(window._pickerState.currentFolder);
  }
}

function renderPickerUpload(){
  return'<div style="text-align:center;padding:30px 20px;border:2px dashed var(--border);border-radius:6px">'
    +'<div style="font-size:32px;margin-bottom:8px">📤</div>'
    +'<div style="font-family:var(--font-display);font-size:16px;color:var(--text);margin-bottom:8px">Upload from device</div>'
    +'<div style="font-size:12px;color:var(--text3);margin-bottom:18px">PNG, JPEG, WEBP, or SVG · auto-resized to '+window._pickerState.maxDim+'px max</div>'
    +'<input type="file" id="picker-file-input" accept="image/png,image/jpeg,image/webp,image/svg+xml" onchange="handlePickerUpload(this)" style="display:none">'
    +'<button class="btn btn-primary" onclick="document.getElementById(\'picker-file-input\').click()">Choose image…</button>'
    +'<div id="picker-upload-status" style="margin-top:14px;font-size:12px;color:var(--text3)"></div>'
    +'</div>';
}

function handlePickerUpload(input){
  var file=input.files&&input.files[0];
  if(!file)return;
  var status=document.getElementById('picker-upload-status');
  if(status)status.textContent='Processing '+file.name+'…';
  var s=window._pickerState;
  readImageAsDataUrl(file,{maxDim:s.maxDim,preferPng:s.preferPng},function(err,dataUrl,info){
    if(err){
      if(status){status.style.color='var(--red2)';status.textContent='⚠ '+err.message;}
      return;
    }
    if(status){
      status.style.color='var(--green2)';
      status.textContent='✓ Loaded '+info.w+'×'+info.h+' · '+(info.bytes/1024).toFixed(0)+'KB';
    }
    if(status)status.textContent='✓ Loaded '+info.w+'×'+info.h+' · storing on server…';
    storeImageAsset(dataUrl,s.kind||'labels').then(function(ref){
      var cb=s.callback;closeImagePicker();cb(ref);
    });
  });
}

function renderPickerUrl(){
  return'<div style="padding:20px">'
    +'<div style="font-family:var(--font-display);font-size:16px;color:var(--text);margin-bottom:8px">Paste an image URL</div>'
    +'<div style="font-size:12px;color:var(--text3);margin-bottom:14px">A direct URL to a PNG/JPEG/SVG. Works for /local/… paths inside HA or external https URLs.</div>'
    +'<div style="display:flex;gap:8px">'
    +'<input type="text" id="picker-url-input" class="form-input" style="flex:1" placeholder="/local/labels/my-mead.png or https://...">'
    +'<button class="btn btn-primary" onclick="confirmPickerUrl()">Use URL</button>'
    +'</div>'
    +'</div>';
}

function confirmPickerUrl(){
  var inp=document.getElementById('picker-url-input');
  if(!inp||!inp.value.trim())return;
  var url=inp.value.trim();
  var s=window._pickerState;var cb=s.callback;closeImagePicker();cb(url);
}

function renderPickerMedia(){
  var s=window._pickerState;
  if(s.mediaLoading)return'<div style="padding:30px;text-align:center;color:var(--text3);font-style:italic">Loading folder…</div>';
  if(s.mediaError)return'<div style="padding:20px;color:var(--red2);font-size:13px">⚠ '+escHtml(s.mediaError)+'<div style="margin-top:10px;color:var(--text3);font-size:12px">Make sure your HA <code>/config/media/labels/</code> folder exists and has images. If you haven\'t set up the folder, the Files addon can create it.</div></div>';
  if(!s.mediaItems)return'<div style="padding:20px;color:var(--text3)">No data</div>';
  var children=s.mediaItems.children||[];
  if(!children.length){
    // Convert media-source ID into a friendly /config/media-relative path.
    var friendly=s.currentFolder
      .replace('media-source://media_source/local/','/config/media/')
      .replace('media-source://media_source/local','/config/media');
    return'<div style="padding:30px;text-align:center;color:var(--text3);font-style:italic">'
      +'Empty folder. Drop images into <code>'+escHtml(friendly)+'</code> on your HA.'
      +(s.currentFolder!=='media-source://media_source/local'?'<div style="margin-top:10px;font-size:11px"><button class="btn btn-secondary btn-sm" onclick="loadMediaFolder(\'media-source://media_source/local\')">↰ Back to /config/media</button></div>':'')
      +'</div>';
  }
  // Path breadcrumb
  var path=s.currentFolder.replace('media-source://media_source/local/','/config/media/')
    .replace('media-source://media_source/local','/config/media');
  var crumb='<div style="font-family:var(--font-mono);font-size:11px;color:var(--text3);margin-bottom:10px;padding:6px 10px;background:var(--bg);border-radius:4px">📂 '+escHtml(path)+'</div>';
  var grid=children.map(function(c){
    var isFolder=c.media_class==='directory';
    var isImage=c.media_class==='image'||/\.(png|jpe?g|webp|svg)$/i.test(c.title||'');
    if(isFolder){
      return'<button onclick="loadMediaFolder(\''+escHtml(c.media_content_id).replace(/'/g,"\\'")+'\')" '
        +'style="display:flex;flex-direction:column;align-items:center;gap:6px;padding:14px 8px;background:var(--bg);'
        +'border:1px solid var(--border);border-radius:4px;cursor:pointer;color:var(--text);font-family:var(--font);font-size:12px">'
        +'<div style="font-size:28px">📁</div>'
        +'<div style="text-align:center;word-break:break-word">'+escHtml(c.title||'(folder)')+'</div>'
        +'</button>';
    }
    if(!isImage)return'';
    // Image item — show thumbnail if available, else filename
    return'<button onclick="confirmPickerMedia(\''+escHtml(c.media_content_id).replace(/'/g,"\\'")+'\')" '
      +'style="display:flex;flex-direction:column;align-items:center;gap:4px;padding:8px;background:var(--bg);'
      +'border:1px solid var(--border);border-radius:4px;cursor:pointer;color:var(--text)" '
      +'onmouseenter="this.style.borderColor=\'var(--gold)\'" onmouseleave="this.style.borderColor=\'var(--border)\'">'
      +(c.thumbnail?'<img src="'+escHtml(c.thumbnail)+'" style="width:100%;height:90px;object-fit:cover;border-radius:3px" loading="lazy">':'<div style="width:100%;height:90px;display:flex;align-items:center;justify-content:center;font-size:32px;background:var(--bg2);border-radius:3px">🖼</div>')
      +'<div style="font-size:11px;text-align:center;word-break:break-word;width:100%">'+escHtml(c.title||'(image)')+'</div>'
      +'</button>';
  }).filter(Boolean).join('');
  return crumb
    +'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(130px,1fr));gap:10px">'+grid+'</div>'
    +(s.currentFolder!=='media-source://media_source/local'?'<div style="margin-top:14px"><button class="btn btn-secondary btn-sm" onclick="loadMediaFolder(\'media-source://media_source/local\')">↰ Up to /config/media</button></div>':'');
}

function loadMediaFolder(mediaContentId){
  var s=window._pickerState;
  if(!s)return;
  s.currentFolder=mediaContentId;
  s.mediaLoading=true;
  s.mediaError=null;
  s.mediaItems=null;
  refreshPickerBody();
  browseMediaSource(mediaContentId).then(function(data){
    s.mediaLoading=false;
    s.mediaItems=data;
    refreshPickerBody();
  }).catch(function(err){
    s.mediaLoading=false;
    s.mediaError=err.message||String(err);
    refreshPickerBody();
  });
}

function refreshPickerBody(){
  var body=document.getElementById('picker-body');
  if(body)body.innerHTML=renderPickerMedia();
}

function confirmPickerMedia(mediaContentId){
  var s=window._pickerState;var cb=s.callback;closeImagePicker();cb(mediaContentId);
}

function closeImagePicker(){
  var overlay=document.getElementById('picker-overlay');
  if(overlay)overlay.remove();
  window._pickerState=null;
}

// Render the BACKGROUND IMAGE card in the Label Designer's left column.
// Shows what artwork the label is currently using and provides upload/clear.
function renderDesignerBackgroundCard(){
  var s=window._designerState;
  if(!s)return'';
  var customRef=(APP.settings.customLabels||{})[s.recipeId];
  var kind=classifyLabelRef(customRef);
  var source,sourceColor;
  if(kind==='data'){source='Uploaded image';sourceColor='var(--green2)';}
  else if(kind==='media'){source='HA media · '+(customRef.replace(/^media-source:\/\/[^\/]+\/[^\/]+\//,''));sourceColor='var(--blue2)';}
  else if(kind==='url'){source='URL';sourceColor='var(--blue2)';}
  else{
    var isGen=(typeof recipeUsesGenericLabel==='function')&&recipeUsesGenericLabel(s.recipeId);
    source=isGen?'Generated artwork':'Built-in image';
    sourceColor='var(--text3)';
  }
  return'<div style="margin-top:16px;padding:12px;background:var(--bg);border-radius:4px;border:1px solid var(--border)">'
    +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px;margin-bottom:8px">BACKGROUND IMAGE</div>'
    +'<div style="font-size:12px;color:'+sourceColor+';margin-bottom:10px;word-break:break-all">'+escHtml(source)+'</div>'
    +'<div style="display:flex;gap:6px;flex-wrap:wrap">'
    +'<button class="btn btn-secondary btn-sm" onclick="pickDesignerBackground()" style="flex:1">🖼 Pick image…</button>'
    +(kind!=='none'?'<button class="btn btn-secondary btn-sm" onclick="clearDesignerBackground()">Clear</button>':'')
    +'</div>'
    +'</div>';
}

// Opens the image picker, on selection stores the ref in customLabels and
// refreshes the designer preview.
function pickDesignerBackground(){
  var s=window._designerState;
  openImagePicker({
    title:'Pick background image for label',
    maxDim:900,
    onPick:function(ref){
      if(!APP.settings.customLabels)APP.settings.customLabels={};
      var prev=APP.settings.customLabels[s.recipeId];
      APP.settings.customLabels[s.recipeId]=ref;
      // If it's a media-source ID, kick off resolution immediately
      if(classifyLabelRef(ref)==='media')getResolvedMediaUrl(ref);
      // Save right away so it survives a Cancel
      scheduleSave();
      // The replaced background's file is orphaned if nothing else uses it.
      if(prev&&prev!==ref&&typeof deleteAssetIfUnused==='function')deleteAssetIfUnused(prev);
      refreshDesigner();
      toast('✦ Background updated');
    }
  });
}

function clearDesignerBackground(){
  var s=window._designerState;
  var prev=APP.settings.customLabels&&APP.settings.customLabels[s.recipeId];
  if(APP.settings.customLabels)delete APP.settings.customLabels[s.recipeId];
  scheduleSave();
  if(typeof deleteAssetIfUnused==='function')deleteAssetIfUnused(prev);
  refreshDesigner();
  toast('Background reverted to default');
}

// ==================== BRAND LOGO PICKER ====================
// Wraps the image picker for the topbar/dashboard logo. Stored server-side as
// an asset at the same 900px/PNG detail as bottle labels — the 200px preview is
// retina/HiDPI, so a smaller source visibly pixelates.
function pickBrandLogo(){
  openImagePicker({
    title:'Pick brand logo',
    kind:'brand',
    maxDim:900,
    preferPng:true,
    onPick:function(ref){
      var prev=APP.settings.brandLogo;
      APP.settings.brandLogo=ref;
      if(classifyLabelRef(ref)==='media')getResolvedMediaUrl(ref);
      scheduleSave();
      if(prev&&prev!==ref&&typeof deleteAssetIfUnused==='function')deleteAssetIfUnused(prev);
      // Rebuild the square dark-background PWA/app icon from the new logo.
      regenerateAppIcon().then(function(){scheduleSave();});
      // Refresh the topbar logo immediately (renderMain doesn't touch it)
      var crest=document.getElementById('topbar-crest');
      if(crest){
        var src=getBrandLogoSrc();
        crest.innerHTML='<img src="'+src+'" alt="MeadOS">';
      }
      renderMain();
      toast('✦ Brand logo updated');
    }
  });
}

function clearBrandLogo(){
  if(!confirm('Restore the default brand logo?'))return;
  var prev=APP.settings.brandLogo;
  var prevIcon=APP.settings.appIcon;
  APP.settings.brandLogo=null;
  APP.settings.appIcon=null;  // revert PWA/app icon to the bundled default too
  scheduleSave();
  if(typeof deleteAssetIfUnused==='function'){deleteAssetIfUnused(prev);if(prevIcon)deleteAssetIfUnused(prevIcon);}
  var crest=document.getElementById('topbar-crest');
  if(crest){
    crest.innerHTML='<img src="'+MEADOS_LOGO+'" alt="MeadOS">';
  }
  renderMain();
  toast('Brand logo reverted');
}

// Returns the URL to use as <img src> for the brand logo. Prefers the user's
// custom logo (APP.settings.brandLogo) — data URL, media-source ID, or direct
// URL — falling back to the bundled MEADOS_LOGO when none is set or the
// media-source ID hasn't yet been resolved.
function getBrandLogoSrc(){
  var custom=(APP.settings&&APP.settings.brandLogo)||null;
  if(custom&&typeof getResolvedMediaUrl==='function'){
    var resolved=getResolvedMediaUrl(custom);
    if(resolved)return resolved;
  }
  return(typeof MEADOS_LOGO!=='undefined')?MEADOS_LOGO:'';
}
// ==================== STUCK FERM DIAGNOSIS MODAL ====================
function showStuckFermDiagnosis(batchId){
  var d=diagnoseStuckFermentation(batchId);
  if(!d){toast('⚠ Batch not found');return;}
  var sevColor={'critical':'var(--red2)','high':'var(--red2)','medium':'var(--honey)','low':'var(--blue2)','info':'var(--text2)'};
  var sevBg={'critical':'#3a1010','high':'#2a1010','medium':'#2a2010','low':'#102030','info':'var(--bg4)'};
  var diagHtml=d.diagnoses.map(function(x){
    return'<div style="padding:12px;background:'+sevBg[x.severity]+';border-left:3px solid '+sevColor[x.severity]+';border-radius:var(--radius);margin-bottom:8px">'
      +'<div style="font-family:var(--font-mono);font-size:10px;color:'+sevColor[x.severity]+';letter-spacing:2px;margin-bottom:4px">'+x.severity.toUpperCase()+'</div>'
      +'<div style="font-weight:600;color:var(--text);margin-bottom:4px">'+escHtml(x.title)+'</div>'
      +'<div style="font-size:13px;color:var(--text2);line-height:1.5">'+escHtml(x.detail)+'</div></div>';
  }).join('');
  var actionHtml=d.actions.length
    ?'<div style="margin-top:10px;padding:12px;background:#102818;border-left:3px solid var(--green2);border-radius:var(--radius)">'
      +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--green2);letter-spacing:2px;margin-bottom:6px">RECOMMENDED ACTIONS</div>'
      +'<ol style="margin:0;padding-left:18px;font-size:13px;color:var(--text2);line-height:1.7">'
      +d.actions.map(function(a){return'<li>'+escHtml(a)+'</li>';}).join('')
      +'</ol></div>'
    :'';
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:600px">'
    +'<div class="modal-title">🔬 FERMENTATION DIAGNOSIS</div>'
    +'<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:14px">'
    +'<div style="padding:10px;background:var(--bg3);border-radius:var(--radius);text-align:center"><div style="font-family:var(--font-display);font-size:20px;color:var(--gold2)">'+d.daysSinceStart+'</div><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-top:2px">DAYS</div></div>'
    +'<div style="padding:10px;background:var(--bg3);border-radius:var(--radius);text-align:center"><div style="font-family:var(--font-display);font-size:20px;color:var(--gold2)">'+(d.attenuation*100).toFixed(0)+'%</div><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-top:2px">ATTENUATION</div></div>'
    +'<div style="padding:10px;background:var(--bg3);border-radius:var(--radius);text-align:center"><div style="font-family:var(--font-display);font-size:20px;color:var(--gold2)">'+d.currentAbv.toFixed(1)+'%</div><div style="font-family:var(--font-mono);font-size:9px;color:var(--text3);letter-spacing:1.5px;margin-top:2px">ABV</div></div>'
    +'</div>'
    +(diagHtml||'<div style="padding:12px;background:var(--bg4);border-radius:var(--radius);color:var(--text3);font-style:italic">No diagnostic findings — fermentation may be proceeding normally.</div>')
    +actionHtml
    +'<div class="modal-actions"><button class="btn btn-secondary" onclick="closeModal()">Close</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}

// ==================== COST LEADERBOARD ====================
function renderCostLeaderboard(){
  var data=computeCostEffectiveness();
  if(!data.length)return'';
  var ccy=APP.settings.currency||'€';
  // Sort by costPerBottle ascending (most efficient first)
  data.sort(function(a,b){return a.costPerBottle-b.costPerBottle;});
  var rows=data.slice(0,15).map(function(d){
    var color=getBatchColor(d.batch);
    var ratingDisplay=d.avgRating?d.avgRating.toFixed(1)+'★':'<span style="color:var(--text3)">—</span>';
    var valueScore=d.avgRating&&d.costPerBottle?(d.avgRating/d.costPerBottle).toFixed(2):'—';
    return'<tr style="cursor:pointer" onclick="showView(\'batch\',\''+d.batch.id+'\')">'
      +'<td style="color:'+color+';font-family:var(--font-display);padding:8px 10px">'+escHtml(d.batch.name)+'</td>'
      +'<td style="text-align:right;font-family:var(--font-mono)">'+ccy+d.totalCost.toFixed(2)+'</td>'
      +'<td style="text-align:right;font-family:var(--font-mono)">'+d.bottles+'</td>'
      +'<td style="text-align:right;font-family:var(--font-mono);color:var(--gold2)">'+ccy+d.costPerBottle.toFixed(2)+'</td>'
      +'<td style="text-align:right;font-family:var(--font-mono)">'+ccy+d.costPerLitre.toFixed(2)+'/L</td>'
      +'<td style="text-align:right;font-family:var(--font-mono)">'+ratingDisplay+'</td>'
      +'<td style="text-align:right;font-family:var(--font-mono);color:var(--green2)" title="Rating per €">'+valueScore+'</td>'
      +'</tr>';
  }).join('');
  return'<div class="card" style="margin-bottom:14px">'
    +'<div class="card-header"><div class="card-title">💰 COST EFFECTIVENESS</div></div>'
    +'<div style="font-size:12px;color:var(--text3);margin-bottom:10px;font-style:italic">Ranked by cost per bottle (most efficient first). "Value" = rating ÷ total cost — higher is better.</div>'
    +'<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px">'
    +'<thead><tr style="border-bottom:1px solid var(--border);color:var(--text3);font-family:var(--font-mono);font-size:10px;letter-spacing:1.5px">'
    +'<th style="text-align:left;padding:8px 10px">BATCH</th>'
    +'<th style="text-align:right">TOTAL</th>'
    +'<th style="text-align:right">BOTTLES</th>'
    +'<th style="text-align:right">PER BOTTLE</th>'
    +'<th style="text-align:right">PER L</th>'
    +'<th style="text-align:right">RATING</th>'
    +'<th style="text-align:right">VALUE</th>'
    +'</tr></thead><tbody>'+rows+'</tbody></table></div>'
    +'</div>';
}

// ==================== TEMPLATES VIEW SECTION ====================
function renderTemplatesSection(){
  var tpls=APP.templates||[];
  if(!tpls.length)return'';
  return'<div class="card" style="margin-bottom:14px"><div class="card-header"><div class="card-title">💾 BATCH TEMPLATES</div></div>'
    +'<div style="font-size:12px;color:var(--text3);margin-bottom:10px;font-style:italic">Saved batch configurations. Click "Apply" to start a new batch pre-filled with these values.</div>'
    +tpls.map(function(t){
      var recipe=APP.recipes.find(function(r){return r.id===t.recipeId;});
      var ccy=APP.settings.currency||'€';
      return'<div style="display:flex;align-items:center;gap:10px;padding:10px;background:var(--bg3);border-radius:var(--radius);margin-bottom:8px;flex-wrap:wrap">'
        +'<div style="flex:1;min-width:240px"><div style="font-family:var(--font-display);font-size:14px;color:var(--gold2)">'+escHtml(t.name)+'</div>'
        +'<div style="font-size:12px;color:var(--text3);font-family:var(--font-mono);margin-top:2px">'
        +(recipe?escHtml(recipe.name):'Unknown recipe')+' · '+(t.volume||'?')+'L · OG '+(t.og||'?')+(t.honeyType?' · '+escHtml(t.honeyType):'')+(t.yeast?' · '+escHtml((getYeastById(t.yeast)||{}).name||'').split('—')[0].trim():'')
        +(t.costPerLitre?' · '+ccy+t.costPerLitre.toFixed(2)+'/L':'')
        +'</div></div>'
        +'<div style="display:flex;gap:6px"><button class="btn btn-primary btn-sm" onclick="applyTemplate(\''+t.id+'\')">Apply</button>'
        +'<button class="btn btn-danger btn-sm" onclick="deleteTemplate(\''+t.id+'\')">✕</button></div>'
        +'</div>';
    }).join('')
    +'</div>';
}

// ==================== RECIPE SCALING WIZARD ====================
function openRecipeScalingWizard(recipeId){
  closeModal();
  var r=APP.recipes.find(function(x){return x.id===recipeId;});
  if(!r){toast('⚠ Recipe not found');return;}
  var defaultVol=r.volume||5;
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:560px">'
    +'<div class="modal-title">📐 SCALE RECIPE</div>'
    +'<div style="font-size:13px;color:var(--text2);margin-bottom:14px"><strong>'+escHtml(r.name)+'</strong> is designed for <strong>'+defaultVol+'L</strong>. Enter your target volume to scale all ingredients proportionally.</div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Original Volume (L)</label><input class="form-input" id="rs-orig" type="number" value="'+defaultVol+'" step="0.1" disabled style="opacity:0.7"></div>'
    +'<div class="form-group"><label class="form-label">Target Volume (L)</label><input class="form-input" id="rs-target" type="number" value="'+defaultVol+'" step="0.1" oninput="updateRecipeScaling(\''+recipeId+'\')" autofocus></div></div>'
    +'<div id="rs-output" style="margin-top:10px"></div>'
    +'<div class="modal-actions"><button class="btn btn-secondary" onclick="closeModal()">Cancel</button>'
    +'<button class="btn btn-primary" onclick="startScaledBatch(\''+recipeId+'\')">Start Batch with This Scaling</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
  updateRecipeScaling(recipeId);
}

function updateRecipeScaling(recipeId){
  var r=APP.recipes.find(function(x){return x.id===recipeId;});
  if(!r)return;
  var targetVol=parseFloat(document.getElementById('rs-target').value)||r.volume;
  var ratio=targetVol/r.volume;
  var outEl=document.getElementById('rs-output');
  var ogPoints=(r.ogTarget-1)*1000;
  var honeyKg=(ogPoints*targetVol/292).toFixed(2);
  var ccy=APP.settings.currency||'€';
  var costEst=APP.settings.honeyPricePerKg?(parseFloat(honeyKg)*APP.settings.honeyPricePerKg).toFixed(2):'';
  // Scale yeast pitch
  var pitch=calcPitchAmount(r.yeast||'m05',targetVol,r.ogTarget);
  outEl.innerHTML='<div style="background:var(--bg3);padding:14px;border-radius:var(--radius);border:1px solid var(--border)">'
    +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">'
    +'<div style="text-align:center;padding:10px;background:var(--bg4);border-radius:var(--radius)"><div style="font-family:var(--font-display);font-size:22px;color:var(--gold2)">'+honeyKg+' kg</div><div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin-top:2px">HONEY</div></div>'
    +'<div style="text-align:center;padding:10px;background:var(--bg4);border-radius:var(--radius)"><div style="font-family:var(--font-display);font-size:22px;color:var(--gold2)">'+targetVol+' L</div><div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin-top:2px">FINAL VOLUME</div></div>'
    +'</div>'
    +'<div style="font-family:var(--font-mono);font-size:12px;color:var(--text2);line-height:1.8">'
    +'<div><strong>Water:</strong> ~'+(targetVol-honeyKg*0.7).toFixed(2)+'L (honey displaces ~0.7L/kg)</div>'
    +(pitch?'<div><strong>Yeast:</strong> '+pitch.sachetsRounded+' sachets ('+pitch.totalGrams.toFixed(1)+' g) · '+pitch.yeast.name.split('—')[0].trim()+'</div>':'')
    +'<div><strong>Target OG:</strong> '+r.ogTarget+'</div>'
    +(costEst?'<div><strong>Est. honey cost:</strong> '+ccy+costEst+'</div>':'')
    +'<div><strong>Scaling factor:</strong> ×'+ratio.toFixed(3)+'</div>'
    +'</div></div>';
}

function startScaledBatch(recipeId){
  var targetVol=parseFloat(document.getElementById('rs-target').value);
  closeModal();
  if(!targetVol||targetVol<=0)return;
  // Open new-batch modal with scaled volume
  openNewBatchModal(recipeId,targetVol);
}

// Wire scale button into recipe detail view
function recipeDetailScaleButton(recipeId){
  return'<button class="btn btn-secondary btn-sm" onclick="openRecipeScalingWizard(\''+recipeId+'\')">📐 Scale to Volume</button>';
}
// ==================== PUBLIC BATCH URL SHARING ====================
// Strategy: the QR encodes a SHORT URL with just the batch ID.
// When the recipient opens it, MeadOS loads the live data from the server
// and renders a static read-only "share" page — no sidebar, no nav, no
// modify UI.
//
// Why this approach: the alternative (encoding the full snapshot in the URL
// hash) blows up the QR to an unscannable density. By loading live data, we
// keep the QR small AND get always-current age/gravity/tasting info.
//
// Access model: anyone who can reach the MeadOS server can read its data.
// The standalone share view has no UI for editing, so casual recipients
// can't change anything.

// Base URL used for every generated link (share links, QR codes, the HA
// companion card). Defaults to wherever the app is currently being browsed,
// but Settings → Public URL overrides it — essential behind a reverse proxy,
// where the address YOU browse on (LAN IP) isn't the address recipients can
// reach. The override is stored in the shared blob so every device generates
// identical links.
function appBaseUrl(){
  var ext=((APP.settings&&APP.settings.externalUrl)||'').trim();
  if(ext)return ext.replace(/\/+$/,'')+'/';
  return window.location.origin+window.location.pathname.replace(/index\.html$/,'');
}

// Mint (or reuse) an unguessable share token for a batch. Tokens are stored in
// APP.shareTokens {token:batchId} and ride the state blob. One stable token per
// batch so re-copying a link doesn't spawn duplicates. ~128 bits of entropy.
function shareTokenForBatch(batchId){
  if(!APP.shareTokens||typeof APP.shareTokens!=='object')APP.shareTokens={};
  // Reuse an existing token for this batch if one was already minted.
  var existing=Object.keys(APP.shareTokens).find(function(t){return APP.shareTokens[t]===batchId;});
  if(existing)return existing;
  var tok='';
  try{
    var arr=new Uint8Array(16);(window.crypto||window.msCrypto).getRandomValues(arr);
    tok=Array.prototype.map.call(arr,function(x){return('0'+x.toString(16)).slice(-2);}).join('');
  }catch(e){
    tok=(Date.now().toString(36)+Math.random().toString(36).slice(2)+Math.random().toString(36).slice(2)).slice(0,32);
  }
  APP.shareTokens[tok]=batchId;
  // Persist the new token so the link resolves on the server. Never write from
  // a guest's share-mode page (it has no business saving state).
  if(!APP._shareMode&&typeof scheduleSave==='function')scheduleSave();
  return tok;
}

function buildShareURL(batch){
  if(!batch||!batch.id)return null;
  var base=appBaseUrl();
  // Tokenised path form: /share/<token>. The token resolves server-side to a
  // single sanitized batch — no serial or internal id is exposed in the URL,
  // and a leaked link reveals only that one batch. The /share path is exempt
  // from the external-access password so guests never hit a login prompt.
  var tok=shareTokenForBatch(batch.id);
  return base+'share/'+tok;
}

// Food pairing heuristic based on sweetness + style category + ABV
function suggestFoodPairings(s){
  var pairings=[];
  var sw=s.sw||s.sweetness||'';
  var cat=s.cat||s.category||'';
  var abv=s.abv||0;
  if(sw==='Bone Dry'||sw==='Dry'){
    pairings.push('Aged cheeses (gouda, manchego, parmesan)');
    pairings.push('Charcuterie boards — saucisson, prosciutto, jamón');
    pairings.push('Grilled or roasted meats');
  }else if(sw==='Off-Dry'||sw==='Semi-Sweet'){
    pairings.push('Soft cheeses (brie, camembert)');
    pairings.push('Spicy Asian dishes — Thai curry, Korean BBQ');
    pairings.push('Mild creamy sauces over poultry');
  }else if(sw==='Sweet'||sw==='Dessert'){
    pairings.push('Blue cheeses (roquefort, gorgonzola, stilton)');
    pairings.push('Fruit-based desserts — tarte tatin, fruit pies');
    pairings.push('Dark chocolate and chocolate-based desserts');
    pairings.push('Foie gras and rich pâtés');
  }
  if(cat==='Bochet')pairings.push('Caramel desserts, crème brûlée, vanilla ice cream');
  if(cat==='Cyser')pairings.push('Pork dishes, especially with apples or root vegetables');
  if(cat==='Pyment')pairings.push('Match its body to the dish like a wine');
  if(cat==='Melomel')pairings.push('Same fruit desserts especially');
  if(cat==='Metheglin')pairings.push('Mulled cider season — spiced cookies, gingerbread');
  if(cat==='Braggot')pairings.push('Pub fare — sausages, hearty stews, smoked meats');
  if(cat==='Specialty')pairings.push('Match the dominant flavor (chili → spicy, coffee → desserts)');
  if(abv>=13)pairings.push('Sipped on its own — treat like a digestif');
  return pairings.slice(0,5);
}

// Copy share URL for a batch to clipboard
async function copyShareLink(batchId){
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b){toast('⚠ Batch not found');return;}
  var url=buildShareURL(b);
  if(!url){toast('⚠ Failed to build share link');return;}
  // Make sure the freshly-minted token is on the server BEFORE handing out the
  // link, otherwise the recipient could 404 on a token the server hasn't seen.
  try{if(typeof saveData==='function')await saveData();}catch(e){}
  try{
    navigator.clipboard.writeText(url);
    toast('✦ Share link copied');
  }catch(e){
    window.prompt('Copy this share link:',url);
  }
}

// Render the standalone read-only share page for a batch.
// REPLACES the entire <body> — no sidebar, no topbar, no app shell.
// Operates on the live batch object from APP state, so age/gravity/tastings
// are always current as of page load.
// ===== Public share view — extra info sections =====
// Honey weight for the bee fun-fact: prefer the batch's logged kg, else parse
// the recipe's honey ingredient line ("1.7 kg").
function shareHoneyKg(b,recipe){
  if(b&&typeof b.honey==='number'&&b.honey>0)return b.honey;
  if(recipe&&recipe.ingredients){
    for(var i=0;i<recipe.ingredients.length;i++){
      var it=recipe.ingredients[i];
      if(/honey/i.test(it.item||'')){
        var m=String(it.amount||'').match(/([\d.]+)\s*kg/i);
        if(m)return parseFloat(m[1]);
      }
    }
  }
  return 0;
}

function renderShareIngredients(b,recipe){
  var ing=(recipe&&recipe.ingredients)||[];
  if(!ing.length)return'';
  var rows=ing.map(function(it){
    var item=it.item||'';
    // Reflect the batch's actual honey variety on the honey line.
    if(b.honeyType&&/honey\s*$/i.test(item)&&item.toLowerCase().indexOf(String(b.honeyType).toLowerCase())<0){
      item=b.honeyType+' Honey';
    }
    // Reflect the batch's actual yeast strain on the yeast line.
    if(b.yeast&&/yeast\s*$/i.test(item)&&typeof getYeastById==='function'){
      var yn=yeastShortName(getYeastById(b.yeast));
      if(yn&&item.toLowerCase().indexOf(yn.toLowerCase())<0)item=yn+' Yeast';
    }
    return'<li><span class="ing-item">'+escHtml(item)+'</span>'+(it.amount?'<span class="ing-amt">'+escHtml(it.amount)+'</span>':'')+'</li>';
  }).join('');
  return'<section class="section"><div class="section-title">What’s Inside</div>'
    +'<ul class="share-ingredients">'+rows+'</ul>'
    +'<div class="ing-note">Honey, water and yeast are the heart of every mead — the nutrients and finishing aids are consumed during fermentation or settle out, leaving no meaningful trace in the glass.</div>'
    +'</section>';
}

// Scan ingredients + style for the allergens that actually apply to mead.
function shareDietaryData(b,recipe){
  var ing=(recipe&&recipe.ingredients)||[];
  var hay=(ing.map(function(i){return(i.item||'')+' '+(i.notes||'');}).join(' ')+' '
    +(b.honeyType||'')+' '+((recipe&&recipe.category)||'')+' '+((recipe&&recipe.name)||'')+' '
    +((recipe&&recipe.style)||'')+' '+(b.name||'')).toLowerCase();
  var contains=[];
  var gluten=/\bmalt|barley|\bwheat|braggot|\bdme\b|\brye\b|\bgrain/.test(hay);
  if(/almond|walnut|pecan|hazelnut|cashew|pistachio|chestnut|\bnut\b|praline|marzipan/.test(hay))contains.push({k:'tree nuts',d:'used as an ingredient'});
  if(/\bmilk\b|cream|lactose|\bwhey\b|\bdairy/.test(hay))contains.push({k:'milk',d:'a dairy ingredient is used'});
  if(/\begg|albumen|isinglass/.test(hay))contains.push({k:'egg or fish',d:'a possible fining agent'});
  var sulfites=/metabisul|campden|k-?meta|sulph?ite|\bso2\b|sorbate/.test(hay);
  return{contains:contains,sulfites:sulfites,gluten:gluten};
}

function renderShareDietary(b,recipe,bot){
  if(!recipe)return'';
  var d=shareDietaryData(b,recipe);
  function badge(txt,tone){
    var c=tone==='good'?'#7cc87c':tone==='warn'?'#e8a050':'#c9a84c';
    return'<span class="diet-badge" style="color:'+c+';border-color:'+c+'55;background:'+c+'14">'+escHtml(txt)+'</span>';
  }
  var badges=[];
  if(bot.abv)badges.push(badge(bot.abv.toFixed(1)+'% alcohol','warn'));
  badges.push(d.gluten?badge('Contains gluten','warn'):badge('Gluten-free','good'));
  badges.push(badge('Vegetarian','good'));
  badges.push(badge('Not vegan · honey','base'));
  var lines=[];
  lines.push(d.sulfites?'<strong>Contains sulfites</strong> — added as an antioxidant and stabiliser.':'<strong>No sulfites added</strong> — though fermentation itself can leave trace amounts.');
  d.contains.forEach(function(c){lines.push('<strong>Contains '+escHtml(c.k)+'</strong> — '+escHtml(c.d)+'.');});
  if(!d.gluten)lines.push('<strong>Naturally gluten-free</strong> — mead is fermented from honey, not grain.');
  return'<section class="section"><div class="section-title">Allergens &amp; Dietary</div>'
    +'<div class="diet-badges">'+badges.join('')+'</div>'
    +'<ul class="allergen-list">'+lines.map(function(l){return'<li>'+l+'</li>';}).join('')+'</ul>'
    +'<div class="ing-note">Homemade — not produced in an allergen-controlled facility. Contains alcohol; not for anyone under legal drinking age, pregnant, or avoiding alcohol.</div>'
    +'</section>';
}

// Public photo journal on the share page — a gallery of the batch's photos
// (oldest → newest), each opening the same lightbox the app uses. Only the
// whitelisted /labels/ asset URLs ship in the share payload.
function renderSharePhotos(b){
  var photos=(APP.photos&&APP.photos[b.id])||[];
  if(!photos.length)return'';
  var sorted=photos.slice().sort(function(a,c){return(a.date||'').localeCompare(c.date||'');});
  var thumbs=sorted.map(function(p){
    var st=(typeof photoStage==='function')?photoStage(p.stage):{label:'',color:'#c9a84c'};
    var src=(typeof getResolvedMediaUrl==='function'&&getResolvedMediaUrl(p.url))||p.url;
    return'<figure class="share-photo" onclick="openPhotoLightbox(\''+b.id+'\',\''+p.id+'\')">'
      +'<span class="share-photo-stage" style="background:'+st.color+'">'+escHtml((st.label||'').toUpperCase())+'</span>'
      +'<img src="'+escHtml(src)+'" alt="'+escHtml(p.caption||st.label||'Batch photo')+'" loading="lazy">'
      +(p.caption?'<figcaption>'+escHtml(p.caption)+'</figcaption>':'')
      +'</figure>';
  }).join('');
  return'<section class="section"><div class="section-title">Photo Journal</div><div class="share-gallery">'+thumbs+'</div></section>';
}

function renderShareFunFacts(b,recipe,bot,ageDays){
  var cat=(recipe&&recipe.category)||'';
  var style=(recipe&&recipe.style)||'';
  var f=[];
  var meaning={
    Bochet:'A bochet is made from honey caramelised before fermenting — that’s where its toffee, marshmallow and dark-chocolate notes come from.',
    Cyser:'A cyser is a mead fermented with apples or apple juice — a honey-and-orchard hybrid.',
    Pyment:'A pyment is a mead made with grapes or grape juice — the point where mead and wine meet.',
    Melomel:'A melomel is simply a mead made with fruit; the name covers everything from berry to stone-fruit meads.',
    Metheglin:'A metheglin is a spiced or herbed mead — the word shares a root with “medicine”, as these were once brewed as tonics.',
    Braggot:'A braggot is an ancient mead-and-ale hybrid, brewed with both honey and malt.',
    Acerglyn:'An acerglyn is a mead made with maple syrup alongside the honey.',
    Sack:'A “sack” mead is a deliberately strong, sweet style, traditionally aged for years before drinking.'
  };
  // Recipes carry the style word in either `category` or `style`.
  var styleFact=meaning[cat]||meaning[style];
  if(styleFact)f.push(styleFact);
  else if(/show|traditional/i.test(style+' '+cat))f.push('A “show mead” (or traditional) contains nothing but honey, water and yeast — it’s judged purely on the character of the honey, with nowhere to hide.');
  f.push('Mead is widely considered humanity’s oldest fermented drink — residue on pottery in northern China dates a honey-based brew to roughly 7000 BCE, predating both wine and beer.');
  var kg=shareHoneyKg(b,recipe);
  if(kg>0){
    var flowers=Math.round(kg*4.4);
    var km=Math.round(kg*120000/1000)*1000;
    var laps=(kg*120000/40075).toFixed(1);
    var kgStr=(kg%1===0)?String(kg):kg.toFixed(1);
    f.push('The '+kgStr+' kg of honey in this batch took bees roughly '+flowers+' million flower visits to gather — about '+km.toLocaleString()+' km of flight, the equivalent of circling the Earth around '+laps+' times.');
  }
  if(bot.abv){
    var a=bot.abv;
    var ctx=a>=14?'stronger than most wine':a>=11?'right in wine territory':a>=8?'between a strong beer and a light wine':'around the strength of a beer';
    f.push('At '+a.toFixed(1)+'% ABV this mead is '+ctx+'. Honey has no vintage: the very same honey can ferment bone-dry or lusciously sweet depending only on the yeast and the brewer.');
  }
  var hp=(typeof HONEY_PROFILES!=='undefined'&&b.honeyType)?HONEY_PROFILES[b.honeyType]:null;
  var honeyHistory=hp&&((hp.details&&hp.details.history)||hp.history);
  if(honeyHistory){
    var first=String(honeyHistory).split('. ')[0];
    if(first)f.push(escHtmlStrip(b.honeyType)+' honey: '+first+'.');
  }
  f.push('The word “honeymoon” may trace back to mead — a tradition of newlyweds drinking honey wine for one moon (a month) after the wedding to bless the union.');
  if(!f.length)return'';
  return'<section class="section"><div class="section-title">Fun Facts</div><ul class="facts-list">'+f.map(function(x){return'<li>'+escHtml(x)+'</li>';}).join('')+'</ul></section>';
}
// Tiny helper: strip any stray markup from a label before re-escaping in context.
function escHtmlStrip(s){return String(s||'').replace(/<[^>]*>/g,'');}

function renderPublicShareView(b){
  if(!b||!b.id){
    document.body.innerHTML='<div style="display:flex;align-items:center;justify-content:center;min-height:100vh;font-family:Georgia,serif;color:#888;background:#1a0f08;font-size:18px;padding:20px;text-align:center">This batch was not found.</div>';
    return;
  }
  var bot=APP.bottling[b.id]||{};
  var recipe=APP.recipes.find(function(r){return r.id===b.recipeId;});
  var tastings=APP.tastings[b.id]||[];
  var logs=APP.logs[b.id]||[];
  var avgRating=tastings.length
    ?tastings.reduce(function(s,t){return s+(t.rating||0);},0)/tastings.length
    :0;
  var ageDays=bot.date?Math.floor((new Date()-new Date(bot.date))/86400000):0;
  var brewerName=(APP.settings&&APP.settings.brewerName)||'MeadOS';
  var recipeName=recipe?recipe.name:(b.style||'');
  if(recipeName.indexOf('·')>0)recipeName=recipeName.split('·')[0].trim();

  // Aging window
  var minDays=recipe?(recipe.minAgeDays||30):30;
  var peakDays=recipe?(recipe.peakAgeDays||180):180;
  var maxDays=recipe?(recipe.maxAgeDays||peakDays*3):peakDays*3;

  // Gravity chart data: build a list of [days_from_start, gravity]
  var startDate=b.startDate?new Date(b.startDate):null;
  var chartData=[];
  if(startDate){
    if(b.og)chartData.push([0,b.og]);
    logs.filter(function(l){return l.gravity;}).sort(function(a,b){return a.date.localeCompare(b.date);}).forEach(function(l){
      var d=Math.floor((new Date(l.date)-startDate)/86400000);
      if(d>0&&!chartData.some(function(p){return p[0]===d;})){
        chartData.push([d,l.gravity]);
      }
    });
    if(bot.fg&&bot.date){
      var bdDays=Math.floor((new Date(bot.date)-startDate)/86400000);
      if(!chartData.some(function(p){return p[0]===bdDays;})){
        chartData.push([bdDays,bot.fg]);
      }
    }
  }

  // Most recent tasting note (with full notes, not truncated)
  var lastTasting=null;
  if(tastings.length){
    var sortedT=tastings.slice().sort(function(a,b){return(b.date||'').localeCompare(a.date||'');});
    lastTasting=sortedT[0];
  }

  // Food pairings
  var pairings=suggestFoodPairings({sw:bot.sweetness,cat:recipe?recipe.category:'',abv:bot.abv});

  // Build the sections
  var agingHtml=renderShareAgingTimeline(ageDays,minDays,peakDays,maxDays);
  var gravityHtml=renderShareGravityChart(chartData,b.og);
  var tastingHtml=renderShareTastingNotes(lastTasting);
  var ingredientsHtml=renderShareIngredients(b,recipe);
  var allergensHtml=renderShareDietary(b,recipe,bot);
  var photosHtml=renderSharePhotos(b);
  var factsHtml=renderShareFunFacts(b,recipe,bot,ageDays);

  var html=''
    +'<style>'
    +'*{box-sizing:border-box}'
    // The main-app stylesheet sets html,body{height:100%;overflow:hidden} for the
    // grid layout. Override here so the share page can scroll naturally.
    +'html,body{height:auto!important;overflow:auto!important;overflow-x:hidden}'
    +'body{margin:0;padding:0;background:linear-gradient(180deg,#1a0f08,#2a1810 40%,#1f1408);color:#e0d6b8;font-family:"EB Garamond",Georgia,"Times New Roman",serif;min-height:100vh;line-height:1.5;-webkit-font-smoothing:antialiased}'
    // Faint honeycomb texture over the page gradient — fixed so it doesn't
    // scroll, pointer-events off so it never eats clicks.
    +'body:before{content:"";position:fixed;inset:0;background-image:url("data:image/svg+xml,%3Csvg xmlns=%27http://www.w3.org/2000/svg%27 width=%2756%27 height=%27100%27%3E%3Cpath d=%27M28 66L0 50L0 16L28 0L56 16L56 50L28 66L28 100%27 fill=%27none%27 stroke=%27%23c9a84c%27 stroke-width=%271%27/%3E%3Cpath d=%27M28 0L28 34L0 50L0 84L28 100L56 84L56 50%27 fill=%27none%27 stroke=%27%23c9a84c%27 stroke-width=%271%27/%3E%3C/svg%3E");background-size:56px 100px;opacity:0.045;pointer-events:none;z-index:0}'
    +'.share-container{position:relative;z-index:1;max-width:600px;margin:22px auto;padding:38px 26px 46px;border:1px solid rgba(201,168,76,0.30);border-radius:8px;background:rgba(22,12,5,0.72);box-shadow:inset 0 0 0 3px rgba(26,15,8,0.95),inset 0 0 0 4px rgba(201,168,76,0.16),0 20px 60px rgba(0,0,0,0.5)}'
    +'.share-container:before{content:"❦";position:absolute;top:-12px;left:50%;transform:translateX(-50%);background:#1f1207;padding:0 12px;color:var(--gold);font-size:15px;line-height:1.5}'
    +'.share-header{text-align:center;padding:10px 0 26px;border-bottom:1px solid rgba(201,168,76,0.25)}'
    +'.brewed-by{font-family:"Cinzel","EB Garamond",serif;font-size:11px;color:var(--gold);letter-spacing:4px;margin-bottom:10px;text-transform:uppercase}'
    +'.brewer-name{font-family:"Cinzel","Times New Roman",serif;font-size:24px;color:#e8c878;letter-spacing:1px;line-height:1.2}'
    +'.batch-card{padding:28px 0 18px;text-align:center}'
    +'.batch-name{font-family:"Cinzel","Times New Roman",serif;font-size:34px;color:#e8c878;line-height:1.15;margin-bottom:6px;letter-spacing:0.5px}'
    +'.batch-style{font-style:italic;font-size:14px;color:#a0937a;letter-spacing:1.5px;margin-bottom:22px}'
    +'.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:18px}'
    +'.stat{padding:14px 6px;background:linear-gradient(180deg,rgba(201,168,76,0.12),rgba(201,168,76,0.03));border:1px solid rgba(201,168,76,0.28);border-radius:6px;position:relative;overflow:hidden}'
    +'.stat:before{content:"";position:absolute;top:0;left:18%;right:18%;height:1px;background:linear-gradient(90deg,transparent,#e8c878,transparent)}'
    +'.stat-val{font-family:"Cinzel","Times New Roman",serif;font-size:22px;color:#e8c878;line-height:1.1}'
    +'.stat-lbl{font-family:"Cinzel",serif;font-size:9px;color:#8a7d68;letter-spacing:2px;margin-top:5px;text-transform:uppercase}'
    +'.meta-line{color:#a0937a;font-size:14px;margin:6px 0}'
    +'.meta-line strong{color:var(--gold);font-weight:500}'
    +'.section{margin-top:26px}'
    +'.section-title{display:flex;align-items:center;gap:14px;justify-content:center;text-align:center;font-family:"Cinzel",serif;font-size:11px;color:var(--gold);letter-spacing:3.5px;margin-bottom:16px;text-transform:uppercase}'
    +'.section-title:before,.section-title:after{content:"";height:1px;flex:1;min-width:20px}'
    +'.section-title:before{background:linear-gradient(90deg,transparent,rgba(201,168,76,0.45))}'
    +'.section-title:after{background:linear-gradient(90deg,rgba(201,168,76,0.45),transparent)}'
    +'.share-gallery{display:grid;grid-template-columns:repeat(auto-fill,minmax(118px,1fr));gap:10px}'
    +'.share-photo{position:relative;margin:0;cursor:pointer;border:1px solid rgba(201,168,76,0.28);border-radius:5px;overflow:hidden;background:rgba(0,0,0,0.28);transition:border-color .2s}'
    +'.share-photo:hover{border-color:rgba(201,168,76,0.6)}'
    +'.share-photo img{width:100%;height:108px;object-fit:cover;display:block}'
    +'.share-photo-stage{position:absolute;top:6px;left:6px;font-family:ui-monospace,Menlo,monospace;font-size:8px;letter-spacing:1px;padding:2px 6px;border-radius:7px;color:#1a0f08}'
    +'.share-photo figcaption{font-size:10.5px;color:#b8a87d;padding:5px 8px;line-height:1.35}'
    +'.share-chart-wrap{padding:16px 14px;background:rgba(0,0,0,0.18);border-radius:6px;border:1px solid rgba(201,168,76,0.1)}'
    // Thin horizontal aging bar — matches MeadOS .aging-bar-bg/.aging-bar-fill style
    +'.share-aging-bar{position:relative;height:10px;background:rgba(0,0,0,0.5);border-radius:5px;margin:14px 0 4px}'
    +'.share-aging-fill{height:100%;border-radius:5px;transition:width .6s ease}'
    +'.share-aging-marker{position:absolute;top:-3px;width:2px;height:16px;border-radius:1px}'
    +'.share-aging-labels{display:flex;justify-content:space-between;font-family:ui-monospace,Menlo,monospace;font-size:10px;color:#8a7d68;margin-top:8px}'
    +'.share-aging-status{margin-top:12px;text-align:center;font-size:13px;font-style:italic;letter-spacing:0.3px}'
    +'.tasting-quote{background:rgba(201,168,76,0.06);border-left:3px solid var(--gold);padding:16px 18px;border-radius:0 6px 6px 0}'
    +'.tasting-quote .q{font-style:italic;color:#e0d6b8;font-size:15px;line-height:1.6}'
    +'.tasting-quote .attrib{margin-top:10px;font-size:11px;color:#8a7d68;font-family:"Cinzel",serif;letter-spacing:1.5px}'
    +'.pairings ul{padding-left:22px;line-height:1.85;margin:0}'
    +'.pairings li{margin-bottom:6px;color:#c9b990}'
    +'.share-ingredients{list-style:none;padding:0;margin:0}'
    +'.share-ingredients li{display:flex;justify-content:space-between;gap:14px;padding:9px 2px;border-bottom:1px solid rgba(201,168,76,0.1)}'
    +'.share-ingredients li:last-child{border-bottom:none}'
    +'.ing-item{color:#e0d6b8}'
    +'.ing-amt{color:var(--gold);font-family:ui-monospace,Menlo,monospace;font-size:13px;white-space:nowrap}'
    +'.ing-note{font-size:12px;color:#8a7d68;font-style:italic;line-height:1.6;margin-top:12px}'
    +'.diet-badges{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:14px}'
    +'.diet-badge{font-family:"Cinzel",serif;font-size:10px;letter-spacing:1px;padding:5px 11px;border:1px solid;border-radius:20px;text-transform:uppercase;white-space:nowrap}'
    +'.allergen-list{list-style:none;padding:0;margin:0}'
    +'.allergen-list li{padding:6px 0 6px 18px;position:relative;color:#c9b990;font-size:13.5px;line-height:1.55}'
    +'.allergen-list li:before{content:"•";position:absolute;left:2px;color:var(--gold)}'
    +'.allergen-list strong{color:#e0d6b8;font-weight:500}'
    +'.facts-list{list-style:none;padding:0;margin:0}'
    +'.facts-list li{padding:10px 0 10px 26px;position:relative;color:#c9b990;font-size:13.5px;line-height:1.62;border-bottom:1px solid rgba(201,168,76,0.08)}'
    +'.facts-list li:last-child{border-bottom:none}'
    +'.facts-list li:before{content:"❦";position:absolute;left:0;top:9px;color:var(--gold);font-size:13px}'
    +'.footer{margin-top:38px;text-align:center;font-size:10px;color:#5e533f;font-family:"Cinzel",serif;letter-spacing:2.5px;padding-top:18px;border-top:1px solid rgba(201,168,76,0.12)}'
    +'.share-crest{width:200px;height:200px;object-fit:contain;margin:0 auto 18px;display:block;filter:drop-shadow(0 0 28px rgba(201,168,76,0.5))}'
    +'.share-orn{display:flex;align-items:center;gap:14px;color:var(--gold);font-size:14px;margin-top:18px}'
    +'.share-orn:before,.share-orn:after{content:"";height:1px;flex:1}'
    +'.share-orn:before{background:linear-gradient(90deg,transparent,rgba(201,168,76,0.5))}'
    +'.share-orn:after{background:linear-gradient(90deg,rgba(201,168,76,0.5),transparent)}'
    +'.label-frame{width:190px;margin:4px auto 22px;padding:9px;background:linear-gradient(150deg,#2c1a0c,#190f07);border:1px solid rgba(201,168,76,0.35);border-radius:8px;box-shadow:0 14px 34px rgba(0,0,0,0.55),inset 0 0 14px rgba(0,0,0,0.5)}'
    +'.label-frame img{width:100%;display:block;border-radius:4px}'
    +'.batch-desc{font-style:italic;font-size:14px;color:#bfae8a;line-height:1.7;max-width:430px;margin:0 auto 22px}'
    +'.seal{width:90px;height:90px;border-radius:50%;margin:6px auto 16px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:2px;border:1px solid rgba(201,168,76,0.55);box-shadow:inset 0 0 0 3px #1a0f08,inset 0 0 0 4px rgba(201,168,76,0.3),0 6px 16px rgba(0,0,0,0.45);background:radial-gradient(circle at 35% 28%,#3a2410,#231304 70%)}'
    +'.seal .s1{font-family:"Cinzel",serif;font-size:8px;color:var(--gold);letter-spacing:2.5px}'
    +'.seal .s2{font-family:"Cinzel",serif;font-size:14px;color:#e8c878;letter-spacing:1px}'
    +'.footer-orn{color:var(--gold);font-size:14px;margin-bottom:8px;letter-spacing:8px}'
    +'.footer-tag{margin-top:7px;font-style:italic;font-family:"EB Garamond",Georgia,serif;font-size:11px;color:#8a7d68;letter-spacing:1px;text-transform:none}'
    +'@media (max-width:480px){'
    +'  .share-container{margin:10px;padding:28px 14px 40px}'
    +'  .label-frame{width:150px}'
    +'  .share-crest{width:150px;height:150px}'
    +'  .batch-name{font-size:26px}'
    +'  .brewer-name{font-size:20px}'
    +'  .stats{gap:6px}'
    +'  .stat{padding:10px 4px}'
    +'  .stat-val{font-size:18px}'
    +'  .stat-lbl{font-size:8px;letter-spacing:1.5px}'
    +'}'
    +'</style>'
    +'<div class="share-container">'
    +'<header class="share-header">'
    +(function(){
      var lg=(typeof getBrandLogoSrc==='function')?getBrandLogoSrc():'';
      // Only embed directly displayable refs (custom logos are data: URLs;
      // unresolved media-source:// refs would render a broken image).
      return(lg&&/^(data:|https?:|\/)/.test(lg))?'<img class="share-crest" src="'+escHtml(lg)+'" alt="">':'';
    }())
    +'<div class="brewed-by">Brewed by</div>'
    +'<div class="brewer-name">'+escHtml(brewerName)+'</div>'
    +'<div class="share-orn">❦</div>'
    +'</header>'
    +'<section class="batch-card">'
    +(function(){
      // Bottle label, rendered through the SAME path as the Label Maker (art +
      // the recipe's overlay config) so it looks exactly as designed — just with
      // the QR code and drinking-window box suppressed for the public page.
      if(!window._shareLabelImage||typeof renderLabelWithABV!=='function')return'';
      var abvText=(bot&&bot.abv!=null)?String(bot.abv):'';
      return'<div class="label-frame">'+renderLabelWithABV(b.recipeId,abvText,{batch:b,qr:false,bestDrink:false})+'</div>';
    }())
    +'<div class="batch-name">'+escHtml(b.name||'')+'</div>'
    +'<div class="batch-style">'+escHtml(recipeName||'')+(recipe&&recipe.category&&recipe.category!==recipeName?' · '+escHtml(recipe.category):'')+'</div>'
    +(recipe&&recipe.description?'<div class="batch-desc">“'+escHtml(recipe.description)+'”</div>':'')
    +'<div class="stats">'
    +'<div class="stat"><div class="stat-val">'+(bot.abv?bot.abv.toFixed(1)+'%':'—')+'</div><div class="stat-lbl">ABV</div></div>'
    +'<div class="stat"><div class="stat-val">'+escHtml(bot.sweetness||'—')+'</div><div class="stat-lbl">Sweetness</div></div>'
    +'<div class="stat"><div class="stat-val">'+(bot.date?(typeof fmtDurationCompact==='function'?fmtDurationCompact(ageDays):ageDays+'d'):'—')+'</div><div class="stat-lbl">Bottle Age</div></div>'
    +'</div>'
    +(b.honeyType?'<div class="meta-line"><strong>Honey:</strong> '+escHtml(b.honeyType)+'</div>':'')
    +(bot.date?'<div class="meta-line"><strong>Bottled:</strong> '+escHtml(typeof fmtDate==='function'?fmtDate(bot.date):bot.date)+'</div>':'')
    +(avgRating>0&&tastings.length?'<div class="meta-line"><strong>Brewer\'s rating:</strong> '+(Math.round(avgRating*10)/10)+'★ ('+tastings.length+' tasting'+(tastings.length!==1?'s':'')+')</div>':'')
    +(b.serial?'<div class="seal"><div class="s1">BATCH</div><div class="s2">'+escHtml(b.serial)+'</div></div>':'')
    +'</section>'
    +ingredientsHtml
    +allergensHtml
    +agingHtml
    +gravityHtml
    +tastingHtml
    +photosHtml
    +(pairings.length?'<section class="section"><div class="section-title">Suggested Pairings</div><div class="pairings"><ul>'+pairings.map(function(p){return'<li>'+escHtml(p)+'</li>';}).join('')+'</ul></div></section>':'')
    +factsHtml
    +'<footer class="footer"><div class="footer-orn">❦</div>'+escHtml(brewerName)+(bot.date?' · '+escHtml(typeof fmtDate==='function'?fmtDate(bot.date):bot.date):'')+'<div class="footer-tag">Crafted with patience</div></footer>'
    +'</div>';
  document.body.innerHTML=html;
  document.title=(b.name||'Mead')+' · '+brewerName;
}

// Aging timeline: matches the MeadOS .aging-bar style — thin horizontal bar
// with gradient progress fill, vertical line markers at Ready/Peak, label row
// below, status sentence underneath.
function renderShareAgingTimeline(ageDays,minD,peakD,maxD){
  if(ageDays==null||!minD)return'';
  peakD=peakD||(minD*3);
  maxD=maxD||(peakD*2);
  var displayMax=Math.max(maxD,ageDays,1);
  var pct=Math.min(100,(ageDays/displayMax)*100);
  var minPct=(minD/displayMax)*100;
  var peakPct=(peakD/displayMax)*100;
  // Gradient + status by aging position
  var gradient,statusColor,status;
  if(ageDays<minD){
    gradient='linear-gradient(90deg,#8a6a30,var(--gold))';
    statusColor='#c9a84c';
    var dr=minD-ageDays;
    status='⏳ Still aging — about '+fmtDuration(dr)+' until ready';
  }else if(ageDays<peakD){
    gradient='linear-gradient(90deg,var(--gold),#7cc87c)';
    statusColor='#7cc87c';
    var dp=peakD-ageDays;
    status='✓ In drinking window — about '+fmtDuration(dp)+' until estimated peak';
  }else if(ageDays<maxD){
    gradient='linear-gradient(90deg,var(--gold),#7cc87c,#e8a050)';
    statusColor='#e8a050';
    status='⚠ Past peak — still good, flavour now slowly declining';
  }else{
    gradient='linear-gradient(90deg,var(--gold),#e8a050,#d06060)';
    statusColor='#d06060';
    status='⚠ Beyond typical drinking window — taste carefully';
  }
  return'<section class="section"><div class="section-title">Drinking Window</div><div class="share-chart-wrap">'
    +'<div class="share-aging-bar">'
    +'<div class="share-aging-fill" style="width:'+pct.toFixed(1)+'%;background:'+gradient+'"></div>'
    +'<div class="share-aging-marker" style="left:'+minPct.toFixed(1)+'%;background:#7cc87c;box-shadow:0 0 6px #7cc87c"></div>'
    +'<div class="share-aging-marker" style="left:'+peakPct.toFixed(1)+'%;background:#e8c878;box-shadow:0 0 6px #e8c878"></div>'
    +'</div>'
    +'<div class="share-aging-labels">'
    +'<span>Now</span>'
    +'<span style="color:#7cc87c">Ready · '+fmtDurationCompact(minD)+'</span>'
    +'<span style="color:#e8c878">Peak · '+fmtDurationCompact(peakD)+'</span>'
    +'<span>Max · '+fmtDurationCompact(maxD)+'</span>'
    +'</div>'
    +'<div class="share-aging-status" style="color:'+statusColor+'">'+escHtml(status)+'</div>'
    +'</div></section>';
}

// Compact SVG line chart of the gravity readings, with the estimated ABV drawn
// on a second (right) axis so the ABV rise as gravity falls is visible. Takes an
// array of [days, gravity_float] and the original gravity (for the ABV scale).
function renderShareGravityChart(data,og){
  if(!data||data.length<2)return'';
  var w=440,h=210,padL=46,padR=44,padT=16,padB=28;
  var maxDay=Math.max.apply(null,data.map(function(p){return p[0];}));
  var grav=data.map(function(p){return p[1];});
  var minG=Math.min.apply(null,grav),maxG=Math.max.apply(null,grav);
  // Round to 3 decimals
  minG=Math.floor((minG-0.005)*1000)/1000;
  maxG=Math.ceil((maxG+0.005)*1000)/1000;
  if(maxG-minG<0.030)maxG=minG+0.030;
  // ABV axis (right): 0 → ABV at the lowest gravity, using OG.
  var ogVal=og||(data[0]&&data[0][0]===0?data[0][1]:null);
  var showAbv=!!ogVal&&(ogVal-minG)>0;
  var maxA=showAbv?Math.max(1,Math.ceil((ogVal-minG)*131.25)):0;
  var sx=function(d){return padL+(d/(maxDay||1))*(w-padL-padR);};
  var sy=function(g){return padT+((maxG-g)/(maxG-minG))*(h-padT-padB);};
  var ay=function(a){return padT+((maxA-a)/(maxA||1))*(h-padT-padB);};
  var pathD=data.map(function(p,i){return(i===0?'M':'L')+' '+sx(p[0]).toFixed(1)+' '+sy(p[1]).toFixed(1);}).join(' ');
  var fillD=pathD+' L '+sx(maxDay).toFixed(1)+' '+(h-padB)+' L '+padL+' '+(h-padB)+' Z';
  var dots=data.map(function(p){return'<circle cx="'+sx(p[0]).toFixed(1)+'" cy="'+sy(p[1]).toFixed(1)+'" r="3.5" fill="#e8c878" stroke="#1f1408" stroke-width="1.5"/>';}).join('');
  // ABV line + dots + right-axis %
  var abvPath='',abvDots='',abvLabels='';
  if(showAbv){
    abvPath='<path d="'+data.map(function(p,i){var a=(ogVal-p[1])*131.25;return(i===0?'M':'L')+' '+sx(p[0]).toFixed(1)+' '+ay(a).toFixed(1);}).join(' ')+'" stroke="#7cc87c" stroke-width="2" fill="none" stroke-linejoin="round"/>';
    abvDots=data.map(function(p){var a=(ogVal-p[1])*131.25;return'<circle cx="'+sx(p[0]).toFixed(1)+'" cy="'+ay(a).toFixed(1)+'" r="3" fill="#7cc87c" stroke="#1f1408" stroke-width="1.2"/>';}).join('');
    for(var j=0;j<=3;j++){var av=(maxA*j)/3;var yy=ay(av);abvLabels+='<text x="'+(w-padR+6)+'" y="'+(yy+3.5).toFixed(1)+'" font-family="monospace" font-size="9" fill="#7ca87c" text-anchor="start">'+av.toFixed(0)+'%</text>';}
  }
  var yLabels='';
  for(var i=0;i<=3;i++){
    var val=minG+((maxG-minG)*i)/3;
    var y=sy(val);
    yLabels+='<line x1="'+padL+'" y1="'+y.toFixed(1)+'" x2="'+(w-padR)+'" y2="'+y.toFixed(1)+'" stroke="rgba(201,168,76,0.1)" stroke-dasharray="2,3"/>'
      +'<text x="'+(padL-6)+'" y="'+(y+3.5).toFixed(1)+'" font-family="monospace" font-size="9" fill="#8a7d68" text-anchor="end">'+val.toFixed(3)+'</text>';
  }
  var xLabels='';
  var xStep=maxDay>60?Math.ceil(maxDay/4/10)*10:Math.max(1,Math.ceil(maxDay/4));
  for(var d=0;d<=maxDay;d+=xStep){
    xLabels+='<text x="'+sx(d).toFixed(1)+'" y="'+(h-padB+14)+'" font-family="monospace" font-size="9" fill="#8a7d68" text-anchor="middle">'+d+'d</text>';
  }
  return'<section class="section"><div class="section-title">Fermentation Curve</div><div class="share-chart-wrap">'
    // Safari/WebKit collapses SVGs with bare height:auto + no width/height
    // attrs to wrong intrinsic dimensions, which made the chart caption render
    // ON TOP OF the next section title. Belt-and-braces: explicit width/height
    // attributes + aspect-ratio CSS so the browser computes the right box.
    +'<svg viewBox="0 0 '+w+' '+h+'" width="'+w+'" height="'+h+'" style="width:100%;max-width:'+w+'px;height:auto;aspect-ratio:'+w+'/'+h+';display:block;margin:0 auto">'
    +yLabels+xLabels+abvLabels
    +'<path d="'+fillD+'" fill="rgba(201,168,76,0.08)"/>'
    +'<path d="'+pathD+'" stroke="#c9a84c" stroke-width="2" fill="none" stroke-linejoin="round"/>'
    +dots
    +abvPath+abvDots
    +'</svg>'
    +'<div style="text-align:center;font-size:10px;color:#8a7d68;letter-spacing:1.5px;margin-top:6px;font-family:Cinzel,serif">'+(showAbv?'<span style="color:#c9a84c">●</span> GRAVITY &nbsp;·&nbsp; <span style="color:#7cc87c">●</span> ABV % &nbsp;·&nbsp; OVER FERMENTATION DAYS':'SPECIFIC GRAVITY OVER FERMENTATION DAYS')+'</div>'
    +'</div></section>';
}

// Tasting Journal — matches MeadOS batch view: date + stars header, radar
// chart + 5-dot bar list if wheel data exists, then color/aroma/flavor/finish/notes.
function renderShareTastingNotes(t){
  if(!t)return'';
  // Build star display
  var stars='';
  for(var i=1;i<=5;i++)stars+='<span style="color:'+(i<=t.rating?'#e8c878':'rgba(201,168,76,0.2)')+';font-size:18px">★</span>';
  // Wheel section
  var wheelSection='';
  if(t.wheel&&typeof TASTING_AXES!=='undefined'&&typeof getTastingWheelRadarHTML==='function'){
    var hasAny=Object.values(t.wheel).some(function(v){return v>0;});
    if(hasAny){
      var bars=TASTING_AXES.filter(function(ax){return t.wheel[ax.key]>0;}).map(function(ax){
        var filled=t.wheel[ax.key];
        return'<div style="display:flex;justify-content:space-between;font-family:ui-monospace,monospace;font-size:11px;color:#a0937a;line-height:1.9"><span>'+ax.label+'</span><span><span style="color:var(--gold)">'+'●'.repeat(filled)+'</span><span style="color:rgba(201,168,76,0.15)">'+'●'.repeat(5-filled)+'</span></span></div>';
      }).join('');
      // Cap the radar's max-width so it doesn't grow huge in narrow grids, and
      // give the inner SVG room to render its labels (which extend past the
      // circle on left/right) without clipping.
      wheelSection='<div style="display:grid;grid-template-columns:minmax(0,1fr) minmax(0,1fr);gap:16px;align-items:center;margin:14px 0 10px"><div style="max-width:220px;margin:0 auto;width:100%;overflow:visible">'+getTastingWheelRadarHTML(t.wheel)+'</div><div>'+bars+'</div></div>';
    }
  }
  // Optional text fields
  function fieldRow(label,val){return val?'<div style="font-size:13px;color:#c9b990;margin:4px 0"><strong style="color:var(--gold)">'+label+':</strong> '+escHtml(val)+'</div>':'';}
  var fields=fieldRow('Color',t.color)+fieldRow('Aroma',t.aroma)+fieldRow('Flavor',t.flavor)+fieldRow('Finish',t.finish);
  // Notes can be in `notes` or `note` depending on schema vintage
  var notes=t.notes||t.note||'';
  return'<section class="section"><div class="section-title">Tasting Journal</div>'
    +'<div class="tasting-quote">'
    +'<div style="display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:6px;flex-wrap:wrap;gap:6px"><div style="font-family:ui-monospace,monospace;font-size:12px;color:#8a7d68">'+escHtml(t.date||'')+'</div><div>'+stars+'</div></div>'
    +wheelSection
    +fields
    +(notes?'<div style="font-style:italic;color:#e0d6b8;font-size:14px;line-height:1.6;margin-top:10px">"'+escHtml(notes)+'"</div>':'')
    +'</div></section>';
}
// ==================== RECIPE PDF EXPORT ====================
// Uses browser's print dialog (saves as PDF). One-page formatted recipe card
// with brand crest, ingredients table, step timeline, and target stats.
function exportRecipePDF(recipeId){
  var r=APP.recipes.find(function(x){return x.id===recipeId;});
  if(!r){toast('⚠ Recipe not found');return;}
  var brand=APP.settings.brewerName||'MeadOS';
  // Steps timeline. Recipes use r.steps with {day, title, desc} — NOT r.schedule.
  var steps=(r.steps||r.schedule||[]).slice().sort(function(a,b){return(a.day||0)-(b.day||0);});
  var stepsHtml=steps.map(function(s){
    var title=s.title||s.task||'';
    var desc=s.desc||s.detail||'';
    return'<tr><td class="day">Day '+(s.day||0)+'</td><td class="task"><div style="font-weight:600">'+escHtml(title)+'</div>'+(desc?'<div class="detail">'+escHtml(desc)+'</div>':'')+'</td></tr>';
  }).join('');
  var ingHtml=r.ingredients.map(function(i){
    return'<tr><td class="ing">'+escHtml(i.item)+'</td><td class="amt">'+escHtml(i.amount)+'</td><td class="notes">'+escHtml(i.notes||'')+'</td></tr>';
  }).join('');
  var w=window.open('','_blank','width=850,height=1100');
  if(!w){toast('⚠ Popup blocked');return;}
  var css='@page{size:A4;margin:14mm 12mm}body{margin:0;padding:0;font-family:"EB Garamond",Georgia,serif;color:#2a1810;background:#fbf6e8;-webkit-print-color-adjust:exact;print-color-adjust:exact}'
    +'.page{max-width:186mm;margin:0 auto;padding:0}'
    +'.header{text-align:center;border-bottom:2px solid var(--gold);padding-bottom:10mm;margin-bottom:8mm}'
    +'.brand{font-family:"Cinzel",serif;font-size:14pt;color:#8a6a30;letter-spacing:4px;margin-bottom:4mm}'
    +'.title{font-family:"Cinzel",serif;font-size:26pt;color:#3a2010;letter-spacing:1px;margin-bottom:2mm;line-height:1.1}'
    +'.style{font-style:italic;font-size:13pt;color:#6a4a20}'
    +'.meta{display:grid;grid-template-columns:repeat(4,1fr);gap:4mm;margin:6mm 0}'
    +'.meta-cell{text-align:center;padding:3mm;background:#f0e6ce;border-radius:2mm}'
    +'.meta-val{font-family:"Cinzel",serif;font-size:14pt;color:var(--gold);font-weight:600}'
    +'.meta-lbl{font-family:"Cinzel",serif;font-size:8pt;color:#6a4a20;letter-spacing:2px;text-transform:uppercase;margin-top:1mm}'
    +'.description{margin:5mm 0;padding:4mm;background:#f5ebd4;border-left:3px solid var(--gold);font-size:11pt;line-height:1.5}'
    +'.section-title{font-family:"Cinzel",serif;font-size:13pt;color:#8a6a30;letter-spacing:3px;border-bottom:1px solid var(--gold);padding-bottom:1mm;margin:6mm 0 3mm}'
    +'table{width:100%;border-collapse:collapse;font-size:10pt}'
    +'th{text-align:left;padding:2mm 3mm;background:var(--gold);color:#fff;font-family:"Cinzel",serif;font-size:9pt;letter-spacing:2px;text-transform:uppercase}'
    +'td{padding:2mm 3mm;border-bottom:1px solid #e0d4b0;vertical-align:top}'
    +'tr:nth-child(even) td{background:rgba(201,168,76,0.06)}'
    +'.ing{font-weight:600;width:30%}.amt{font-family:"Cinzel",serif;color:#8a6a30;width:25%}.notes{font-style:italic;color:#6a4a20;font-size:9.5pt}'
    +'.day{font-family:"Cinzel",serif;color:var(--gold);font-weight:600;width:18%}.task{}'
    +'.detail{font-style:italic;color:#6a4a20;font-size:9.5pt;margin-top:1mm}'
    +'.footer{margin-top:6mm;text-align:center;font-family:"Cinzel",serif;font-size:8pt;color:#8a6a30;letter-spacing:3px;border-top:1px solid var(--gold);padding-top:3mm}'
    +'.tags{display:flex;gap:2mm;flex-wrap:wrap;margin-top:3mm}'
    +'.tag{padding:1mm 3mm;background:#e8d9a7;border-radius:3mm;font-size:9pt;color:#3a2010}';
  w.document.write('<!DOCTYPE html><html><head><meta charset="utf-8"><title>'+escHtml(r.name)+' — Recipe</title>'
    +'<link rel="preconnect" href="https://fonts.googleapis.com">'
    +'<link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@500;700&family=EB+Garamond:ital@0;1&display=swap" rel="stylesheet">'
    +'<style>'+css+'</style></head><body><div class="page">'
    +'<div class="header">'
    +'<div class="brand">'+escHtml(brand.toUpperCase())+'</div>'
    +'<div class="title">'+escHtml(r.name)+'</div>'
    +'<div class="style">'+escHtml(r.style)+(r.category&&r.category!==r.style?' · '+escHtml(r.category):'')+'</div>'
    +'</div>'
    +'<div class="meta">'
    +'<div class="meta-cell"><div class="meta-val">'+(r.volume||'?')+' L</div><div class="meta-lbl">Volume</div></div>'
    +'<div class="meta-cell"><div class="meta-val">'+(r.ogTarget||'?')+'</div><div class="meta-lbl">Target OG</div></div>'
    +'<div class="meta-cell"><div class="meta-val">~'+(r.abvTarget||'?')+'%</div><div class="meta-lbl">Target ABV</div></div>'
    +'<div class="meta-cell"><div class="meta-val">'+escHtml(r.difficulty||'?')+'</div><div class="meta-lbl">Difficulty</div></div>'
    +'</div>'
    +(r.description?'<div class="description">'+escHtml(r.description)+'</div>':'')
    +'<div class="section-title">Ingredients</div>'
    +'<table><thead><tr><th>Item</th><th>Amount</th><th>Notes</th></tr></thead><tbody>'+ingHtml+'</tbody></table>'
    +(stepsHtml?'<div class="section-title">Schedule</div>'
      +'<table><thead><tr><th>When</th><th>Task</th></tr></thead><tbody>'+stepsHtml+'</tbody></table>':'')
    +(r.tags&&r.tags.length?'<div class="tags">'+r.tags.map(function(t){return'<span class="tag">'+escHtml(t)+'</span>';}).join('')+'</div>':'')
    +'<div class="footer">PRINTED FROM MEADOS · '+new Date().toLocaleDateString()+'</div>'
    +'</div></body></html>');
  w.document.close();
  setTimeout(function(){w.print();},300);
}

// ==================== GIFT CARD MODE ====================
// A 6×9 cm printable card. Front: label artwork + brewer's compliments.
// Back: tasting notes, ABV, sweetness, food pairings, brew story.
function openGiftCardModal(batchId){
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b){toast('⚠ Batch not found');return;}
  var bot=APP.bottling[b.id]||{};
  var recipe=APP.recipes.find(function(r){return r.id===b.recipeId;});
  var ageDays=bot.date?Math.floor((new Date()-new Date(bot.date))/86400000):0;
  var pairings=suggestFoodPairings({sw:bot.sweetness,cat:recipe?recipe.category:'',abv:bot.abv});
  var snap={ag:ageDays};  // used below for the "30d aged" display
  var tastings=APP.tastings[b.id]||[];
  var notes=tastings.slice(-2).map(function(t){return t.note||t.notes||'';}).filter(Boolean).join(' / ').slice(0,200);
  var labelImg=getLabelImage(b.recipeId);
  // Unified overlay layer — respects per-recipe customizations
  var overlay=(typeof renderOverlayLayer==='function')
    ?renderOverlayLayer(recipe,b,bot.abv||'',{qr:false,bestDrink:false})
    :'';
  var brand=APP.settings.brewerName||'MeadOS';
  var brandLogo=(typeof getBrandLogoSrc==='function')?getBrandLogoSrc():'';
  if(!/^(data:|https?:|\/)/.test(brandLogo||''))brandLogo='';
  // Long brewery names overflow the 45mm text column at the fixed 11pt size —
  // scale type and tracking down with name length instead of clipping.
  var bnLen=brand.length;
  var brandFont=bnLen>26?'7.5pt':bnLen>18?'8.5pt':bnLen>12?'9.5pt':'11pt';
  var brandSpacing=bnLen>18?'1.5px':'3px';
  // Batch names also vary wildly in length — scale so 3-line wraps can't
  // push the gift message off the 60mm card.
  var batchFont=b.name.length>22?'10pt':b.name.length>14?'11.5pt':'14.5pt';

  var w=window.open('','_blank','width=700,height=900');
  if(!w){toast('⚠ Popup blocked');return;}
  // 6×9 cm card front+back side by side for double-sided printing
  var css='@page{size:landscape;margin:8mm}'
    +'*{box-sizing:border-box}'
    +'body{margin:0;padding:0;font-family:"EB Garamond",Georgia,serif;color:#2a1810;background:#fff;-webkit-print-color-adjust:exact;print-color-adjust:exact}'
    +'.controls{padding:14px;background:#222;color:#ddd;text-align:center;font-family:sans-serif;font-size:13px}'
    +'.controls button{margin:0 6px;padding:8px 16px;border:none;border-radius:4px;background:var(--gold);color:#000;font-weight:600;cursor:pointer}'
    +'.cards{display:flex;gap:6mm;flex-wrap:wrap;justify-content:center;padding:6mm}'
    +'.card{width:90mm;height:60mm;background:#fbf6e8;border:1px dashed #aaa;border-radius:3mm;overflow:hidden;display:flex;position:relative}'
    +'.front{flex-direction:row}.back{flex-direction:column;padding:5mm;position:relative;overflow:hidden}'
    +'.back .wm{position:absolute;inset:0;background-position:center;background-repeat:no-repeat;background-size:42mm;opacity:0.09;pointer-events:none}'
    +'.front .label-side{flex:1;display:flex;align-items:center;justify-content:center;padding:3mm;background:#fff;border-right:1px solid #e0d4b0}'
    +'.front .label-side svg,.front .label-side img{max-width:100%;max-height:100%}'
    +'.front .text-side{flex:1;display:flex;flex-direction:column;justify-content:flex-start;align-items:center;padding:2.4mm 3.5mm;text-align:center;background:linear-gradient(135deg,#f5ebd4,#fbf6e8);overflow:hidden}'
    +'.front .brand-name{font-family:"Cinzel",serif;font-size:11pt;color:#8a6a30;letter-spacing:3px;margin-bottom:0.8mm}'
    +'.front .batch-name{font-family:"Cinzel",serif;font-size:16pt;color:#3a2010;font-weight:700;margin-bottom:1mm;line-height:1.05}'
    +'.front .style{font-style:italic;font-size:8.5pt;color:#6a4a20;margin-bottom:1.2mm}'
    +'.front .meta{font-family:"Cinzel",serif;font-size:9pt;color:var(--gold);letter-spacing:2px}'
    +'.front .gift-msg{margin-top:auto;font-style:italic;font-size:6.5pt;color:#6a4a20;line-height:1.2;padding-top:1mm;border-top:1px solid #e0d4b0;width:100%}'
    +'.back .title{font-family:"Cinzel",serif;font-size:9pt;color:#8a6a30;letter-spacing:3px;text-align:center;border-bottom:1px solid var(--gold);padding-bottom:1.5mm;margin-bottom:2mm}'
    +'.back .stats{display:flex;justify-content:space-around;margin-bottom:2.5mm;font-size:9pt}'
    +'.back .stat-val{font-family:"Cinzel",serif;color:var(--gold);font-weight:700}'
    +'.back .stat-lbl{font-size:7pt;color:#6a4a20;letter-spacing:1.5px;text-transform:uppercase}'
    +'.back .notes{font-style:italic;font-size:8.5pt;color:#3a2010;line-height:1.3;margin-bottom:2.5mm;padding:2mm;background:rgba(201,168,76,0.08);border-radius:1mm}'
    +'.back .pairing-title{font-family:"Cinzel",serif;font-size:7.5pt;color:#8a6a30;letter-spacing:2px;text-transform:uppercase;margin-bottom:1mm}'
    +'.back .pairing-list{font-size:8.5pt;color:#3a2010;line-height:1.4;padding-left:4mm}'
    +'.back .pairing-list li{margin-bottom:0.5mm}'
    +'.back .footer{margin-top:auto;text-align:center;font-family:"Cinzel",serif;font-size:6pt;color:#8a6a30;letter-spacing:2px;padding-top:1.5mm;border-top:1px solid #e0d4b0}'
    +'@media print{.controls{display:none}}';
  var labelInnerHtml='';
  if(labelImg){
    labelInnerHtml='<svg viewBox="0 0 900 900" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid meet"><image href="'+labelImg+'" x="0" y="0" width="900" height="900"/>'
      +overlay
      +'</svg>';
  }
  w.document.write('<!DOCTYPE html><html><head><meta charset="utf-8"><title>'+escHtml(b.name)+' Gift Card</title>'
    +'<link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@500;700&family=EB+Garamond:ital@0;1&display=swap" rel="stylesheet">'
    +'<style>'+css+'</style></head><body>'
    +'<div class="controls">📄 Two cards per page (front + back). Print double-sided on cardstock, then cut along dashed lines. <button onclick="window.print()">Print</button> <button onclick="window.close()">Close</button></div>'
    +'<div class="cards">'
    +'<div class="card front">'
    +'<div class="label-side">'+labelInnerHtml+'</div>'
    +'<div class="text-side">'
    +(brandLogo?'<img src="'+brandLogo+'" style="height:8mm;max-width:24mm;object-fit:contain;margin-bottom:0.8mm;flex-shrink:0" alt="">':'')
    +'<div class="brand-name" style="font-size:'+brandFont+';letter-spacing:'+brandSpacing+';line-height:1.25">'+escHtml(brand.toUpperCase())+'</div>'
    +'<div style="color:var(--gold);font-size:6pt;letter-spacing:4px;margin-bottom:0.8mm">— ❦ —</div>'
    +'<div class="batch-name" style="font-size:'+batchFont+'">'+escHtml(b.name)+'</div>'
    +'<div class="style">'+escHtml(recipe?recipe.style:(b.style||'Mead'))+'</div>'
    +'<div class="meta">'+(bot.abv?bot.abv.toFixed(1)+'%':'?')+(bot.sweetness?' · '+escHtml(bot.sweetness):'')+(snap.ag?' · '+snap.ag+'d aged':'')+'</div>'
    +'<div class="gift-msg">Crafted with care — enjoy at your leisure.</div>'
    +'</div></div>'
    +'<div class="card back">'
    +(brandLogo?'<div class="wm" style="background-image:url('+brandLogo+')"></div>':'')
    +'<div class="title">❦&nbsp; ABOUT THIS MEAD &nbsp;❦</div>'
    +'<div class="stats">'
    +'<div><div class="stat-val">'+(bot.abv?bot.abv.toFixed(1)+'%':'?')+'</div><div class="stat-lbl">ABV</div></div>'
    +'<div><div class="stat-val">'+escHtml(bot.sweetness||'?')+'</div><div class="stat-lbl">Sweetness</div></div>'
    +'<div><div class="stat-val">'+(b.honeyType||'?').split(' ')[0]+'</div><div class="stat-lbl">Honey</div></div>'
    +'<div><div class="stat-val">'+(bot.date?bot.date.split('-')[0]:'?')+'</div><div class="stat-lbl">Vintage</div></div>'
    +'</div>'
    +(notes?'<div class="notes">"'+escHtml(notes)+'"</div>':'')
    +'<div class="pairing-title">Pairs well with</div>'
    +(pairings.length?'<ul class="pairing-list">'+pairings.slice(0,3).map(function(p){return'<li>'+escHtml(p)+'</li>';}).join('')+'</ul>':'<div style="font-size:8pt;color:#6a4a20;font-style:italic">Sip and enjoy on its own.</div>')
    +'<div class="footer" style="font-size:'+(bnLen>18?'5.5pt':'6pt')+';letter-spacing:'+(bnLen>18?'1px':'2px')+';white-space:normal;line-height:1.5">'+escHtml(brand.toUpperCase())+' · BOTTLED '+(bot.date?escHtml(bot.date):'')+'</div>'
    +'</div>'
    +'</div></body></html>');
  w.document.close();
}

// ==================== 3D BOTTLE PREVIEW ====================
// All-SVG render: realistic wine/mead bottle silhouette with multi-stop glass
// gradients and a label that wraps around the cylinder (clip-path with curved
// edges + cylinder-shadow overlay). Click to rotate 180° showing the back.

var _bottle3DAngle=-12;
function rotate3DBottle(){
  var el=document.getElementById('bottle-3d');
  if(!el)return;
  _bottle3DAngle+=180;
  el.style.transform='rotateY('+_bottle3DAngle+'deg)';
}

// ==================== FERMENTER CARD (PRINT) ====================
// A landscape A6-ish card to stick on or near the fermenter. Shows batch name,
// recipe, OG, milestone dates ("add nutrients", "rack", "expected end of
// fermentation", "ready to bottle window"), and a 2cm-wide handwriting strip
// for jotting hydrometer readings.
function printFermenterCard(batchId){
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b){toast('⚠ Batch not found');return;}
  var recipe=APP.recipes.find(function(r){return r.id===b.recipeId;});
  if(!recipe){toast('⚠ Recipe not found');return;}
  var startDate=b.startDate?new Date(b.startDate):new Date();
  function dateOffset(days){
    var d=new Date(startDate.getTime()+days*86400000);
    var dd=String(d.getDate()).padStart(2,'0');
    var months=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    return dd+' '+months[d.getMonth()]+' '+d.getFullYear();
  }
  // Build the milestone list from recipe.steps (skip the brew day itself)
  var milestones=(recipe.steps||[]).filter(function(s){return s.day>0;}).map(function(s){
    return{day:s.day,date:dateOffset(s.day),title:s.title,desc:s.desc};
  });
  var fermentEnd=recipe.fermentDays||42;
  var endOfFermentation=dateOffset(fermentEnd);
  var readyToBottleStart=dateOffset(fermentEnd-3);
  var readyToBottleEnd=dateOffset(fermentEnd+14);
  var color=recipe.brandColor||'#c9a84c';
  var brand=(APP.settings&&APP.settings.brewerName)||'MeadOS';

  var w=window.open('','_blank','width=1100,height=800');
  if(!w){toast('⚠ Popup blocked');return;}
  var css='@page{size:A4 landscape;margin:8mm}'
    +'body{margin:0;padding:0;font-family:Georgia,"Times New Roman",serif;color:#1a1208;background:#fff;-webkit-print-color-adjust:exact;print-color-adjust:exact}'
    // Use min-height so it always FILLS the page but never overflows. Padding
    // tightened from 12mm/14mm to 7mm/10mm so content fits the 281mm × 194mm
    // printable area without spilling onto page 2.
    +'.card{box-sizing:border-box;width:281mm;min-height:194mm;padding:7mm 10mm;display:grid;grid-template-columns:1fr 1.35fr;gap:10mm;border:1px solid #1a1208}'
    +'.header{grid-column:1/-1;border-bottom:2px solid '+color+';padding-bottom:5px;margin-bottom:4px;display:flex;justify-content:space-between;align-items:baseline}'
    +'.brewer{font-size:10px;letter-spacing:3px;color:#6a4a20;text-transform:uppercase}'
    +'.batch-name{font-family:"Times New Roman",serif;font-size:24px;font-weight:700;color:#1a1208;letter-spacing:0.5px;line-height:1.1}'
    +'.recipe-name{font-style:italic;color:'+color+';font-size:13px;margin-top:2px}'
    +'.section-title{font-size:10px;letter-spacing:2.5px;color:#8a6a30;text-transform:uppercase;border-bottom:1px solid #d0c094;padding-bottom:2px;margin:6px 0 4px;font-family:Georgia,serif}'
    +'.kv{display:flex;justify-content:space-between;font-size:11px;padding:2.5px 0;border-bottom:1px dotted #d8cca8}'
    +'.kv .k{color:#6a4a20}'
    +'.kv .v{font-weight:700;color:#1a1208;font-family:Menlo,monospace;font-size:11px}'
    +'.milestone{display:grid;grid-template-columns:34mm 1fr;gap:5px;padding:2.5px 0;border-bottom:1px dotted #d8cca8;font-size:10.5px;line-height:1.3}'
    +'.milestone .when{font-family:Menlo,monospace;font-size:10px;color:'+color+';font-weight:700;line-height:1.3}'
    +'.milestone .what{color:#1a1208;font-weight:600}'
    +'.milestone .what .desc{font-size:9.5px;color:#6a4a20;font-style:italic;margin-top:1px;line-height:1.35;font-weight:400}'
    +'.log-strip{margin-top:4px}'
    +'.log-strip table{width:100%;border-collapse:collapse}'
    +'.log-strip th{font-size:9.5px;color:#8a6a30;letter-spacing:1.5px;text-align:left;padding:3px 4px;border-bottom:1px solid #b0a070}'
    +'.log-strip td{border-bottom:1px solid #d8cca8;height:8mm;padding:0 4px}'
    +'.window-box{margin-top:5px;border:1.5px solid '+color+';padding:6px 8px;border-radius:3px;background:#fcf6e8}'
    +'.window-box .lbl{font-size:9.5px;letter-spacing:2px;color:#6a4a20;text-transform:uppercase;margin-bottom:2px}'
    +'.window-box .val{font-family:Menlo,monospace;font-size:11.5px;color:#1a1208;font-weight:700}'
    +'.print-btn{position:fixed;top:10px;right:10px;padding:8px 14px;background:'+color+';color:#fff;border:none;border-radius:3px;cursor:pointer;font-family:Georgia,serif;font-size:13px}'
    +'@media print{.print-btn{display:none}html,body{margin:0;padding:0}.card{border:1px solid #1a1208;page-break-inside:avoid;break-inside:avoid}}';

  var leftHtml=
    '<div class="section-title">Batch</div>'
    +'<div class="kv"><span class="k">Started</span><span class="v">'+dateOffset(0)+'</span></div>'
    +'<div class="kv"><span class="k">Volume</span><span class="v">'+(b.volume||recipe.volume)+' L</span></div>'
    +(b.og?'<div class="kv"><span class="k">OG</span><span class="v">'+b.og.toFixed(3)+'</span></div>':'<div class="kv"><span class="k">OG</span><span class="v">________</span></div>')
    +'<div class="kv"><span class="k">Target FG</span><span class="v">'+(recipe.fgTarget||'1.010').toString()+'</span></div>'
    +'<div class="kv"><span class="k">Target ABV</span><span class="v">~'+recipe.abvTarget+'%</span></div>'
    +(b.honeyType?'<div class="kv"><span class="k">Honey</span><span class="v">'+escHtml(b.honeyType)+'</span></div>':'')
    +(b.yeast?'<div class="kv"><span class="k">Yeast</span><span class="v">'+escHtml(b.yeast.toUpperCase())+'</span></div>':'')
    +'<div class="section-title" style="margin-top:8px">Hydrometer log</div>'
    +'<div class="log-strip"><table>'
    +'<tr><th style="width:30mm">Date</th><th style="width:18mm">SG</th><th style="width:14mm">°C</th><th>Notes</th></tr>'
    +'<tr><td></td><td></td><td></td><td></td></tr>'
    +'<tr><td></td><td></td><td></td><td></td></tr>'
    +'<tr><td></td><td></td><td></td><td></td></tr>'
    +'<tr><td></td><td></td><td></td><td></td></tr>'
    +'<tr><td></td><td></td><td></td><td></td></tr>'
    +'<tr><td></td><td></td><td></td><td></td></tr>'
    +'<tr><td></td><td></td><td></td><td></td></tr>'
    +'</table></div>';

  var rightHtml=
    '<div class="section-title">Milestones</div>'
    +(milestones.length?milestones.map(function(m){
      // A4 landscape has room for full descriptions
      return'<div class="milestone"><div class="when">Day '+m.day+'<br/><span style="color:#1a1208;font-weight:400">'+m.date+'</span></div><div class="what"><div>'+escHtml(m.title)+'</div>'+(m.desc?'<div class="desc">'+escHtml(m.desc)+'</div>':'')+'</div></div>';
    }).join(''):'<div style="font-size:11px;color:#6a4a20;font-style:italic">No milestones defined for this recipe.</div>')
    +'<div class="window-box">'
    +'<div class="lbl">Expected end of fermentation</div>'
    +'<div class="val">~ Day '+fermentEnd+' · '+endOfFermentation+'</div>'
    +'</div>'
    +'<div class="window-box" style="margin-top:6px">'
    +'<div class="lbl">Bottling window</div>'
    +'<div class="val">'+readyToBottleStart+' → '+readyToBottleEnd+'</div>'
    +'<div style="font-size:10px;color:#6a4a20;margin-top:3px;font-style:italic">Two identical SG readings 3-7 days apart = stable. Bottle then.</div>'
    +'</div>';

  var html='<!DOCTYPE html><html><head><meta charset="utf-8"><title>'+escHtml(b.name||'Mead')+' — Fermenter Card</title><style>'+css+'</style></head><body>'
    +'<button class="print-btn" onclick="window.print()">🖨 Print</button>'
    +'<div class="card">'
    +'<div class="header"><div><div class="brewer">'+escHtml(brand)+'</div><div class="batch-name">'+escHtml(b.name||'Mead')+'</div><div class="recipe-name">'+escHtml(recipe.name)+'</div></div><div style="font-family:Menlo,monospace;font-size:10px;color:#8a6a30;text-align:right">Card printed<br/>'+dateOffset(daysSince(b.startDate))+'</div></div>'
    +'<div>'+leftHtml+'</div>'
    +'<div>'+rightHtml+'</div>'
    +'</div></body></html>';

  w.document.write(html);
  w.document.close();
}
// ==================== SCHEMA VERSIONING ====================
// Current schema version. Bump when packageState/applyState changes shape.
var CURRENT_SCHEMA_VERSION=12;

var SCHEMA_MIGRATIONS={
  // v1 → v2: legacy locations as numbers → size-keyed maps
  2:function(d){
    if(d.bottling){
      Object.keys(d.bottling).forEach(function(bid){
        var bot=d.bottling[bid];
        if(!bot.locations)return;
        ['cellar','fridge','gifted','other'].forEach(function(loc){
          if(typeof bot.locations[loc]==='number'){
            var n=bot.locations[loc];
            bot.locations[loc]={};
            bot.locations[loc][750]=n;
          }
        });
      });
    }
    return d;
  },
  // v2 → v3: ensure countsAtBottling exists (immutable original counts)
  3:function(d){
    if(d.bottling){
      Object.keys(d.bottling).forEach(function(bid){
        var bot=d.bottling[bid];
        if(bot&&bot.locations&&!bot.countsAtBottling){
          bot.countsAtBottling={};
          ['cellar','fridge','gifted','other'].forEach(function(loc){
            var sizes=bot.locations[loc]||{};
            Object.keys(sizes).forEach(function(sz){
              bot.countsAtBottling[sz]=(bot.countsAtBottling[sz]||0)+(sizes[sz]||0);
            });
          });
        }
      });
    }
    return d;
  },
  // v3 → v4: add honeyType + yeast fields to batches (default missing values)
  4:function(d){
    if(d.batches){
      d.batches.forEach(function(b){
        if(!b.honeyType)b.honeyType='Wildflower';
        if(!b.yeast)b.yeast='m05';
      });
    }
    return d;
  },
  // v4 → v5: introduce gravityRaw separate from corrected gravity in logs
  5:function(d){
    // No-op migration — both keys are optional and old data is forward-compatible
    return d;
  },
  // v5 → v6: introduce fermenters as first-class entities. The user may have 1+
  // fermenters; existing batches with no fermenterId get assigned to f1
  // (the first/default fermenter). Settings.favoriteRecipes also normalized.
  6:function(d){
    if(!d.fermenters||!d.fermenters.length){
      d.fermenters=[
        {id:'f1',name:'Primary 1',capacity:9,notes:'9 L wide-mouth · primary fermentation',color:'#c9a84c',tempSensorEntity:''},
        {id:'f2',name:'Primary 2',capacity:9,notes:'9 L wide-mouth · primary fermentation',color:'#a87aa0',tempSensorEntity:''},
        {id:'f3',name:'Secondary 1',capacity:7.6,notes:'7.6 L wide-mouth · secondary / assist',color:'#7aa8c0',tempSensorEntity:''},
        {id:'f4',name:'Secondary 2',capacity:7.6,notes:'7.6 L wide-mouth · secondary / assist',color:'#7aa850',tempSensorEntity:''},
        {id:'f5',name:'Bulk Aging 1',capacity:5,notes:'5 L wide-mouth · secondary + bulk aging before bottling',color:'#c87850',tempSensorEntity:''},
        {id:'f6',name:'Bulk Aging 2',capacity:5,notes:'5 L wide-mouth · secondary + bulk aging before bottling',color:'#5a8a7a',tempSensorEntity:''}
      ];
    }
    if(d.batches){
      d.batches.forEach(function(b){
        if(!b.fermenterId)b.fermenterId='f1';
      });
    }
    if(!d.settings)d.settings={};
    if(!Array.isArray(d.settings.favoriteRecipes))d.settings.favoriteRecipes=[];
    return d;
  },
  // v6 → v7: photo journal feature removed. Strip b.photos arrays from any
  // existing batches to reclaim storage space (base64 JPEGs were ~80 KB each).
  // This is destructive — photo data is gone after migration runs. Intentional.
  7:function(d){
    if(d.batches){
      d.batches.forEach(function(b){
        if(b.photos)delete b.photos;
      });
    }
    return d;
  },
  // v7 → v8: human-readable batch serial numbers (e.g. 2024-001). Backfilled
  // onto every existing batch in chronological order, grouped by start-year.
  // Once assigned, a serial is sticky — never recomputed — so they're safe to
  // reference on printed storage labels, certificates, share URLs.
  8:function(d){
    if(!d.batches||!d.batches.length)return d;
    var byYear={};
    d.batches.forEach(function(b){
      var year=new Date(b.startDate||(new Date().toISOString().slice(0,10))).getFullYear();
      if(isNaN(year))year=new Date().getFullYear();
      if(!byYear[year])byYear[year]=[];
      byYear[year].push(b);
    });
    Object.keys(byYear).forEach(function(yr){
      var year=parseInt(yr,10);
      var maxExisting=0;
      var unassigned=[];
      byYear[yr].forEach(function(b){
        var m=b.serial&&/^(\d{4})-(\d{3,})$/.exec(String(b.serial));
        if(m&&parseInt(m[1],10)===year){
          var seq=parseInt(m[2],10);
          if(seq>maxExisting)maxExisting=seq;
        }else{
          unassigned.push(b);
        }
      });
      unassigned.sort(function(a,b){
        return((a.startDate||'')+'|'+(a.id||'')).localeCompare((b.startDate||'')+'|'+(b.id||''));
      });
      unassigned.forEach(function(b){
        maxExisting++;
        b.serial=year+'-'+String(maxExisting).padStart(3,'0');
      });
    });
    return d;
  },
  // v8 → v9: add time-capsule reservations and cellar sub-locations.
  // Time-capsule reservations: per-batch list of {count, openDate, reason}
  // marking bottles set aside for a specific future event. Counts against
  // bottlesOnHand but won't appear in normal drink/gift workflows.
  // Cellar sub-locations: free-text labels like "Shelf A box 3" that can be
  // assigned to bottles within the cellar location. Purely a label — no
  // structural change to the bottle count model.
  // Both fields are optional; missing values are treated as empty arrays.
  9:function(d){
    if(d.batches){
      d.batches.forEach(function(b){
        // No-op data initialization — the runtime code tolerates missing
        // fields, but explicitly seeding empty arrays makes the schema shape
        // visible in exports/backups.
        if(!Array.isArray(b.timeCapsules))b.timeCapsules=[];
      });
    }
    if(d.bottling){
      Object.keys(d.bottling).forEach(function(bid){
        var bot=d.bottling[bid];
        if(bot&&typeof bot==='object'&&!bot.cellarSublocation){
          bot.cellarSublocation='';
        }
      });
    }
    return d;
  },
  // v9 → v10: supplier rolodex. Tracks beekeepers and shops with notes,
  // honey specialties, contact info. Pure additive — existing data unaffected.
  10:function(d){
    if(!Array.isArray(d.suppliers))d.suppliers=[];
    return d;
  },
  // v10 → v11: Cellar as a first-class object. Previously the cellar was just
  // a sensor entity field on settings + free-text cellarSublocation on each
  // bottling record. Now there's a proper APP.cellar object with name, model,
  // both temp+humidity sensors, target band, and a structured shelves[] array.
  // The temp sensor entity gets migrated from settings.cellarTempSensorEntity
  // (the settings field is kept as a fallback for legacy code paths).
  // Existing bottling.cellarSublocation values are preserved as-is and shown
  // alongside the new shelf assignment.
  11:function(d){
    if(!d.cellar){
      d.cellar={
        name:'',
        model:'',
        location:'',
        capacity:0,
        tempSensorEntity:(d.settings&&d.settings.cellarTempSensorEntity)||'',
        humiditySensorEntity:'',
        targetTemp:13,
        targetTempMin:8,
        targetTempMax:18,
        targetHumidityMin:50,
        targetHumidityMax:75,
        shelves:[]
      };
    }
    return d;
  },
  // v11 → v12: Multi-cabinet cellar. The singleton `cellar` object becomes a
  // `cabinets` array so brewers can track several cabinets/fridges/racks in
  // different places. Shelf ids are globally unique, so existing
  // cellarShelfId references on batches/bottling/fermenters keep working.
  12:function(d){
    if(!Array.isArray(d.cabinets)){
      d.cabinets=[];
      var c=d.cellar;
      var hasContent=c&&(c.name||c.model||c.location||c.tempSensorEntity||c.humiditySensorEntity||(Array.isArray(c.shelves)&&c.shelves.length));
      if(hasContent){
        if(!c.id)c.id='cab-1';
        d.cabinets.push(c);
      }
    }
    delete d.cellar;
    return d;
  }
};

function migrateData(d){
  if(!d)return{result:d,steps:[]};
  var fromVersion=d.dataVersion||1;
  var steps=[];
  for(var v=fromVersion+1;v<=CURRENT_SCHEMA_VERSION;v++){
    var fn=SCHEMA_MIGRATIONS[v];
    if(fn){
      try{
        d=fn(d)||d;
        steps.push({from:v-1,to:v,ok:true});
      }catch(e){
        steps.push({from:v-1,to:v,ok:false,error:e.message});
      }
    }
  }
  d.dataVersion=CURRENT_SCHEMA_VERSION;
  return{result:d,steps:steps,fromVersion:fromVersion,toVersion:CURRENT_SCHEMA_VERSION};
}

function showMigrationReport(report){
  if(!report||!report.steps||!report.steps.length)return;
  if(report.fromVersion===report.toVersion)return;
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:540px">'
    +'<div class="modal-title">⚙ DATA MIGRATED</div>'
    +'<div style="font-size:13px;color:var(--text2);margin-bottom:12px">Your stored data was upgraded from schema <strong>v'+report.fromVersion+'</strong> to <strong>v'+report.toVersion+'</strong>. The original data is preserved; this is just a non-destructive reshape so newer features can read older batches.</div>'
    +'<div style="background:var(--bg3);padding:12px;border-radius:var(--radius);font-family:var(--font-mono);font-size:12px;line-height:1.8">'
    +report.steps.map(function(s){return'<div>'+(s.ok?'<span style="color:var(--green2)">✓</span>':'<span style="color:var(--red2)">✗</span>')+' v'+s.from+' → v'+s.to+(s.error?' <span style="color:var(--red2)">'+escHtml(s.error)+'</span>':'')+'</div>';}).join('')
    +'</div>'
    +'<div class="modal-actions"><button class="btn btn-primary" onclick="closeModal()">OK</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}

// ==================== STORAGE BUDGET ====================
// Computes a breakdown of the synced JSON payload so the user can see what's
// taking up space and how close they are to their mode's limit.
// Uploaded images (data: URLs) bloat the payload; media-source IDs are tiny.

function computeStorageBreakdown(){
  var pkg=(typeof packageState==='function')?packageState():null;
  if(!pkg)return null;
  var fullJson=JSON.stringify(pkg);
  var total=fullJson.length;
  // Compute the data: URL portion of customLabels + brandLogo (these are the
  // big-ticket items — full base64-encoded images).
  var labels=(pkg.sharedSettings&&pkg.sharedSettings.customLabels)||{};
  var dataLabelBytes=0,mediaLabelCount=0,urlLabelCount=0,dataLabelCount=0;
  Object.keys(labels).forEach(function(k){
    var v=labels[k]||'';
    if(typeof v!=='string')return;
    if(v.indexOf('data:')===0){dataLabelBytes+=v.length;dataLabelCount++;}
    else if(v.indexOf('media-source://')===0)mediaLabelCount++;
    else if(v.length>0)urlLabelCount++;
  });
  // Brand logo
  var brandLogo=(pkg.sharedSettings&&pkg.sharedSettings.brandLogo)||'';
  var brandLogoBytes=0,brandLogoKind='none';
  if(typeof brandLogo==='string'&&brandLogo){
    if(brandLogo.indexOf('data:')===0){brandLogoBytes=brandLogo.length;brandLogoKind='data';}
    else if(brandLogo.indexOf('media-source://')===0)brandLogoKind='media';
    else brandLogoKind='url';
  }
  // Limit — the SQLite server stores far more than this without complaint,
  // but the localStorage offline cache and page-load time degrade past a few
  // MB. 5 MB is a safe soft warning threshold.
  var mode='server';
  var limit=5*1024*1024;
  var limitNote='offline-cache soft limit';
  var imagesBytes=dataLabelBytes+brandLogoBytes;
  var coreBytes=total-imagesBytes;
  return{
    total:total,
    coreBytes:coreBytes,
    imagesBytes:imagesBytes,
    dataLabelBytes:dataLabelBytes,
    dataLabelCount:dataLabelCount,
    mediaLabelCount:mediaLabelCount,
    urlLabelCount:urlLabelCount,
    brandLogoBytes:brandLogoBytes,
    brandLogoKind:brandLogoKind,
    mode:mode,
    limit:limit,
    limitNote:limitNote,
    pct:Math.min(100,total/limit*100)
  };
}

function fmtBytes(n){
  if(n<1024)return n+' B';
  if(n<1024*1024)return(n/1024).toFixed(1)+' KB';
  return(n/1024/1024).toFixed(2)+' MB';
}

function renderStorageBudgetCard(){
  var b=computeStorageBreakdown();
  if(!b)return'';
  // Color zones based on % usage
  var barColor='var(--green2)',statusLabel='Healthy',statusColor='var(--green2)';
  if(b.pct>85){barColor='var(--red2)';statusLabel='Near limit';statusColor='var(--red2)';}
  else if(b.pct>60){barColor='var(--gold2)';statusLabel='Watch';statusColor='var(--gold2)';}
  // Breakdown rows
  var rows=[];
  rows.push({label:'Core data (batches, logs, supplies, etc.)',bytes:b.coreBytes,color:'var(--text2)'});
  if(b.dataLabelCount>0)rows.push({label:b.dataLabelCount+' uploaded label'+(b.dataLabelCount===1?'':'s')+' (data URLs)',bytes:b.dataLabelBytes,color:'var(--gold2)'});
  if(b.brandLogoBytes>0)rows.push({label:'Uploaded brand logo',bytes:b.brandLogoBytes,color:'var(--gold2)'});
  // Storage-free items get a separate informational note
  var freeItems=[];
  if(b.mediaLabelCount>0)freeItems.push(b.mediaLabelCount+' HA Media label'+(b.mediaLabelCount===1?'':'s'));
  if(b.urlLabelCount>0)freeItems.push(b.urlLabelCount+' URL-referenced label'+(b.urlLabelCount===1?'':'s'));
  if(b.brandLogoKind==='media')freeItems.push('brand logo (HA Media)');
  if(b.brandLogoKind==='url')freeItems.push('brand logo (URL)');
  // Recommendation
  var recommendation='';
  if(b.dataLabelCount>=3){
    recommendation='<div style="margin-top:10px;padding:10px;background:rgba(201,163,80,0.08);border-left:3px solid var(--gold);border-radius:3px;font-size:12px;color:var(--text2)">'
      +'<strong style="color:var(--gold2)">Tip:</strong> '+b.dataLabelCount+' uploaded labels are riding the synced blob ('+fmtBytes(b.dataLabelBytes)+'). For tighter syncs and easier backups, drop those PNGs into <code>/config/media/labels/</code> and re-pick them via the 🗂 HA Media tab. Media-source picks add ~60 bytes regardless of image size.'
      +'</div>';
  }else if(b.pct>85){
    recommendation='<div style="margin-top:10px;padding:10px;background:rgba(199,80,80,0.08);border-left:3px solid var(--red2);border-radius:3px;font-size:12px;color:var(--text2)">'
      +'<strong style="color:var(--red2)">Approaching capacity.</strong> Consider replacing uploaded labels with URL or HA-media references, or trimming old batches.'
      +'</div>';
  }
  return'<div class="card" style="margin-bottom:16px"><div class="card-header"><div class="card-title">📊 STORAGE BUDGET</div></div>'
    +'<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:8px">'
    +'<div style="font-family:var(--font-display);font-size:18px;color:var(--text)">'+fmtBytes(b.total)+'</div>'
    +'<div style="font-family:var(--font-mono);font-size:11px;color:'+statusColor+';letter-spacing:0.5px">'+statusLabel.toUpperCase()+' · '+b.pct.toFixed(1)+'%</div>'
    +'</div>'
    // Progress bar
    +'<div style="background:var(--bg4);border-radius:3px;overflow:hidden;height:8px;margin-bottom:6px">'
    +'<div style="background:'+barColor+';height:100%;width:'+b.pct.toFixed(1)+'%;transition:width 0.3s"></div>'
    +'</div>'
    +'<div style="font-family:var(--font-mono);font-size:11px;color:var(--text3);margin-bottom:14px">'
    +'of '+fmtBytes(b.limit)+' · '+escHtml(b.limitNote)
    +'</div>'
    // Breakdown table
    +(rows.length>0?'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px;margin-bottom:6px">BREAKDOWN</div>':'')
    +rows.map(function(r){
      return'<div style="display:flex;justify-content:space-between;padding:5px 0;font-size:12.5px;color:var(--text2);border-bottom:1px solid var(--bg4)">'
        +'<span style="color:'+r.color+'">'+escHtml(r.label)+'</span>'
        +'<span style="font-family:var(--font-mono);color:var(--text)">'+fmtBytes(r.bytes)+'</span>'
        +'</div>';
    }).join('')
    +(freeItems.length>0?'<div style="margin-top:10px;padding:8px 10px;background:var(--bg);border-radius:3px;font-size:11.5px;color:var(--text3);font-style:italic">'
      +'+ '+escHtml(freeItems.join(', '))+' — references only, no storage cost'
      +'</div>':'')
    +recommendation
    +'</div>';
}

// ==================== MODAL HANDLERS ====================
function closeModal(){var m=document.querySelector('.modal-overlay');if(m)m.remove();}

function openNewBatchModal(recipeId,scaledVol,opts){
  closeModal();
  opts=opts||{};
  // When deploying a planned batch, remember which plan to retire on success.
  // A plain new batch clears it so a stale id can't consume an unrelated plan.
  window._deployingPlanId=opts.plannedId||null;
  window._batchDangerOverride=false;
  window._lastBatchYeastCheck=null;
  var preselect=recipeId||(APP.recipes[0]&&APP.recipes[0].id);
  var recipeOpts=APP.recipes.map(function(r){return'<option value="'+r.id+'"'+(r.id===preselect?' selected':'')+'>'+escHtml(r.name)+' ('+r.style+')</option>';}).join('');
  var initial=APP.recipes.find(function(r){return r.id===preselect;})||APP.recipes[0];
  var volPrefSI=scaledVol||(initial?initial.volume:4.5);      // metric litres
  // Estimate honey amount from OG + volume (metric kg)
  var initialHoneyKg=initial?((initial.ogTarget-1)*1000*volPrefSI/292):0;
  var initialCost=APP.settings.honeyPricePerKg?(initialHoneyKg*APP.settings.honeyPricePerKg).toFixed(2):'';
  // Display values honour the chosen unit system (storage stays metric).
  var us=currentUnitSystem();
  var volPref=(volPrefSI/UNIT_VOL[us].toSI).toFixed(us==='metric'?2:3);
  var initialHoney=initialHoneyKg?(initialHoneyKg/UNIT_WT[us].toSI).toFixed(2):'';
  var unitBtns=['metric','us','imperial'].map(function(s){
    var lbl={metric:'Metric · L / kg',us:'US · gal / lb',imperial:'Imperial · gal / lb'}[s];
    var on=(s===us);
    return'<button type="button" id="nb-unit-'+s+'" onclick="onBatchUnitChange(\''+s+'\')" style="flex:1;padding:7px 4px;border-radius:var(--radius);cursor:pointer;font-family:var(--font-mono);font-size:10.5px;letter-spacing:0.3px;border:1px solid '+(on?'var(--gold)':'var(--border)')+';background:'+(on?'rgba(201,168,76,0.14)':'var(--bg3)')+';color:'+(on?'var(--gold2)':'var(--text3)')+'">'+lbl+'</button>';
  }).join('');
  // Fermenter picker — show all fermenters with availability badges
  var defaultFermId=defaultFermenterIdForNewBatch();
  var fermenterOpts=(APP.fermenters||[]).map(function(f){
    var occ=fermenterOccupiedBy(f.id);
    var label=f.name+(f.capacity?' ('+f.capacity+'L)':'');
    if(occ)label+=' — occupied by '+occ.name;
    else label+=' — free';
    return'<option value="'+f.id+'"'+(f.id===defaultFermId?' selected':'')+(occ?' style="color:#a07060"':'')+'>'+escHtml(label)+'</option>';
  }).join('');
  var fermenterRow=fermenterOpts?
    '<div class="form-group"><label class="form-label">Fermenter</label><select class="form-select" id="nb-fermenter">'+fermenterOpts+'</select><div style="font-size:11px;color:var(--text3);margin-top:4px;font-style:italic">Occupied fermenters can still be selected (e.g., if you bottle and re-pitch the same day).</div></div>':
    '';
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal"><div class="modal-title">⚗ NEW BATCH</div>'
    +'<div class="form-group"><label class="form-label">Choose Recipe</label><select class="form-select" id="nb-recipe" onchange="updateRecipeFields();updateYeastCompatibility()">'+recipeOpts+'</select></div>'
    +'<div class="form-group"><label class="form-label">Batch Name</label><input class="form-input" id="nb-name" placeholder="e.g., Spring Batch #1" value="'+escHtml((initial?initial.name:'Mead')+' #'+(APP.batches.length+1))+'"></div>'
    +'<div class="form-group"><label class="form-label">Units</label><div style="display:flex;gap:6px">'+unitBtns+'</div></div>'
    +fermenterRow
    +'<div class="form-row"><div class="form-group"><label class="form-label">Start Date</label><input class="form-input" id="nb-date" type="date" value="'+today()+'"></div>'
    +'<div class="form-group"><label class="form-label" id="nb-vol-label">Volume ('+UNIT_VOL[us].label+')</label><input class="form-input" id="nb-vol" type="number" step="0.1" value="'+volPref+'"></div></div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Target OG</label><input class="form-input" id="nb-og" type="number" step="0.001" value="'+(initial?initial.ogTarget:1.095)+'" onchange="updateYeastCompatibility()"></div>'
    +'<div class="form-group"><label class="form-label" id="nb-honey-label">Honey ('+UNIT_WT[us].label+')</label><input class="form-input" id="nb-honey" type="number" step="0.01" value="'+initialHoney+'"></div></div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Honey Type</label><select class="form-select" id="nb-honey-type" onchange="updateYeastCompatibility()">'
    +(function(){
      // Build two-group dropdown: honeys you actually have in supplies first,
      // then every other variety. Quantities and units shown for stocked ones
      // so the user picks "what's available" rather than "what's nice in theory".
      var honeySupplies=(APP.supplies||[]).filter(function(s){return s.type==='honey'&&parseFloat(s.qty)>0;});
      // Match each supply to a canonical HONEY_TYPES entry by substring; track which canonical names are stocked
      var stockedCanonical={};
      var inStockOptions=honeySupplies.map(function(s){
        var name=String(s.name||'').trim();
        var canonical=HONEY_TYPES.find(function(t){
          var lt=t.toLowerCase(),ln=name.toLowerCase();
          return ln.indexOf(lt)!==-1||lt.indexOf(ln)!==-1;
        });
        var displayValue=canonical||name;
        if(canonical)stockedCanonical[canonical]=true;
        var qtyLabel=(parseFloat(s.qty)||0)+' '+(s.unit||'');
        var brandSuffix=s.brand?' · '+s.brand:'';
        return'<option value="'+escHtml(displayValue)+'">'+escHtml(name)+' ('+qtyLabel+brandSuffix+')</option>';
      }).join('');
      var otherOptions=HONEY_TYPES.filter(function(t){return!stockedCanonical[t];})
        .map(function(t){return'<option value="'+escHtml(t)+'"'+(t==='Wildflower'&&!inStockOptions?' selected':'')+'>'+escHtml(t)+'</option>';}).join('');
      // If user has stocked honeys, default-select the first one
      if(inStockOptions){
        return'<optgroup label="🟢 In your supplies">'+inStockOptions+'</optgroup>'
          +'<optgroup label="Other varieties (not stocked)">'+otherOptions+'</optgroup>';
      }
      return otherOptions;
    }())
    +'</select></div>'
    +'<div class="form-group"><label class="form-label">Yeast Strain</label><select class="form-select" id="nb-yeast" onchange="updateYeastCompatibility()">'
    +(function(){
      // Same treatment for yeast — show what you have first
      var yeastSupplies=(APP.supplies||[]).filter(function(s){return s.type==='yeast'&&parseFloat(s.qty)>0;});
      var stockedStrains={};
      var inStockOptions=yeastSupplies.map(function(s){
        var name=String(s.name||'').trim();
        var strain=YEAST_STRAINS.find(function(y){
          var ln=name.toLowerCase(),lyn=y.name.toLowerCase(),lyid=y.id.toLowerCase();
          return ln.indexOf(lyid)!==-1||ln.indexOf(lyn.split(' ').pop().toLowerCase())!==-1;
        });
        var value=strain?strain.id:'m05';
        if(strain)stockedStrains[strain.id]=true;
        var qtyLabel=(parseFloat(s.qty)||0)+' '+(s.unit||'');
        return'<option value="'+escHtml(value)+'">'+escHtml(name)+' ('+qtyLabel+')</option>';
      }).join('');
      var otherOptions=YEAST_STRAINS.filter(function(y){return!stockedStrains[y.id];})
        .map(function(y){return'<option value="'+escHtml(y.id)+'"'+(y.id==='m05'&&!inStockOptions?' selected':'')+'>'+escHtml(y.name)+'</option>';}).join('');
      if(inStockOptions){
        return'<optgroup label="🟢 In your supplies">'+inStockOptions+'</optgroup>'
          +'<optgroup label="Other strains (not stocked)">'+otherOptions+'</optgroup>';
      }
      return otherOptions;
    }())
    +'</select>'
    +'<div id="nb-yeast-check" style="margin-top:8px"></div>'
    +'</div></div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Nutrient Product</label><select class="form-select" id="nb-nutrient" onchange="onNutrientChange()">'
    +(function(){
      // Group: nutrients you have in supplies (matched by product name) first,
      // then the rest. Selection sets batch.nutrient which drives the protocol
      // (Fermaid-O → TOSNA, everything else → SNA).
      var nutSupplies=(APP.supplies||[]).filter(function(s){return s.type==='nutrient'&&parseFloat(s.qty)>0;});
      var stockedProducts={};
      var inStockOptions=nutSupplies.map(function(s){
        var name=String(s.name||'').trim();
        var product=NUTRIENT_PRODUCTS.find(function(p){
          var ln=name.toLowerCase(),lpn=p.name.toLowerCase();
          // Match by full name or by salient keyword
          return ln.indexOf(lpn)!==-1||lpn.indexOf(ln)!==-1||
            (p.id==='mj-mead'&&/mangrove|mead\s*yeast\s*nutrient/i.test(name))||
            (p.id==='fermaid-o'&&/fermaid-?o/i.test(name))||
            (p.id==='fermaid-k'&&/fermaid-?k/i.test(name))||
            (p.id==='vinoferm-nutrivit'&&/nutrivit/i.test(name))||
            (p.id==='vinoferm-nutrisal'&&/nutrisal/i.test(name))||
            (p.id==='goferm'&&/go-?ferm/i.test(name))||
            (p.id==='generic-dap'&&/^dap$|diammonium/i.test(name));
        });
        var value=product?product.id:'other';
        if(product)stockedProducts[product.id]=true;
        var qtyLabel=(parseFloat(s.qty)||0)+' '+(s.unit||'');
        var protocolTag=product?' ['+(product.protocol==='tosna'?'TOSNA':product.protocol==='goferm'?'rehydration':'SNA')+']':'';
        return'<option value="'+escHtml(value)+'">'+escHtml(name)+' ('+qtyLabel+')'+protocolTag+'</option>';
      }).join('');
      var otherOptions=NUTRIENT_PRODUCTS.filter(function(p){return!stockedProducts[p.id];})
        .map(function(p){var tag=' ['+(p.protocol==='tosna'?'TOSNA':p.protocol==='goferm'?'rehydration':'SNA')+']';return'<option value="'+escHtml(p.id)+'"'+(p.id==='mj-mead'&&!inStockOptions?' selected':'')+'>'+escHtml(p.name)+tag+'</option>';}).join('');
      if(inStockOptions){
        return'<optgroup label="🟢 In your supplies">'+inStockOptions+'</optgroup>'
          +'<optgroup label="Other products (not stocked)">'+otherOptions+'</optgroup>';
      }
      return otherOptions;
    }())
    +'</select>'
    +'<div id="nb-nutrient-hint" style="font-size:11px;color:var(--text3);margin-top:4px;font-style:italic"></div>'
    +'</div>'
    +'<div class="form-group"><label class="form-label">Nutrient schedule</label><select class="form-select" id="nb-protocol" onchange="onNutrientChange()">'
    +'<option value="auto" selected>Auto — match the nutrient</option>'
    +'<option value="tosca2">TOSCA 2.0 — organic, GoFerm + 24/48/72h + 1/3 break</option>'
    +'<option value="tosna2">TOSNA (classic) — organic, GoFerm + 24/48/72/96h</option>'
    +'<option value="tiosna">TiOSNA — organic, GoFerm + pitch/24/48h + 1/3 break</option>'
    +'<option value="sna">SNA — standard (2 doses, days 1 &amp; 3)</option>'
    +'<option value="sna-high">SNA — high-gravity (3 doses, days 1/3/7)</option>'
    +'</select></div></div>'
    +'<div id="nb-protocol-warn"></div>'
    +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1.5px;margin:14px 0 8px;text-transform:uppercase">Cost Tracking (optional)</div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Honey Cost ('+(APP.settings.currency||'€')+')</label><input class="form-input" id="nb-cost-honey" type="number" step="0.01" value="'+initialCost+'" placeholder="e.g. 18.00"></div>'
    +'<div class="form-group"><label class="form-label">Extras Cost ('+(APP.settings.currency||'€')+')</label><input class="form-input" id="nb-cost-extras" type="number" step="0.01" placeholder="fruit, spices, etc."></div></div>'
    +'<div class="form-group"><label class="form-label">Notes (optional)</label><textarea class="form-textarea" id="nb-notes" placeholder="Honey source, intentions, anything worth remembering…"></textarea></div>'
    +'<div class="modal-actions"><button class="btn btn-secondary" onclick="closeModal()">Cancel</button><button class="btn btn-primary" onclick="createBatch()">Create Batch</button></div></div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
  // Deploy pre-fills: when launched from a planned batch, seed the target
  // vessel, brew date, and notes so the brewer just confirms.
  if(opts.fermenterId){var fe=document.getElementById('nb-fermenter');if(fe)fe.value=opts.fermenterId;}
  if(opts.startDate){var de=document.getElementById('nb-date');if(de)de.value=opts.startDate;}
  if(opts.notes){var ne=document.getElementById('nb-notes');if(ne)ne.value=opts.notes;}
  // Deploy from a plan also seeds the chosen yeast / nutrient / honey type.
  if(opts.yeast){var ye=document.getElementById('nb-yeast');if(ye){ye.value=opts.yeast;if(typeof updateYeastCompatibility==='function')updateYeastCompatibility();}}
  if(opts.nutrient){var nu=document.getElementById('nb-nutrient');if(nu){nu.value=opts.nutrient;if(typeof onNutrientChange==='function')onNutrientChange();}}
  if(opts.honeyType){var ht=document.getElementById('nb-honey-type');if(ht)ht.value=opts.honeyType;}
  if(typeof onNutrientChange==='function')onNutrientChange();
  if(typeof updateYeastCompatibility==='function')updateYeastCompatibility();
}

// Read the new-batch form's yeast + recipe + OG fields and render a coloured
// compatibility panel below the yeast dropdown. Severity drives:
//   - the visible banner colour/icon
//   - whether createBatch() will gate behind a confirmation
// The check is non-modal — the user sees feedback as they pick options.
function updateYeastCompatibility(){
  var box=document.getElementById('nb-yeast-check');
  if(!box)return;
  var yeastEl=document.getElementById('nb-yeast');
  var recipeEl=document.getElementById('nb-recipe');
  var ogEl=document.getElementById('nb-og');
  if(!yeastEl||!recipeEl)return;
  var yeastId=yeastEl.value;
  var recipeId=recipeEl.value;
  var recipe=APP.recipes.find(function(r){return r.id===recipeId;});
  if(!recipe){box.innerHTML='';return;}
  // Override recipe's OG/ABV target with the user's chosen OG (so a high-OG
  // pick triggers ABV warnings even if the recipe normally targets less).
  var liveRecipe=Object.assign({},recipe);
  if(ogEl){
    var og=parseFloat(ogEl.value);
    if(og>1){
      liveRecipe.ogTarget=og;
      // Re-derive ABV target if recipe declared a finishing gravity
      if(recipe.fgTarget){
        liveRecipe.abvTarget=parseFloat(((og-recipe.fgTarget)*131.25).toFixed(1));
      }
    }
  }
  var result=evaluateYeastForRecipe(yeastId,liveRecipe);
  // Fructose-stall alert: a high/critical-fructose honey paired
  // with a non-fructophilic yeast stalls at the 1/3 break. Uses the honey's
  // F:G tech data + the strain's fructophilic flag.
  (function(){
    var honeyEl=document.getElementById('nb-honey-type');
    var honey=honeyEl&&HONEY_PROFILES[honeyEl.value];
    var tech=honey&&honey.tech;
    var y=getYeastById(yeastId);
    if(!tech||!y||y.fructophilic)return;
    var rank={recommended:0,good:1,caveat:2,warning:3,danger:4};
    var yn=y.name.split('—')[0].trim();
    if(tech.fructoseRisk==='critical'){
      result.messages.push({tone:'danger',text:honeyEl.value+' is critically fructose-dominant (F:G ~'+(tech.fgRatio||'?')+') and '+yn+' is not fructophilic — it will likely stall at the 1/3 sugar break. Use a fructophilic strain: K1-V1116, Fermentis BC-S103, or UVAFERM 43.'});
      if(rank[result.severity]<rank.danger)result.severity='danger';
    }else if(tech.fructoseRisk==='high'){
      result.messages.push({tone:'caveat',text:honeyEl.value+' is high-fructose (F:G ~'+(tech.fgRatio||'?')+') and '+yn+' isn\'t fructophilic — watch gravity closely near the 1/3 break, or switch to a fructophilic strain to be safe.'});
      if(rank[result.severity]<rank.caveat)result.severity='caveat';
    }
  })();
  var conf={
    recommended:{bg:'rgba(122,160,64,0.15)',border:'var(--green2)',icon:'✓',label:'RECOMMENDED',textColor:'var(--green2)'},
    good:{bg:'rgba(201,163,80,0.10)',border:'var(--gold2)',icon:'•',label:'ACCEPTABLE',textColor:'var(--gold2)'},
    caveat:{bg:'rgba(214,165,67,0.14)',border:'#d6a543',icon:'⚠',label:'CAVEAT',textColor:'#d6a543'},
    warning:{bg:'rgba(218,108,52,0.16)',border:'#da6c34',icon:'⚠',label:'NOT RECOMMENDED',textColor:'#da6c34'},
    danger:{bg:'rgba(200,60,60,0.18)',border:'var(--red2)',icon:'⛔',label:'WILL FAIL',textColor:'var(--red2)'}
  };
  var c=conf[result.severity]||conf.good;
  // Cache the result so createBatch() can read it without re-computing
  window._lastBatchYeastCheck={severity:result.severity,yeastId:yeastId,recipeId:recipeId,messages:result.messages};
  box.innerHTML='<div style="background:'+c.bg+';border:1px solid '+c.border+'66;border-left:3px solid '+c.border+';border-radius:var(--radius);padding:9px 12px;font-size:12.5px;line-height:1.55">'
    +'<div style="display:flex;align-items:center;gap:8px;margin-bottom:'+(result.messages.length>1?'6px':'0')+'">'
      +'<span style="color:'+c.textColor+';font-size:14px">'+c.icon+'</span>'
      +'<span style="font-family:var(--font-mono);font-size:10px;color:'+c.textColor+';letter-spacing:1.5px;font-weight:bold">'+c.label+'</span>'
      +'<span style="color:var(--text3);font-family:var(--font-mono);font-size:9.5px;letter-spacing:1px;margin-left:auto">'+escHtml(result.yeast.name.split('—')[0].trim())+' × '+escHtml(recipe.style||recipe.name)+'</span>'
    +'</div>'
    +result.messages.map(function(m){
      var mc=conf[m.tone]||c;
      return '<div style="color:var(--text2);padding:'+(result.messages.length>1?'4px 0':'2px 0')+';'+(result.messages.length>1?'border-top:1px dotted var(--border);':'')+'">'+(result.messages.length>1?'<span style="color:'+mc.textColor+';font-family:var(--font-mono);font-size:9.5px;margin-right:6px">'+(m.tone||'').toUpperCase()+'</span>':'')+escHtml(m.text)+'</div>';
    }).join('')
  +'</div>';
}

// Updates the helper hint below the nutrient dropdown to show the protocol
// description for the currently-selected product. Fires on change AND once on
// modal open so the first selection's hint is populated.
function onNutrientChange(){
  var sel=document.getElementById('nb-nutrient');
  var hint=document.getElementById('nb-nutrient-hint');
  if(!sel||!hint)return;
  var product=getNutrientById(sel.value);
  if(!product)return;
  var protocolName=product.protocol==='tosna'?'TOSNA':(product.protocol==='goferm'?'Rehydration only':'SNA');
  var color=product.protocol==='tosna'?'var(--green2)':(product.protocol==='goferm'?'var(--blue2)':'var(--gold2)');
  hint.innerHTML='<span style="color:'+color+';font-family:var(--font-mono);font-size:10px;letter-spacing:1px">→ '+protocolName+'</span> · '+escHtml(product.notes||'');
  // Dummy-proof compatibility check between the chosen schedule and nutrient.
  var protoSel=document.getElementById('nb-protocol');
  var warnEl=document.getElementById('nb-protocol-warn');
  if(protoSel&&warnEl){
    var chosen=protoSel.value;            // auto | tosca2 | tosna2 | tiosna | sna | sna-high
    var isOrganicProtocol=(chosen==='tosca2'||chosen==='tosna2'||chosen==='tiosna');
    var isOrganic=(product.id==='fermaid-o');
    var w='';
    if(isOrganicProtocol&&!isOrganic){
      w='<div style="margin:4px 0 12px;padding:10px 12px;border-radius:var(--radius);border-left:4px solid var(--red2);background:rgba(176,58,46,0.09);font-size:12px;color:var(--text2);line-height:1.55">'
        +'<strong style="color:var(--red2)">⛔ '+escHtml(product.name)+' isn\'t an organic (TOSCA/TOSNA) nutrient.</strong> These protocols are organic-only — they need <strong>Fermaid-O</strong>. '+(product.id==='mj-mead'?'The MJ/M05 sachet is a pre-blended SNA product; ':(/dap/i.test(product.id)||product.protocol==='sna'?'This product contains DAP; ':''))+'either switch the nutrient to Fermaid-O, or pick an <strong>SNA</strong> schedule above.</div>';
    }else if((chosen==='sna'||chosen==='sna-high')&&isOrganic){
      w='<div style="margin:4px 0 12px;padding:10px 12px;border-radius:var(--radius);border-left:4px solid #e0843c;background:rgba(224,132,60,0.08);font-size:12px;color:var(--text2);line-height:1.55">'
        +'<strong style="color:#e0843c">⚠ Fermaid-O on an SNA schedule.</strong> Fermaid-O is organic and is normally run as <strong>TOSCA 2.0 / TOSNA</strong> (staggered doses to the 1/3 break) for the cleanest result. SNA still works, but consider switching the schedule.</div>';
    }
    warnEl.innerHTML=w;
  }
}

// Convert the open new-batch modal's volume/honey fields between unit systems
// in place (no re-render, so other fields are preserved) and persist the
// preference. Storage stays metric; this is presentation only.
function onBatchUnitChange(sys){
  if(sys!=='metric'&&sys!=='us'&&sys!=='imperial')return;
  var old=currentUnitSystem();
  var volEl=document.getElementById('nb-vol'),honeyEl=document.getElementById('nb-honey');
  if(volEl&&volEl.value!==''){
    var si=parseFloat(volEl.value)*UNIT_VOL[old].toSI;
    volEl.value=(si/UNIT_VOL[sys].toSI).toFixed(sys==='metric'?2:3);
  }
  if(honeyEl&&honeyEl.value!==''){
    var sik=parseFloat(honeyEl.value)*UNIT_WT[old].toSI;
    honeyEl.value=(sik/UNIT_WT[sys].toSI).toFixed(2);
  }
  APP.settings.unitSystem=sys;
  if(typeof saveSettings==='function')saveSettings();
  var vl=document.getElementById('nb-vol-label');if(vl)vl.textContent='Volume ('+UNIT_VOL[sys].label+')';
  var hl=document.getElementById('nb-honey-label');if(hl)hl.textContent='Honey ('+UNIT_WT[sys].label+')';
  ['metric','us','imperial'].forEach(function(s){
    var b=document.getElementById('nb-unit-'+s);if(!b)return;var on=(s===sys);
    b.style.border='1px solid '+(on?'var(--gold)':'var(--border)');
    b.style.background=on?'rgba(201,168,76,0.14)':'var(--bg3)';
    b.style.color=on?'var(--gold2)':'var(--text3)';
  });
}

function updateRecipeFields(){
  var id=document.getElementById('nb-recipe').value;
  var r=APP.recipes.find(function(x){return x.id===id;});
  if(!r)return;
  var us=currentUnitSystem();
  document.getElementById('nb-name').value=r.name+' #'+(APP.batches.length+1);
  // r.volume is metric litres; convert to the displayed unit.
  document.getElementById('nb-vol').value=(r.volume/UNIT_VOL[us].toSI).toFixed(us==='metric'?2:3);
  document.getElementById('nb-og').value=r.ogTarget;
  var honeyKg=((r.ogTarget-1)*1000*r.volume/292);      // metric kg
  document.getElementById('nb-honey').value=(honeyKg/UNIT_WT[us].toSI).toFixed(2);
  if(APP.settings.honeyPricePerKg){
    // Cost is always computed from the metric kg, regardless of display unit.
    document.getElementById('nb-cost-honey').value=(honeyKg*APP.settings.honeyPricePerKg).toFixed(2);
  }
}

function createBatch(){
  var name=document.getElementById('nb-name').value.trim();
  if(!name){toast('⚠ Name required');return;}
  // Compatibility gate — if the live check flagged danger (yeast can't reach the
  // recipe's target ABV, ferment temp out of yeast range, etc.), make the user
  // explicitly confirm. This is the "stop me from ruining a batch" guard rail.
  var check=window._lastBatchYeastCheck;
  if(check&&check.severity==='danger'&&!window._batchDangerOverride){
    var msgList=(check.messages||[]).map(function(m){return'• '+m.text;}).join('\n');
    var ok=confirm('⛔ This yeast/recipe combination will likely fail:\n\n'+msgList+'\n\nContinue anyway? (Tip: pick a different yeast from the dropdown — see the Yeast Library for guidance.)');
    if(!ok)return;
    window._batchDangerOverride=true; // skip prompt on retry within same modal session
  }
  var costHoney=parseFloat(document.getElementById('nb-cost-honey').value)||0;
  var costExtras=parseFloat(document.getElementById('nb-cost-extras').value)||0;
  var fermenterSel=document.getElementById('nb-fermenter');
  var startDate=document.getElementById('nb-date').value||today();
  // Volume/honey are entered in the user's chosen unit — convert back to the
  // metric values MeadOS stores and calculates with everywhere else.
  var volIn=parseFloat(document.getElementById('nb-vol').value);
  var honeyIn=parseFloat(document.getElementById('nb-honey').value);
  var volumeSI=(!isNaN(volIn)?volIn*UNIT_VOL[currentUnitSystem()].toSI:4.5);
  var honeySI=(!isNaN(honeyIn)?honeyIn*UNIT_WT[currentUnitSystem()].toSI:null);
  var protoSel=(document.getElementById('nb-protocol')||{}).value||'auto';
  var b={
    id:genId(),
    // Human-readable batch serial number — YEAR-NNN, sequenced per calendar
    // year of the batch's startDate. Stable from creation, unique even when
    // names collide (e.g. several "Traditional Mead" boxes side by side).
    // The internal id stays the random hex string for technical references;
    // the serial is what you see on labels, in the UI, and in search.
    serial:assignBatchSerial(startDate),
    name:name,
    recipeId:document.getElementById('nb-recipe').value,
    startDate:startDate,
    volume:Math.round(volumeSI*1000)/1000,
    og:parseFloat(document.getElementById('nb-og').value)||1.095,
    honey:honeySI!=null?Math.round(honeySI*1000)/1000:null,
    honeyType:(document.getElementById('nb-honey-type')||{}).value||'Wildflower',
    yeast:(document.getElementById('nb-yeast')||{}).value||'m05',
    nutrient:(document.getElementById('nb-nutrient')||{}).value||'mj-mead',
    // Nutrient schedule the batch follows: 'auto' defers to the nutrient's own
    // protocol; otherwise an explicit tosna2 / sna / sna-high choice.
    nutrientProtocol:(protoSel!=='auto'?protoSel:undefined),
    fermenterId:(fermenterSel&&fermenterSel.value)||defaultFermenterIdForNewBatch(),
    cost:(costHoney||costExtras)?{honey:costHoney,extras:costExtras}:null,
    notes:document.getElementById('nb-notes').value.trim()
  };
  var r=APP.recipes.find(function(x){return x.id===b.recipeId;});
  if(r)b.style=r.style;
  APP.batches.push(b);
  APP.logs[b.id]=[];
  // If this batch was deployed from the brew plan, retire that plan entry now
  // that it's a real, supply-deducting batch.
  if(window._deployingPlanId){
    APP.plannedBatches=(APP.plannedBatches||[]).filter(function(p){return p.id!==window._deployingPlanId;});
    window._deployingPlanId=null;
  }
  // Auto-deduct supplies (honey, yeast, nutrient). Returns array of
  // {supply, amount, unit, before, after, insufficient}. Build a summary
  // line for the toast so the user sees what got debited.
  var deductions=(typeof deductSuppliesForBatch==='function')?deductSuppliesForBatch(b,r):[];
  closeModal();
  scheduleSave();
  if(deductions.length){
    var anyInsufficient=deductions.some(function(d){return d.insufficient;});
    var summary=deductions.map(function(d){
      // Round display amount for readability
      var amt=d.amount;
      var amtStr=(Math.abs(amt-Math.round(amt))<0.01)?String(Math.round(amt)):String(parseFloat(amt.toFixed(2)));
      return amtStr+' '+(d.unit||'')+' '+(d.supply.name||'').replace(/\s*honey\s*$/i,'');
    }).join(' · ');
    toast('✦ Batch created '+(anyInsufficient?'⚠ ':'· ')+'deducted: '+summary,5000);
  }else{
    toast('✦ Batch created');
  }
  showView('batch',b.id);
}

// ==================== RACKING (move batch to different vessel) ====================
// Opens a modal letting the user pick a target vessel and a racking date.
// Saves to b.rackings[] and updates b.fermenterId. The Fermenter Schedule
// then renders the batch as separate segments across the relevant vessels.
function openRackModal(batchId){
  closeModal();
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b){toast('⚠ Batch not found');return;}
  var currentVessel=getFermenter(b.fermenterId);
  if(!APP.fermenters||APP.fermenters.length<2){
    toast('⚠ Add a second fermenter first');showView('settings');return;
  }
  // Build options excluding current vessel, annotating each with occupancy
  var opts=APP.fermenters.filter(function(f){return f.id!==b.fermenterId;}).map(function(f){
    var occ=fermenterOccupiedBy(f.id);
    var label=f.name+(f.capacity?' ('+f.capacity+'L)':'')+(occ?' — currently has '+occ.name:' — free');
    return'<option value="'+f.id+'"'+(occ?' style="color:#a07060"':'')+'>'+escHtml(label)+'</option>';
  }).join('');
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal">'
    +'<div class="modal-title">🔁 RACK '+escHtml(b.name)+' TO NEW VESSEL</div>'
    +'<div style="font-size:13px;color:var(--text2);margin-bottom:12px">Currently in: <strong style="color:'+(currentVessel&&currentVessel.color||'var(--gold2)')+'">'+escHtml(currentVessel?currentVessel.name:'(unassigned)')+'</strong>. This records the move on the Fermenter Schedule and frees up the current vessel for new batches.</div>'
    +'<div class="form-group"><label class="form-label">Rack To</label><select class="form-select" id="rack-target">'+opts+'</select></div>'
    +'<div class="form-group"><label class="form-label">Racking Date</label><input class="form-input" id="rack-date" type="date" value="'+today()+'"></div>'
    +'<div class="form-group"><label class="form-label">Notes (optional)</label><textarea class="form-textarea" id="rack-notes" placeholder="e.g. left lees behind, added 0.5g K-meta, gravity 1.012"></textarea></div>'
    +'<div class="modal-actions"><button class="btn btn-secondary" onclick="closeModal()">Cancel</button><button class="btn btn-primary" onclick="saveRack(\''+batchId+'\')">Rack Batch</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}

function saveRack(batchId){
  var target=document.getElementById('rack-target').value;
  var date=document.getElementById('rack-date').value||today();
  var notes=document.getElementById('rack-notes').value.trim();
  if(rackBatch(batchId,target,date,notes)){
    closeModal();
    toast('✦ Racked to new vessel');
    renderMain();
  }
}

function openEditBatchModal(id){
  closeModal();
  var b=APP.batches.find(function(x){return x.id===id;});
  if(!b)return;
  var cost=b.cost||{};
  var fermenterOpts=(APP.fermenters||[]).map(function(f){
    return'<option value="'+f.id+'"'+(f.id===b.fermenterId?' selected':'')+'>'+escHtml(f.name+(f.capacity?' ('+f.capacity+'L)':''))+'</option>';
  }).join('');
  var fermenterRow=fermenterOpts?'<div class="form-group"><label class="form-label">Fermenter</label><select class="form-select" id="eb-fermenter">'+fermenterOpts+'</select></div>':'';
  // Honey type — datalist with all known varieties (free-text still allowed
  // for custom additions). Defaults to whatever was stored on the batch.
  var honeyDatalist=(typeof HONEY_TYPES!=='undefined'&&HONEY_TYPES.length)
    ?'<datalist id="eb-honey-types">'+HONEY_TYPES.map(function(h){return'<option value="'+escHtml(h)+'"></option>';}).join('')+'</datalist>':'';
  // Yeast strain — dropdown of known strains plus the raw value (for legacy
  // data that may not match any known id).
  var currentYeast=b.yeast||'m05';
  var yeastOpts='';
  if(typeof YEAST_STRAINS!=='undefined'&&YEAST_STRAINS.length){
    var found=false;
    yeastOpts=YEAST_STRAINS.map(function(y){
      var sel=(y.id===currentYeast);
      if(sel)found=true;
      return'<option value="'+y.id+'"'+(sel?' selected':'')+'>'+escHtml(y.name)+'</option>';
    }).join('');
    if(!found&&currentYeast){
      yeastOpts='<option value="'+escHtml(currentYeast)+'" selected>'+escHtml(currentYeast)+' (custom)</option>'+yeastOpts;
    }
  }
  var yeastRow=yeastOpts?'<div class="form-group"><label class="form-label">Yeast</label><select class="form-select" id="eb-yeast">'+yeastOpts+'</select></div>':'';
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal"><div class="modal-title">EDIT BATCH</div>'
    +'<div class="form-group"><label class="form-label">Name</label><input class="form-input" id="eb-name" value="'+escHtml(b.name)+'"></div>'
    +fermenterRow
    +'<div class="form-row"><div class="form-group"><label class="form-label">Start Date</label><input class="form-input" id="eb-date" type="date" value="'+b.startDate+'"></div>'
    +'<div class="form-group"><label class="form-label">Volume (L)</label><input class="form-input" id="eb-vol" type="number" step="0.1" value="'+(b.volume||4.5)+'"></div></div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">OG</label><input class="form-input" id="eb-og" type="number" step="0.001" value="'+(b.og||1.095)+'"></div>'
    +'<div class="form-group"><label class="form-label">Honey (kg)</label><input class="form-input" id="eb-honey" type="number" step="0.1" value="'+(b.honey||'')+'"></div></div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Honey Type</label><input class="form-input" id="eb-honey-type" value="'+escHtml(b.honeyType||'')+'" list="eb-honey-types" placeholder="Wildflower, Acacia, Buckwheat…">'+honeyDatalist+'</div>'
    +yeastRow+'</div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Honey Cost ('+(APP.settings.currency||'€')+')</label><input class="form-input" id="eb-cost-honey" type="number" step="0.01" value="'+(cost.honey||'')+'"></div>'
    +'<div class="form-group"><label class="form-label">Extras Cost ('+(APP.settings.currency||'€')+')</label><input class="form-input" id="eb-cost-extras" type="number" step="0.01" value="'+(cost.extras||'')+'"></div></div>'
    +'<div class="form-group"><label class="form-label">Notes</label><textarea class="form-textarea" id="eb-notes">'+escHtml(b.notes||'')+'</textarea></div>'
    +'<div class="form-group" style="background:var(--bg);border-left:3px solid var(--gold2);border-radius:var(--radius);padding:12px 14px">'
      +'<label class="form-label">📡 Gravity sensor entity <span style="font-weight:400;color:var(--text3);font-size:11px;margin-left:6px">optional · iSpindel / Tilt / RAPT / generic HA sensor</span></label>'
      +'<input class="form-input" id="eb-gravsensor" type="text" placeholder="sensor.ispindel_floor_gravity (leave blank if you measure manually)" value="'+escHtml(b.gravitySensorEntity||'')+'" style="font-family:var(--font-mono);font-size:12px">'
      +'<div style="font-size:11.5px;color:var(--text3);margin-top:6px;line-height:1.55;font-style:italic">When set, a 📡 button appears on the gravity-log form to pull the current sensor reading with one tap. You still confirm and save each reading manually — automated logging would create noisy data, so this is just a convenience shortcut. Compatible with iSpindel, Tilt Hydrometer, RAPT Pill, or any HA sensor reporting SG (e.g. 1.045).</div>'
    +'</div>'
    +'<div class="modal-actions"><button class="btn btn-secondary" onclick="closeModal()">Cancel</button><button class="btn btn-primary" onclick="saveBatchEdit(\''+id+'\')">Save</button></div></div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}

function saveBatchEdit(id){
  var b=APP.batches.find(function(x){return x.id===id;});
  if(!b)return;
  b.name=document.getElementById('eb-name').value.trim()||b.name;
  b.startDate=document.getElementById('eb-date').value||b.startDate;
  b.volume=parseFloat(document.getElementById('eb-vol').value)||b.volume;
  b.og=parseFloat(document.getElementById('eb-og').value)||b.og;
  b.honey=parseFloat(document.getElementById('eb-honey').value)||null;
  // Honey type — optional free-text/datalist. Empty leaves the field cleared.
  var htEl=document.getElementById('eb-honey-type');
  if(htEl){var ht=htEl.value.trim();b.honeyType=ht||null;}
  // Yeast — read from the strain dropdown if present.
  var yEl=document.getElementById('eb-yeast');
  if(yEl&&yEl.value)b.yeast=yEl.value;
  var fermSel=document.getElementById('eb-fermenter');
  if(fermSel&&fermSel.value)b.fermenterId=fermSel.value;
  var ch=parseFloat(document.getElementById('eb-cost-honey').value)||0;
  var ce=parseFloat(document.getElementById('eb-cost-extras').value)||0;
  b.cost=(ch||ce)?{honey:ch,extras:ce}:null;
  b.notes=document.getElementById('eb-notes').value.trim();
  // Gravity-sensor binding — empty string clears the binding cleanly
  var gsEl=document.getElementById('eb-gravsensor');
  if(gsEl)b.gravitySensorEntity=gsEl.value.trim();
  closeModal();scheduleSave();toast('✦ Updated');renderMain();
}

function addLog(batchId){
  var rawG=parseFloat(document.getElementById('log-gravity').value);
  if(!rawG){toast('⚠ Gravity required');return;}
  var temp=parseFloat(document.getElementById('log-temp').value);
  // Hydrometer temp correction. Most home hydrometers calibrate at 20°C.
  // Standard approximation: correction = (T - 20) × 0.00013 per °C.
  // Apply only when temp is provided and meaningfully different from 20°C.
  var correctedG=rawG;
  var corrApplied=false;
  if(temp!=null&&!isNaN(temp)&&Math.abs(temp-20)>=1){
    correctedG=rawG+(temp-20)*0.00013;
    correctedG=Math.round(correctedG*1000)/1000;
    corrApplied=true;
  }
  // pH is fully optional. Only stored when the user actually enters a value;
  // null is preserved as null so charts and aggregates can ignore it cleanly.
  var phEl=document.getElementById('log-ph');
  var phRaw=phEl?phEl.value.trim():'';
  var ph=phRaw!==''?parseFloat(phRaw):null;
  if(ph!==null&&(isNaN(ph)||ph<2||ph>5))ph=null; // reject obvious garbage
  var entry={
    id:genId(),
    date:document.getElementById('log-date').value||today(),
    gravity:correctedG,
    temp:isNaN(temp)?null:temp,
    ph:ph,
    airlock:document.getElementById('log-airlock').value||'',
    note:document.getElementById('log-note').value.trim()
  };
  if(corrApplied){
    entry.gravityRaw=rawG;
    entry.tempCorrected=true;
  }
  if(!APP.logs[batchId])APP.logs[batchId]=[];
  APP.logs[batchId].push(entry);
  APP.logs[batchId].sort(function(a,b){return a.date.localeCompare(b.date);});
  scheduleSave();
  toast(corrApplied?'✦ Logged (corrected '+rawG.toFixed(3)+' → '+correctedG.toFixed(3)+' @ '+temp+'°C)':'✦ Reading logged');
  renderMain();
}

function deleteLog(batchId,logId){
  if(!confirm('Delete this reading?'))return;
  APP.logs[batchId]=(APP.logs[batchId]||[]).filter(function(l){return l.id!==logId;});
  scheduleSave();toast('Reading deleted');renderMain();
}

function setTastingStars(n){
  document.getElementById('t-rating').value=n;
  for(var i=1;i<=5;i++){
    var s=document.getElementById('t-star-'+i);
    if(s)s.classList.toggle('active',i<=n);
  }
}

function addTasting(batchId){
  var wheel=window._tastingWheel||{};
  var entry={
    id:genId(),
    date:document.getElementById('t-date').value||today(),
    rating:parseInt(document.getElementById('t-rating').value)||0,
    color:document.getElementById('t-color').value.trim(),
    aroma:document.getElementById('t-aroma').value.trim(),
    flavor:document.getElementById('t-flavor').value.trim(),
    finish:document.getElementById('t-finish').value.trim(),
    wheel:wheel,
    bjcp:(typeof readBJCPScore==='function')?readBJCPScore():null,
    note:document.getElementById('t-note').value.trim()
  };
  var hasWheel=Object.values(wheel).some(function(v){return v>0;});
  if(!entry.color&&!entry.aroma&&!entry.flavor&&!entry.finish&&!entry.note&&!entry.rating&&!hasWheel&&!entry.bjcp){toast('⚠ Add at least one note or rating');return;}
  if(!APP.tastings[batchId])APP.tastings[batchId]=[];
  APP.tastings[batchId].push(entry);
  APP.tastings[batchId].sort(function(a,b){return a.date.localeCompare(b.date);});
  window._tastingWheel={};  // reset for next entry
  scheduleSave();toast('✦ Tasting saved');renderMain();
}

function deleteTasting(batchId,id){
  if(!confirm('Delete this tasting note?'))return;
  APP.tastings[batchId]=(APP.tastings[batchId]||[]).filter(function(t){return t.id!==id;});
  scheduleSave();toast('Deleted');renderMain();
}

// ==================== PHOTO JOURNAL ====================
// Per-batch photo gallery. Images are resized client-side then uploaded to
// /api/asset (stored as files under labels/); only the /labels/<hash> URL and
// metadata ride the state blob. Stages let you tell brew-day from bottling.
var PHOTO_STAGES=[
  {key:'brew',label:'Brew Day',color:'#c9a84c'},
  {key:'ferment',label:'Fermentation',color:'#7aa850'},
  {key:'racking',label:'Racking',color:'#7aa8c0'},
  {key:'bottling',label:'Bottling',color:'#a87aa0'},
  {key:'tasting',label:'Tasting',color:'#c04858'},
  {key:'other',label:'Other',color:'#8a8a8a'}
];
function photoStage(key){return PHOTO_STAGES.find(function(s){return s.key===key;})||PHOTO_STAGES[PHOTO_STAGES.length-1];}

function renderBatchPhotos(b){
  var photos=(APP.photos[b.id]||[]).slice().sort(function(a,c){return(c.date||c.addedAt||'').localeCompare(a.date||a.addedAt||'');});
  var addBtn='<button class="btn btn-primary btn-sm" onclick="addBatchPhoto(\''+b.id+'\')">📷 Add Photo</button>';
  var head='<div class="card-header" style="display:flex;justify-content:space-between;align-items:center"><div class="card-title">📷 PHOTO JOURNAL</div>'+addBtn+'</div>';
  if(!photos.length){
    return'<div class="card">'+head
      +'<div style="text-align:center;padding:30px 16px;color:var(--text3)"><div style="font-size:32px;margin-bottom:8px">📷</div>'
      +'<div style="font-size:13px;font-style:italic;line-height:1.5">No photos yet. Capture brew day, the fermentation, racking, or the finished bottles —<br>a visual diary of this batch\'s life.</div></div></div>';
  }
  var grid=photos.map(function(p){
    var st=photoStage(p.stage);
    var src=(typeof getResolvedMediaUrl==='function'&&getResolvedMediaUrl(p.url))||p.url;
    return'<div style="border:1px solid var(--border);border-radius:var(--radius);overflow:hidden;background:var(--bg3)">'
      +'<div style="position:relative;aspect-ratio:4/3;background:var(--bg);cursor:pointer;overflow:hidden" onclick="openPhotoLightbox(\''+b.id+'\',\''+p.id+'\')">'
      +'<img src="'+escHtml(src)+'" style="width:100%;height:100%;object-fit:cover;display:block" loading="lazy" alt="'+escHtml(p.caption||st.label)+'">'
      +'<span style="position:absolute;top:6px;left:6px;font-family:var(--font-mono);font-size:9px;letter-spacing:1px;padding:2px 7px;border-radius:8px;background:'+st.color+'cc;color:#0f0f0a">'+st.label.toUpperCase()+'</span></div>'
      +'<div style="padding:8px 10px">'
      +'<div style="font-size:12.5px;color:var(--text2);line-height:1.4;min-height:18px">'+escHtml(p.caption||'')+'</div>'
      +'<div style="display:flex;justify-content:space-between;align-items:center;margin-top:4px"><span style="font-family:var(--font-mono);font-size:10px;color:var(--text3)">'+fmtDate(p.date||p.addedAt)+'</span>'
      +'<button class="btn-icon" style="font-size:12px" onclick="deleteBatchPhoto(\''+b.id+'\',\''+p.id+'\')" title="Delete photo">🗑</button></div>'
      +'</div></div>';
  }).join('');
  return'<div class="card">'+head
    +'<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:12px;margin-top:8px">'+grid+'</div></div>';
}

function addBatchPhoto(batchId){
  var input=document.createElement('input');
  input.type='file';input.accept='image/*';
  input.onchange=function(){
    var file=input.files&&input.files[0];
    if(!file)return;
    toast('⏳ Processing photo…');
    readImageAsDataUrl(file,{maxDim:1400},function(err,dataUrl){
      if(err){toast('⚠ '+err.message);return;}
      storeImageAsset(dataUrl,'photos').then(function(url){
        openPhotoMetaModal(batchId,url);
      });
    });
  };
  input.click();
}

// After upload, collect caption + stage + date before committing the entry.
function openPhotoMetaModal(batchId,url){
  closeModal();
  var src=(typeof getResolvedMediaUrl==='function'&&getResolvedMediaUrl(url))||url;
  var stageOpts=PHOTO_STAGES.map(function(s){return'<option value="'+s.key+'">'+s.label+'</option>';}).join('');
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal">'
    +'<div class="modal-title">📷 ADD PHOTO</div>'
    +'<div style="text-align:center;margin-bottom:14px"><img src="'+escHtml(src)+'" style="max-width:100%;max-height:240px;border-radius:var(--radius);border:1px solid var(--border)"></div>'
    +'<div class="form-row"><div class="form-group"><label class="form-label">Stage</label><select class="form-select" id="ph-stage">'+stageOpts+'</select></div>'
    +'<div class="form-group"><label class="form-label">Date</label><input class="form-input" id="ph-date" type="date" value="'+today()+'"></div></div>'
    +'<div class="form-group"><label class="form-label">Caption (optional)</label><input class="form-input" id="ph-caption" placeholder="e.g. vigorous krausen on day 3"></div>'
    +'<input type="hidden" id="ph-url" value="'+escHtml(url)+'">'
    +'<div class="modal-actions"><button class="btn btn-secondary" onclick="closeModal()">Cancel</button><button class="btn btn-primary" onclick="savePhoto(\''+batchId+'\')">Save Photo</button></div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}

function savePhoto(batchId){
  var url=document.getElementById('ph-url').value;
  if(!url){toast('⚠ No image');return;}
  var entry={
    id:genId(),
    url:url,
    stage:document.getElementById('ph-stage').value,
    date:document.getElementById('ph-date').value||today(),
    caption:document.getElementById('ph-caption').value.trim(),
    addedAt:new Date().toISOString()
  };
  if(!APP.photos[batchId])APP.photos[batchId]=[];
  APP.photos[batchId].push(entry);
  closeModal();scheduleSave();toast('✦ Photo added');renderMain();
}

function deleteBatchPhoto(batchId,photoId){
  if(!confirm('Delete this photo? This removes it from the journal and deletes the image file.'))return;
  var photo=(APP.photos[batchId]||[]).find(function(p){return p.id===photoId;});
  var url=photo&&photo.url;
  APP.photos[batchId]=(APP.photos[batchId]||[]).filter(function(p){return p.id!==photoId;});
  if(!APP.photos[batchId].length)delete APP.photos[batchId];
  scheduleSave();
  // Remove the underlying file now that the reference is gone (if unused).
  if(typeof deleteAssetIfUnused==='function')deleteAssetIfUnused(url);
  toast('Deleted');renderMain();
}

// Full-screen lightbox with prev/next across the batch's photos.
function openPhotoLightbox(batchId,photoId){
  var photos=(APP.photos[batchId]||[]).slice().sort(function(a,c){return(c.date||c.addedAt||'').localeCompare(a.date||a.addedAt||'');});
  var idx=photos.findIndex(function(p){return p.id===photoId;});
  if(idx<0)return;
  window._lightbox={batchId:batchId,ids:photos.map(function(p){return p.id;}),idx:idx};
  renderPhotoLightbox();
}
function renderPhotoLightbox(){
  var lb=window._lightbox;if(!lb)return;
  var existing=document.getElementById('photo-lightbox');if(existing)existing.remove();
  var photos=APP.photos[lb.batchId]||[];
  var p=photos.find(function(x){return x.id===lb.ids[lb.idx];});
  if(!p)return;
  var st=photoStage(p.stage);
  var src=(typeof getResolvedMediaUrl==='function'&&getResolvedMediaUrl(p.url))||p.url;
  var multi=lb.ids.length>1;
  var html='<div id="photo-lightbox" class="modal-overlay" style="z-index:9999;background:rgba(8,8,6,0.94)" onclick="if(event.target===this)closePhotoLightbox()">'
    +'<div style="max-width:92vw;max-height:92vh;display:flex;flex-direction:column;align-items:center;gap:10px">'
    +'<img src="'+escHtml(src)+'" style="max-width:92vw;max-height:78vh;object-fit:contain;border-radius:6px;box-shadow:0 8px 40px rgba(0,0,0,0.6)">'
    +'<div style="text-align:center;color:var(--text2)">'
    +'<span style="font-family:var(--font-mono);font-size:10px;letter-spacing:1px;padding:2px 8px;border-radius:8px;background:'+st.color+';color:#0f0f0a">'+st.label.toUpperCase()+'</span>'
    +(p.caption?'<div style="font-size:14px;margin-top:8px">'+escHtml(p.caption)+'</div>':'')
    +'<div style="font-family:var(--font-mono);font-size:11px;color:var(--text3);margin-top:4px">'+fmtDate(p.date||p.addedAt)+(multi?' · '+(lb.idx+1)+'/'+lb.ids.length:'')+'</div></div>'
    +(multi?'<div style="display:flex;gap:10px;margin-top:4px"><button class="btn btn-secondary" onclick="event.stopPropagation();navPhotoLightbox(-1)">← Prev</button><button class="btn btn-secondary" onclick="event.stopPropagation();navPhotoLightbox(1)">Next →</button></div>':'')
    +'<button class="btn btn-secondary btn-sm" onclick="closePhotoLightbox()" style="margin-top:2px">Close</button>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}
function navPhotoLightbox(delta){
  var lb=window._lightbox;if(!lb)return;
  lb.idx=(lb.idx+delta+lb.ids.length)%lb.ids.length;
  renderPhotoLightbox();
}
function closePhotoLightbox(){
  var el=document.getElementById('photo-lightbox');if(el)el.remove();
  window._lightbox=null;
}

function updateBottlingTotalDisplay(){
  var el=document.getElementById('bt-total-display');
  if(!el)return;
  var c500=parseInt((document.getElementById('bt-count-500')||{}).value)||0;
  var c750=parseInt((document.getElementById('bt-count-750')||{}).value)||0;
  var customSize=parseInt((document.getElementById('bt-count-custom-size')||{}).value)||0;
  var customQty=parseInt((document.getElementById('bt-count-custom-qty')||{}).value)||0;
  var totalBottles=c500+c750+(customSize>0?customQty:0);
  var totalMl=c500*500+c750*750+(customSize>0?customQty*customSize:0);
  if(totalBottles===0){
    el.innerHTML='<span style="color:var(--text3)">Enter bottle counts above to see total volume.</span>';
    return;
  }
  var parts=[];
  if(c500>0)parts.push(c500+'×500ml');
  if(c750>0)parts.push(c750+'×750ml');
  if(customSize>0&&customQty>0)parts.push(customQty+'×'+customSize+'ml');
  el.innerHTML='<span style="color:var(--gold2)">TOTAL: '+totalBottles+' bottle'+(totalBottles!==1?'s':'')+' · '+(totalMl/1000).toFixed(2)+' L</span> &nbsp; <span style="color:var(--text3);font-size:11px">('+parts.join(' + ')+')</span>';
}

function saveBottling(batchId){
  var count500=parseInt(document.getElementById('bt-count-500').value)||0;
  var count750=parseInt(document.getElementById('bt-count-750').value)||0;
  var customSize=parseInt((document.getElementById('bt-count-custom-size')||{}).value)||0;
  var customCount=parseInt((document.getElementById('bt-count-custom-qty')||{}).value)||0;
  var countsAtBottling={};
  if(count500>0)countsAtBottling[500]=count500;
  if(count750>0)countsAtBottling[750]=count750;
  if(customSize>0&&customCount>0)countsAtBottling[customSize]=customCount;
  var total=Object.keys(countsAtBottling).reduce(function(s,k){return s+countsAtBottling[k];},0);
  if(total===0){toast('⚠ Enter at least one bottle count (500ml or 750ml)');return;}
  var existing=APP.bottling[batchId];
  var existingTotal=existing?totalBottles(existing):0;
  // Build new locations map
  var locations={cellar:{},fridge:{},gifted:{},other:{}};
  if(existing&&existing.locations&&existingTotal>0){
    // Editing meaningful existing inventory — preserve splits, rebalance delta per size
    Object.assign(locations,{
      cellar:Object.assign({},_coerceLocations(existing.locations.cellar)),
      fridge:Object.assign({},_coerceLocations(existing.locations.fridge)),
      gifted:Object.assign({},_coerceLocations(existing.locations.gifted)),
      other:Object.assign({},_coerceLocations(existing.locations.other))
    });
    // For each size, rebalance: delta goes to/from cellar
    Object.keys(countsAtBottling).forEach(function(size){
      var sz=parseInt(size);
      var newCount=countsAtBottling[size];
      var oldCount=Object.keys(locations).reduce(function(s,loc){return s+(locations[loc][sz]||0);},0);
      var delta=newCount-oldCount;
      if(delta>0)locations.cellar[sz]=(locations.cellar[sz]||0)+delta;
      else if(delta<0){
        var toRemove=-delta;
        ['cellar','fridge','other','gifted'].forEach(function(loc){
          if(toRemove<=0)return;
          var avail=locations[loc][sz]||0;
          var take=Math.min(toRemove,avail);
          locations[loc][sz]=avail-take;
          if(locations[loc][sz]<=0)delete locations[loc][sz];
          toRemove-=take;
        });
      }
    });
    // Remove sizes that aren't in the new count map at all (probably user removed them entirely)
    ['cellar','fridge','gifted','other'].forEach(function(loc){
      Object.keys(locations[loc]).forEach(function(sz){
        if(!countsAtBottling[sz]&&locations[loc][sz]>0){
          // size removed entirely from bottling — clear from all locations
          delete locations[loc][sz];
        }
      });
    });
  }else{
    // Fresh bottling — all bottles go to cellar
    Object.keys(countsAtBottling).forEach(function(size){
      locations.cellar[parseInt(size)]=countsAtBottling[size];
    });
  }
  APP.bottling[batchId]={
    date:document.getElementById('bt-date').value||today(),
    bottleCount:total,                       // IMMUTABLE total — legacy field
    bottlesAtBottling:total,                 // explicit as-bottled snapshot
    countsAtBottling:countsAtBottling,       // per-size immutable map
    bottleSizes:Object.keys(countsAtBottling).map(function(s){return parseInt(s);}).sort(function(a,b){return a-b;}),
    locations:locations,
    fg:parseFloat(document.getElementById('bt-fg').value)||null,
    abv:parseFloat(document.getElementById('bt-abv').value)||null,
    sweetness:document.getElementById('bt-sweet').value,
    notes:document.getElementById('bt-notes').value.trim(),
    closure:((document.getElementById('bt-closure')||{}).value)||(existing&&existing.closure)||'crown',
    // Bottling auto-places everything in the cellar, so the cellar IS filled —
    // mark it so a later drink-to-zero reads as "Finished", not "needs fill".
    cellarFilled:true,
    // Preserve gifts log from existing
    gifts:(existing&&existing.gifts)||[]
  };
  // Deduct bottles + closures from tracked supplies — but ONLY on the first
  // (fresh) bottling, so editing an existing record doesn't double-deduct.
  // (The guided workflow has its own deduction path.)
  if((!existing||existingTotal===0)&&typeof consumePackagingSupplies==='function'){
    var pkg=consumePackagingSupplies(countsAtBottling,total,APP.bottling[batchId].closure);
    APP.bottling[batchId].packaging=pkg;
    if(pkg&&pkg.items&&pkg.items.length){
      var deducted=pkg.items.filter(function(i){return i.tracked;}).map(function(i){return i.qty+' '+i.label;});
      if(deducted.length)toast('📦 Deducted: '+deducted.join(' · '),4000);
    }
  }
  scheduleSave();
  try{console.log('[MeadOS] saveBottling — total',total,'counts',countsAtBottling,'locations',JSON.parse(JSON.stringify(locations)));}catch(e){}
  toast('✦ '+total+' bottle'+(total!==1?'s':'')+' bottled · cellar populated');
  showView('cellar');
}

function clearBottling(batchId){
  if(!confirm('Clear bottling record? Batch will return to active.'))return;
  delete APP.bottling[batchId];
  scheduleSave();toast('Bottling cleared');renderMain();
}

function deleteBatch(id){
  var b=APP.batches.find(function(x){return x.id===id;});
  if(!b)return;
  if(!confirm('Permanently delete "'+b.name+'" and all associated logs, tastings, and bottling data?'))return;
  APP.batches=APP.batches.filter(function(x){return x.id!==id;});
  delete APP.logs[id];delete APP.tastings[id];delete APP.bottling[id];
  scheduleSave();toast('Batch deleted');showView('batches');
}

// ==================== FAILURE POSTMORTEM ====================
// When a batch goes wrong — contamination, irrecoverable stuck ferment,
// off-flavors, accident, planned-experiment-that-flopped — recording a
// postmortem preserves the lesson without losing the data. Unlike Delete,
// the batch stays in the database, just flagged as failed. Useful because:
//   - Year-end stats are honest (you brewed 30, dumped 4)
//   - Pattern-mining shows what failed batches share (counterpart to the
//     "best batches share" insights view)
//   - Future-you doesn't repeat the same mistake from forgetting

// Categories chosen for mead specifically — bacteria/wild yeast contamination
// is the #1 cause; oxidation and stuck-beyond-rescue are next.
var FAILURE_CATEGORIES=[
  {id:'contamination',label:'Contamination (bacteria / wild yeast)',icon:'🦠'},
  {id:'stuck',label:'Stuck ferment beyond rescue',icon:'⏸'},
  {id:'off-flavor',label:'Off-flavors / autolysis',icon:'🙊'},
  {id:'oxidation',label:'Oxidation / acetification',icon:'🍶'},
  {id:'accident',label:'Accident (spill, breakage, mishap)',icon:'💥'},
  {id:'process',label:'Process error (wrong yeast, miscalc, etc.)',icon:'🧪'},
  {id:'experiment',label:'Planned experiment that didn\'t work',icon:'🔬'},
  {id:'other',label:'Other',icon:'❓'}
];

function openFailureModal(batchId){
  closeModal();
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b){toast('⚠ Batch not found');return;}
  var f=b.failed||{};
  var isEdit=!!b.failed;
  var catChips=FAILURE_CATEGORIES.map(function(c){
    var isSel=f.category===c.id;
    return'<span onclick="document.querySelectorAll(\'.fail-cat-chip\').forEach(function(el){el.classList.remove(\'sel\');el.style.background=\'var(--bg)\';el.style.color=\'var(--text2)\';el.style.borderColor=\'var(--border)\'});this.classList.add(\'sel\');this.style.background=\'rgba(232,196,106,0.15)\';this.style.color=\'var(--gold2)\';this.style.borderColor=\'var(--gold)\';document.getElementById(\'fail-cat\').value=\''+c.id+'\'" class="fail-cat-chip'+(isSel?' sel':'')+'" style="display:inline-flex;align-items:center;gap:5px;cursor:pointer;font-size:12px;background:'+(isSel?'rgba(232,196,106,0.15)':'var(--bg)')+';border:1px solid '+(isSel?'var(--gold)':'var(--border)')+';color:'+(isSel?'var(--gold2)':'var(--text2)')+';padding:5px 11px;border-radius:14px;margin:3px 4px 3px 0;transition:all 0.15s">'+c.icon+' '+escHtml(c.label)+'</span>';
  }).join('');
  var html='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal" style="max-width:680px;max-height:92vh;display:flex;flex-direction:column">'
    +'<div class="modal-title">⚰ '+(isEdit?'EDIT POSTMORTEM':'MARK BATCH AS FAILED')+'</div>'
    +'<div style="font-size:12.5px;color:var(--text3);margin-bottom:14px;line-height:1.6">Recording a postmortem preserves the lesson — far better than just deleting the batch. The batch stays in your database (so year-end stats are honest) but is marked failed: it stops appearing on aging timelines and fermenter schedules, but contributes to "what your failed batches share" analysis. You can unfail it later if you change your mind.</div>'
    +'<div style="flex:1;overflow-y:auto;padding-right:4px">'
    +'<div style="background:var(--bg);padding:12px;border-radius:var(--radius);margin-bottom:14px;border-left:3px solid var(--gold)">'
      +'<div style="font-family:var(--font-display);font-size:14px;color:var(--gold2)">'+escHtml(b.name)+(b.serial?' <span style="font-family:var(--font-mono);font-size:11px;color:var(--text3)">#'+escHtml(b.serial)+'</span>':'')+'</div>'
      +'<div style="font-size:11px;color:var(--text3);margin-top:4px">Started '+fmtDate(b.startDate)+' · OG '+(b.og||'?')+' · '+(b.honeyType||'?')+'</div>'
    +'</div>'
    +'<div class="form-group"><label class="form-label">Date of failure</label><input class="form-input" type="date" id="fail-date" value="'+(f.date||today())+'"></div>'
    +'<div class="form-group"><label class="form-label">Failure category</label><div style="line-height:2.2">'+catChips+'</div><input type="hidden" id="fail-cat" value="'+escHtml(f.category||'')+'"></div>'
    +'<div class="form-group"><label class="form-label">What went wrong?</label><textarea class="form-textarea" id="fail-what" placeholder="Be specific: aromas, gravity readings, timeline, anything visual. Future-you will thank present-you for the detail." style="min-height:100px">'+escHtml(f.whatWentWrong||'')+'</textarea></div>'
    +'<div class="form-group"><label class="form-label">What would you do differently next time?</label><textarea class="form-textarea" id="fail-next" placeholder="Concrete corrective action. e.g. \'Pitch yeast at 22°C not 28°C\', \'Use Chemipro SAN with 2min contact time, not just rinse\'" style="min-height:80px">'+escHtml(f.whatToTryNext||'')+'</textarea></div>'
    +'<div class="form-group"><label style="display:flex;align-items:center;gap:8px;cursor:pointer;font-size:13px;color:var(--text2)"><input type="checkbox" id="fail-saved" '+(f.wasSaved?'checked':'')+' style="width:16px;height:16px;cursor:pointer;accent-color:var(--gold2)"> The mead was salvaged (bottled as cooking mead, vinegar, etc.) rather than dumped</label></div>'
    +'</div>'
    +'<div class="modal-actions" style="border-top:1px solid var(--border);padding-top:14px;margin-top:14px">'
      +'<button class="btn btn-secondary" onclick="closeModal()">Cancel</button>'
      +'<button class="btn btn-primary" onclick="saveFailurePostmortem(\''+batchId+'\')">'+(isEdit?'Save Postmortem':'Mark Failed & Save')+'</button>'
    +'</div>'
    +'</div></div>';
  document.body.insertAdjacentHTML('beforeend',html);
}

function saveFailurePostmortem(batchId){
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b)return;
  var cat=document.getElementById('fail-cat').value;
  var what=document.getElementById('fail-what').value.trim();
  if(!cat){toast('⚠ Pick a failure category');return;}
  if(!what){toast('⚠ Describe what went wrong');return;}
  b.failed={
    date:document.getElementById('fail-date').value||today(),
    category:cat,
    whatWentWrong:what,
    whatToTryNext:document.getElementById('fail-next').value.trim(),
    wasSaved:document.getElementById('fail-saved').checked,
    markedAt:Date.now()
  };
  scheduleSave();
  closeModal();
  toast('⚰ Marked as failed — postmortem saved');
  renderMain();
}

function unmarkBatchFailed(batchId){
  var b=APP.batches.find(function(x){return x.id===batchId;});
  if(!b||!b.failed)return;
  if(!confirm('Restore "'+b.name+'" to its previous active state? The postmortem notes will be deleted.'))return;
  delete b.failed;
  scheduleSave();
  toast('Batch restored');
  renderMain();
}

// Prominent banner shown at the top of the batch detail view when failed.
function renderFailureBanner(b){
  if(!b||!b.failed)return'';
  var f=b.failed;
  var cat=FAILURE_CATEGORIES.find(function(c){return c.id===f.category;})||{label:f.category||'Unknown',icon:'⚰'};
  return'<div style="background:rgba(180,40,40,0.10);border-left:4px solid var(--red2);border-radius:var(--radius);padding:14px 18px;margin:12px 0">'
    +'<div style="display:flex;align-items:baseline;gap:10px;flex-wrap:wrap;margin-bottom:6px">'
      +'<div style="font-family:var(--font-display);font-size:16px;color:var(--red2)">'+cat.icon+' Failed batch — '+escHtml(cat.label)+'</div>'
      +'<div style="font-family:var(--font-mono);font-size:10px;color:var(--text3);letter-spacing:1px">'+(f.date?fmtDate(f.date):'')+(f.wasSaved?' · SALVAGED':' · DUMPED')+'</div>'
    +'</div>'
    +(f.whatWentWrong?'<div style="font-size:12.5px;color:var(--text2);line-height:1.6;margin-bottom:6px"><strong style="color:var(--red2);font-family:var(--font-mono);font-size:10px;letter-spacing:1px;text-transform:uppercase">What went wrong</strong><br>'+escHtml(f.whatWentWrong)+'</div>':'')
    +(f.whatToTryNext?'<div style="font-size:12.5px;color:var(--text2);line-height:1.6"><strong style="color:var(--gold2);font-family:var(--font-mono);font-size:10px;letter-spacing:1px;text-transform:uppercase">What to try next time</strong><br>'+escHtml(f.whatToTryNext)+'</div>':'')
    +'</div>';
}

// ==================== SETTINGS ACTIONS ====================
function saveHASettings(){
  function normUrl(v){
    v=(v||'').trim().replace(/\/+$/,'');
    if(v&&!/^https?:\/\//i.test(v))v='http://'+v;
    return v;
  }
  var urlEl=document.getElementById('set-url');
  if(urlEl)APP.settings.haUrl=normUrl(urlEl.value);
  var extUrlEl=document.getElementById('set-url-external');
  if(extUrlEl)APP.settings.haUrlExternal=normUrl(extUrlEl.value);
  // The token is write-only: only a freshly-typed value is sent to the server;
  // a blank field keeps whatever token is already stored there.
  var tokEl=document.getElementById('set-token');
  var typedToken=tokEl?tokEl.value.trim():'';
  var brewerEl=document.getElementById('set-brewer');
  if(brewerEl)APP.settings.brewerName=brewerEl.value.trim();
  var extEl=document.getElementById('set-external-url');
  if(extEl)APP.settings.externalUrl=extEl.value.trim().replace(/\/+$/,'');
  var usehaEl=document.getElementById('set-useha');
  if(usehaEl)APP.settings.useHA=usehaEl.checked;
  var pubEl=document.getElementById('set-publish-summary');
  if(pubEl)APP.settings.haPublishSummary=pubEl.checked;
  var tempEl=document.getElementById('set-temp');
  if(tempEl)APP.settings.tempSensorEntity=tempEl.value.trim();
  var cellarTempEl=document.getElementById('set-cellar-temp');
  if(cellarTempEl)APP.settings.cellarTempSensorEntity=cellarTempEl.value.trim();
  var notifyEl=document.getElementById('set-notify');
  if(notifyEl)APP.settings.notificationService=notifyEl.value.trim();
  var notifEnEl=document.getElementById('set-notif-enabled');
  if(notifEnEl)APP.settings.notificationsEnabled=notifEnEl.checked;
  var sachetEl=document.getElementById('set-sachet');
  if(sachetEl)APP.settings.sachetSize=parseFloat(sachetEl.value)||6;
  var hpEl=document.getElementById('set-honey-price');
  if(hpEl)APP.settings.honeyPricePerKg=parseFloat(hpEl.value)||0;
  var ccyEl=document.getElementById('set-currency');
  if(ccyEl)APP.settings.currency=ccyEl.value;
  saveSettings();
  scheduleSave(); // brewer name rides the shared blob — sync it too
  // Push the HA connection to the server: URLs + (only if typed) the token.
  // The token is stored server-side and proxied — never in the synced blob.
  var cfg={url:APP.settings.haUrl,urlExternal:APP.settings.haUrlExternal};
  if(typedToken)cfg.token=typedToken;
  fetch('/api/ha-config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(cfg)})
    .then(function(r){return r.json();})
    .then(function(j){
      APP._haTokenSet=!!(j&&j.hasToken);
      APP._haTokenExp=(j&&j.tokenExp)||null;
      if(tokEl)tokEl.value='';  // clear the field; status now reads "stored"
      toast('Settings saved');
      startTempPolling();
      if(haConfigured())testConnection();
    })
    .catch(function(){toast('Settings saved — but HA config sync failed');});
}

// Clear the server-side HA token (e.g. on rotation or disconnect).
function clearHAToken(){
  if(!confirm('Remove the stored Home Assistant token from the server?'))return;
  fetch('/api/ha-config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({clearToken:true})})
    .then(function(r){return r.json();})
    .then(function(j){
      APP._haTokenSet=!!(j&&j.hasToken);
      APP._haTokenExp=(j&&j.tokenExp)||null;
      toast('HA token cleared');
      if(typeof showView==='function')showView('settings');
    })
    .catch(function(){toast('Could not clear token');});
}

// Auto-save handler for the Costs & Supplies card. Wired to each input's
